// ── Fecha LOCAL (no UTC) en formato YYYY-MM-DD. ──
// IMPORTANTE: new Date().toISOString() siempre da la fecha en UTC. México (Tabasco)
// está en UTC-6 todo el año, así que a partir de aproximadamente las 6:00 PM hora
// local, la hora UTC ya cruzó la medianoche y toISOString() empieza a devolver la
// fecha de MAÑANA en vez de la de HOY. Esta función usa siempre el reloj local del
// dispositivo para evitar ese desfase.
function fechaLocalISO(d = new Date()) {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
}

function urlBase64ToUint8Array(base64String) {
  const padding = "=".repeat((4 - (base64String.length % 4)) % 4);
  const base64 = (base64String + padding).replace(/-/g, "+").replace(/_/g, "/");
  const rawData = atob(base64);
  return Uint8Array.from([...rawData].map((c) => c.charCodeAt(0)));
}

// Pide permiso al celular y activa los recordatorios de citas para este asesor.
// Devuelve "activado", "denegado", o "no-soportado" (por ejemplo, si no está
// instalada como app en iPhone).
async function activarNotificaciones(asesorId) {
  if (!("serviceWorker" in navigator) || !("PushManager" in window)) return "no-soportado";
  const permiso = await Notification.requestPermission();
  if (permiso !== "granted") return "denegado";
  const registro = await navigator.serviceWorker.ready;
  let sub = await registro.pushManager.getSubscription();
  if (!sub) {
    sub = await registro.pushManager.subscribe({
      userVisibleOnly: true,
      applicationServerKey: urlBase64ToUint8Array(VAPID_PUBLIC_KEY),
    });
  }
  const json = sub.toJSON();
  const { error } = await supabase.from("push_subscriptions").upsert({
    asesor_id: asesorId,
    endpoint: json.endpoint,
    p256dh: json.keys.p256dh,
    auth: json.keys.auth,
  }, { onConflict: "endpoint" });
  if (error) throw error;
  return "activado";
}
async function notificacionesActivas() {
  if (!("serviceWorker" in navigator) || !("PushManager" in window)) return false;
  const registro = await navigator.serviceWorker.getRegistration();
  if (!registro) return false;
  const sub = await registro.pushManager.getSubscription();
  return !!sub;
}

async function llamarGestionarCuentas(body) {
  const { data, error } = await supabase.functions.invoke("gestionar-cuentas", { body });
  if (error) {
    // Cuando la función responde con un error, Supabase no muestra el mensaje real
    // automáticamente — hay que leerlo del cuerpo de la respuesta que sí mandamos nosotros.
    let mensajeReal = null;
    try {
      const cuerpo = await error.context.json();
      if (cuerpo && typeof cuerpo.error === "string" && cuerpo.error.trim()) mensajeReal = cuerpo.error;
    } catch { /* el cuerpo no se pudo leer, se usa el mensaje genérico de abajo */ }
    const mensajeError = typeof error.message === "string" && error.message.trim() ? error.message : null;
    throw new Error(mensajeReal || mensajeError || "No se pudo completar la operación. Vuelve a intentar en unos segundos.");
  }
  if (data?.error) throw new Error(typeof data.error === "string" ? data.error : "No se pudo completar la operación.");
  invalidarCache("asesores"); // por si la cuenta afectada era de un asesor
  return data;
}
