const MESES_ES = ["enero", "febrero", "marzo", "abril", "mayo", "junio", "julio", "agosto", "septiembre", "octubre", "noviembre", "diciembre"];
const fmtDateLong = (d) => `${d.getDate()} de ${MESES_ES[d.getMonth()]} de ${d.getFullYear()}`;

// Timestamp (ms) de una solicitud, usado para ordenar "por horario" y ubicarla en el día
// correcto. Las solicitudes nuevas ya traen fechaHoraCreacion exacta; las capturadas antes de
// esta actualización solo tienen fecha (sin hora), así que se ubican al inicio de ese día.
const getSolTimestamp = (s) => {
  if (s.fechaHoraCreacion) return new Date(s.fechaHoraCreacion).getTime();
  if (!s.fechaCreacion) return 0;
  const [dd, mm, yyyy] = s.fechaCreacion.split("/");
  if (!dd || !mm || !yyyy) return 0;
  return new Date(Number(yyyy), Number(mm) - 1, Number(dd), 0, 0, 0).getTime();
};
const fmtHoraSol = (s) => {
  if (!s.fechaHoraCreacion) return "—";
  const d = new Date(s.fechaHoraCreacion);
  return `${String(d.getHours()).padStart(2, "0")}:${String(d.getMinutes()).padStart(2, "0")}`;
};

// Igual que getSolTimestamp/fmtHoraSol, pero para cotizaciones (que ya traían fechaHoraCreacion
// desde antes de esta actualización, así que casi todas tendrán hora exacta).
const getCotTimestamp = (c) => {
  if (c.fechaHoraCreacion) return new Date(c.fechaHoraCreacion).getTime();
  if (!c.fechaCreacion) return 0;
  const [dd, mm, yyyy] = c.fechaCreacion.split("/");
  if (!dd || !mm || !yyyy) return 0;
  return new Date(Number(yyyy), Number(mm) - 1, Number(dd), 0, 0, 0).getTime();
};
const fmtHoraCot = (c) => {
  if (!c.fechaHoraCreacion) return "—";
  const d = new Date(c.fechaHoraCreacion);
  return `${String(d.getHours()).padStart(2, "0")}:${String(d.getMinutes()).padStart(2, "0")}`;
};
/* Fecha del CAT: se recalcula sola cada 10 días, tomando el inicio del bloque de 10 días vigente. */
const getCatDate = () => {
  const epoch = new Date(2026, 0, 1).getTime();
  const now = Date.now();
  const diffDays = Math.floor((now - epoch) / 86400000);
  const periodStartDays = Math.floor(diffDays / 10) * 10;
  const periodDate = new Date(epoch + periodStartDays * 86400000);
  return fmtDateLong(periodDate);
};
const fmtMoney = (n) => {
  const v = parseFloat(n);
  if (isNaN(v)) return "$0.00";
  return v.toLocaleString("es-MX", { style: "currency", currency: "MXN" });
};
// Exporta cualquier lista como PDF: arma una tabla imprimible y abre el diálogo de
// impresión del navegador — desde ahí se elige "Guardar como PDF". Usa el mismo mecanismo
// que ya imprime cotizaciones y solicitudes individuales, solo que en formato de tabla.
async function exportarListaComoPDF({ titulo, subtitulo, columnas, filas }) {
  // Espera un instante antes de hacer el trabajo pesado, para que cualquier aviso de
  // "Generando…" que haya puesto quien llama a esta función alcance a pintarse en
  // pantalla primero — si no, el navegador se siente "congelado" un momento sin avisar nada.
  await new Promise((resolve) => setTimeout(resolve, 0));
  const escapar = (v) => String(v ?? "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
  const encabezados = columnas.map((c) => `<th style="padding:8px 10px;border:1px solid #0A1E3A;background:#142B4D;color:#fff;font-size:11px;text-align:left;white-space:nowrap;">${escapar(c)}</th>`).join("");
  const cuerpo = filas.map((fila, i) => `<tr style="background:${i % 2 === 0 ? "#FAFAF7" : "#fff"};">${fila.map((celda) => `<td style="padding:7px 10px;border:1px solid #E3DECF;font-size:11px;color:#374151;">${escapar(celda)}</td>`).join("")}</tr>`).join("");
  const html = `<!DOCTYPE html><html><head><meta charset="utf-8" />
    <title>${escapar(titulo)}</title>
    <style>
      @page { size: letter landscape; margin: 10mm; }
      * { box-sizing: border-box; -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; color-adjust: exact !important; }
      body { font-family: Arial, Helvetica, sans-serif; color: #2E3744; margin: 0; padding: 24px; }
      table { width: 100%; border-collapse: collapse; }
      #btn-imprimir-flotante { position: fixed; top: 14px; right: 14px; background: #142B4D; color: #fff; border: none; border-radius: 6px; padding: 12px 20px; font-size: 15px; font-weight: 700; cursor: pointer; box-shadow: 0 4px 14px rgba(0,0,0,0.3); z-index: 9999; }
      @media print { #btn-imprimir-flotante { display: none !important; } }
    </style>
    </head><body>
    <button id="btn-imprimir-flotante" onclick="window.print()">🖨️ Guardar como PDF</button>
    <div style="font-weight:800;font-size:19px;color:#142B4D;margin-bottom:2px;">${escapar(titulo)}</div>
    <div style="color:#6B7280;font-size:12px;margin-bottom:16px;">${escapar(subtitulo)} · Generado el ${escapar(fmtDateTime(new Date()))}</div>
    <table><thead><tr>${encabezados}</tr></thead><tbody>${cuerpo}</tbody></table>
    </body></html>`;
  const w = window.open("", "_blank");
  if (!w) { alert("El navegador bloqueó la ventana emergente. Permite las ventanas emergentes para poder exportar."); return; }
  w.document.open();
  w.document.write(html);
  w.document.close();
}
const calcEdad = (fechaNac) => {
  if (!fechaNac) return "";
  const d = new Date(fechaNac);
  if (isNaN(d)) return "";
  const diff = new Date(Date.now() - d.getTime());
  return Math.abs(diff.getUTCFullYear() - 1970);
};
