/* Fórmulas del cotizador (validadas con caso real Alfa Sur):
   Inscripción con IVA = Monto contratado × 3.5% × 1.16
   1ra cuota periódica  = Monto contratado × 2.2%
   Importe total         = Inscripción con IVA + 1ra cuota periódica */
const calcMontos = (monto) => {
  const m = parseFloat(monto) || 0;
  const inscripcion = m * 0.035 * 1.16;
  const cuota = m * 0.022;
  const total = inscripcion + cuota;
  return { inscripcion, cuota, total };
};

/* ============================================================
   COTIZADOR OFICIAL ALFA SUR (replicado de COTIZA_AUTOCON.xlsx)
   Uso exclusivo dentro de la plataforma. Sin exportación.
   ============================================================ */
const PLAN_FACTORES = {
  agencia: 0.137 / 12,
  ahorrador: 0.0175,
  puntual60: 0.022,
  puntual48: 0.026,
  casaLiquidez: 0.01,
};
const PLAN_PLAZOS_FIJOS = { engancheDirecto: 44, ahorroPuntos: 59, engancheDiferido: 46 };

// Réplica exacta de la función PMT de Excel (rate, nper, pv, fv=0, type=0)
function pmtExcel(rate, nper, pv, fv = 0, type = 0) {
  if (rate === 0) return -(pv + fv) / nper;
  const pow = Math.pow(1 + rate, nper);
  let pmt = (rate / (pow - 1)) * -(pv * pow + fv);
  if (type === 1) pmt /= 1 + rate;
  return pmt;
}

function calcCotizador({ precio, precioLleno }) {
  const p = parseFloat(precio) || 0;
  const pLleno = parseFloat(precioLleno) || 0;
  const baseMensualidad = pLleno > 0 ? pLleno : p; // IF($B$13="",$B$15,$B$13)

  const descuentoAplicado = pLleno > 0 ? 1 - p / pLleno : null; // "-" si no hay precio lleno

  const maxAutorizado = (p + 15000) + (p + 15000) * 0.5; // (B15+15000)*1.5
  const inscripcion = maxAutorizado * 0.035;
  const iva = inscripcion * 0.16;
  const inscripcionConIva = inscripcion + iva;

  const mma = {
    ahorrador: maxAutorizado * PLAN_FACTORES.ahorrador,
    puntual60: maxAutorizado * PLAN_FACTORES.puntual60,
    puntual48: maxAutorizado * PLAN_FACTORES.puntual48,
    casaLiquidez: maxAutorizado * PLAN_FACTORES.casaLiquidez,
  };

  const pagoInicialGeneral = inscripcionConIva + mma.puntual60; // D17+E17+D25

  const pagoInicial = {
    agencia: p * 0.2 + inscripcionConIva, // B21
    ahorrador: pagoInicialGeneral, // C21
    puntual60: pagoInicialGeneral, // D21
    puntual48: pagoInicialGeneral, // E21
    casaLiquidez: inscripcionConIva + mma.casaLiquidez, // F21
  };

  const tasaNominal = {};
  const tasaEfectiva = {};
  Object.keys(PLAN_FACTORES).forEach((k) => {
    tasaNominal[k] = PLAN_FACTORES[k] * 12;
    tasaEfectiva[k] = Math.pow(1 + PLAN_FACTORES[k], 12) - 1;
  });

  const financiadoAgencia = baseMensualidad * 0.8;
  const primeraMensualidad = {
    agencia: pmtExcel(PLAN_FACTORES.agencia * 1.16, 48, -financiadoAgencia),
    ahorrador: baseMensualidad * PLAN_FACTORES.ahorrador,
    puntual60: baseMensualidad * PLAN_FACTORES.puntual60,
    puntual48: baseMensualidad * PLAN_FACTORES.puntual48,
    casaLiquidez: baseMensualidad * PLAN_FACTORES.casaLiquidez,
  };

  // CV (cálculo interno, visible para asesores y admins, nunca en la cotización del cliente)
  const factorCV = pagoInicialGeneral >= 30000 ? 0.26 : 0.25;
  const cv = pagoInicialGeneral * factorCV;
  const ret12 = cv * 0.12;
  const cvTotal = cv - ret12;

  // Comparativa (solo aplica si Precio Lleno sin Descuento es mayor a $100,000)
  // B28 = IF(B13="","",B13*0.022) · C28 = IF(B13="","",B15*0.0175) · D28=B28-C28 · E28=D28*12
  // B14 = IF(B13="","-",1-B15/B13)  → % Descuento Aplicado
  const comparativa = pLleno > 100000 ? {
    descuentoAplicado: 1 - p / pLleno, // B14
    mensualSinDescuento: pLleno * PLAN_FACTORES.puntual60, // B28: Precio Lleno × 2.2% (factor Pago Puntual 60m)
    mensualConDescuento: p * PLAN_FACTORES.ahorrador, // C28: Precio (con descuento) × 1.75% (factor Plan Ahorrador)
    ahorroMensual: 0, // se calcula abajo
    ahorroAnual: 0,
  } : null;
  if (comparativa) {
    comparativa.ahorroMensual = comparativa.mensualSinDescuento - comparativa.mensualConDescuento; // D28
    comparativa.ahorroAnual = comparativa.ahorroMensual * 12; // E28
  }

  // Planes para la hoja de cotización del cliente (Cotización)
  const planesCliente = {
    engancheDirecto: { enganche: maxAutorizado * 0.35, plazo: PLAN_PLAZOS_FIJOS.engancheDirecto, cuota: mma.puntual60 },
    ahorroPuntos: { enganche: null, plazo: PLAN_PLAZOS_FIJOS.ahorroPuntos, cuota: mma.puntual60 },
    engancheDiferido: { enganche: maxAutorizado * 0.25, plazo: PLAN_PLAZOS_FIJOS.engancheDiferido, cuota: mma.puntual60 },
  };

  return {
    maxAutorizado, inscripcion, iva, inscripcionConIva, descuentoAplicado,
    mma, pagoInicialGeneral, pagoInicial, tasaNominal, tasaEfectiva,
    primeraMensualidad, factorCV, cv, ret12, cvTotal, planesCliente, comparativa,
  };
}

/* ---------- storage ---------- */
function withTimeout(promise, ms = 8000) {
  return Promise.race([
    promise,
    new Promise((_, reject) => setTimeout(() => reject(new Error("La plataforma tardó demasiado en responder. Intenta de nuevo.")), ms)),
  ]);
}
// Reintenta una operación de guardado varias veces antes de rendirse — se usa después de reservar
// un folio, para no desperdiciarlo por una falla pasajera de conexión (en vez de solo tronar una vez).
async function conReintento(fn, intentos = 3, esperaMs = 600) {
  let ultimoError;
  for (let i = 0; i < intentos; i++) {
    try {
      return await fn();
    } catch (err) {
      ultimoError = err;
      if (i < intentos - 1) await new Promise((r) => setTimeout(r, esperaMs));
    }
  }
  throw ultimoError;
}
/* ── Progreso de Entrenamiento de Ventas (progreso, quizzes, insignias) ── */
const PROGRESO_VACIO = { completados: {}, quizScores: {}, badges: [] };

async function loadProgresoEntrenamiento(asesorId) {
  try {
    const { data, error } = await supabase.from("entrenamiento_progreso").select("*").eq("asesor_id", asesorId).maybeSingle();
    if (error) throw error;
    if (!data) return { ...PROGRESO_VACIO };
    // "badges" siempre se calculan en vivo a partir del progreso — nunca se guardan aparte.
    return { completados: data.completados || {}, quizScores: data.quiz_scores || {}, badges: [] };
  } catch {
    return { ...PROGRESO_VACIO };
  }
}
async function guardarProgresoEntrenamiento(asesorId, progreso) {
  const { error } = await supabase.from("entrenamiento_progreso").upsert({
    asesor_id: asesorId,
    completados: progreso.completados || {},
    quiz_scores: progreso.quizScores || {},
  });
  if (error) throw error;
}
// Lee el progreso más reciente, aplica el cambio, y guarda de inmediato — evita pisar avances hechos en otra sesión/pestaña.
async function actualizarProgresoEntrenamiento(asesorId, actualizarFn) {
  const actual = await loadProgresoEntrenamiento(asesorId);
  const nuevo = actualizarFn(actual);
  await guardarProgresoEntrenamiento(asesorId, nuevo);
  return nuevo;
}
// Para el ranking del admin: junta el progreso de todos los asesores.
async function loadProgresoDeTodos(advisors) {
  const resultados = await Promise.all(
    advisors.map(async (a) => {
      const p = await loadProgresoEntrenamiento(a.id);
      return { asesorId: a.id, nombre: a.nombre, activo: a.activo, progreso: p };
    })
  );
  return resultados;
}

/* ── Cobranza Mensual (clientes ya contratados, ventana de pago del 1 al 3 de cada mes) ── */
async function loadCobranza(citaId) {
  try {
    const { data, error } = await supabase.from("cobranza_pagos").select("*").eq("solicitud_id", citaId);
    if (error) throw error;
    const pagos = {};
    (data || []).forEach((fila) => {
      pagos[fila.mes] = { estatus: fila.estatus, fechaPago: fila.fecha_pago, comprobante: fila.comprobante };
    });
    return { pagos };
  } catch {
    return { pagos: {} };
  }
}
// Trae la cobranza de MUCHOS clientes en una sola consulta (en vez de una por cliente,
// como hacía antes CobranzaMensual y RespaldoCompleto). Devuelve un mapa { solicitudId: {pagos} }.
async function loadCobranzaBulk(solicitudIds) {
  const mapa = {};
  if (!solicitudIds || solicitudIds.length === 0) return mapa;
  try {
    const { data, error } = await supabase.from("cobranza_pagos").select("*").in("solicitud_id", solicitudIds);
    if (error) throw error;
    (data || []).forEach((fila) => {
      if (!mapa[fila.solicitud_id]) mapa[fila.solicitud_id] = { pagos: {} };
      mapa[fila.solicitud_id].pagos[fila.mes] = { estatus: fila.estatus, fechaPago: fila.fecha_pago, comprobante: fila.comprobante };
    });
    return mapa;
  } catch {
    return mapa;
  }
}
async function guardarCobranza(citaId, datos) {
  const meses = Object.keys(datos.pagos || {});
  if (meses.length === 0) {
    await supabase.from("cobranza_pagos").delete().eq("solicitud_id", citaId);
    return;
  }
  // Borra los meses que ya no estén en "datos" (por si algún día se quita un mes por completo)
  await supabase.from("cobranza_pagos").delete().eq("solicitud_id", citaId)
    .not("mes", "in", `(${meses.map((m) => `"${m}"`).join(",")})`);
  const filas = meses.map((mes) => ({
    solicitud_id: citaId,
    mes,
    estatus: datos.pagos[mes].estatus,
    fecha_pago: datos.pagos[mes].fechaPago || null,
    comprobante: datos.pagos[mes].comprobante || null,
  }));
  const { error } = await supabase.from("cobranza_pagos").upsert(filas, { onConflict: "solicitud_id,mes" });
  if (error) throw error;
}
// Lee la cobranza más reciente antes de escribir, para no pisar un pago marcado desde otra sesión.
async function actualizarCobranza(citaId, actualizarFn) {
  const actual = await loadCobranza(citaId);
  const nuevo = actualizarFn(actual);
  await guardarCobranza(citaId, nuevo);
  return nuevo;
}

// Determina el día 1 del primer mes de cobro según la fecha de contratación (fecha en que se guardó la solicitud):
// - Contratado del día 1 al 21  → primer cobro el día 1 del mes SIGUIENTE.
// - Contratado del día 22 al 31 → primer cobro el día 1 del mes SUBSECUENTE (se salta un mes completo).
function primerMesCobro(fechaContratacion) {
  const dia = fechaContratacion.getDate();
  const saltoMeses = dia <= 21 ? 1 : 2;
  return new Date(fechaContratacion.getFullYear(), fechaContratacion.getMonth() + saltoMeses, 1);
}

// Genera los 12 meses de cobro consecutivos ("YYYY-MM") a partir del primer mes de cobro calculado.
function mesesDeCobranzaSolicitud(fechaContratacion) {
  const meses = [];
  let cursor = primerMesCobro(fechaContratacion);
  for (let i = 0; i < 12; i++) {
    meses.push(`${cursor.getFullYear()}-${String(cursor.getMonth() + 1).padStart(2, "0")}`);
    cursor = new Date(cursor.getFullYear(), cursor.getMonth() + 1, 1);
  }
  return meses;
}
const MES_LABEL = (mesStr) => {
  const [anio, mes] = mesStr.split("-").map(Number);
  return `${MESES_ES[mes - 1]} ${anio}`;
};
const MES_LABEL_CORTO = (mesStr) => {
  const [anio, mes] = mesStr.split("-").map(Number);
  return `${MESES_ES[mes - 1].slice(0, 3)} ${String(anio).slice(-2)}`;
};

// Citas de Agenda Virtual — una fila por cita, ligada al asesor dueño.
async function loadCitas(asesorId) {
  try {
    const { data, error } = await supabase.from("citas").select("*").eq("asesor_id", asesorId);
    if (error) throw error;
    return (data || []).map(aCamelCase);
  } catch {
    return [];
  }
}
// Trae las citas de MUCHOS asesores en una sola consulta (en vez de una por asesor, como
// hacía antes RespaldoCompleto). Devuelve un mapa { asesorId: [citas...] }.
async function loadCitasBulk(asesorIds) {
  const mapa = {};
  if (!asesorIds || asesorIds.length === 0) return mapa;
  try {
    const { data, error } = await supabase.from("citas").select("*").in("asesor_id", asesorIds);
    if (error) throw error;
    (data || []).map(aCamelCase).forEach((cita) => {
      if (!mapa[cita.asesorId]) mapa[cita.asesorId] = [];
      mapa[cita.asesorId].push(cita);
    });
    return mapa;
  } catch {
    return mapa;
  }
}
async function saveCitas(asesorId, list) {
  const idsNuevos = list.map((c) => c.id);
  if (idsNuevos.length > 0) {
    await supabase.from("citas").delete().eq("asesor_id", asesorId).not("id", "in", `(${idsNuevos.map((id) => `"${id}"`).join(",")})`);
  } else {
    await supabase.from("citas").delete().eq("asesor_id", asesorId);
  }
  if (list.length > 0) {
    const filas = list.map((c) => aSnakeCase({ ...c, asesorId }));
    const { error } = await supabase.from("citas").upsert(filas);
    if (error) throw error;
  }
}

// Caché sencilla en memoria (se reinicia sola al recargar la página). Solo se usa para
// datos que cambian poco (como la lista de asesores) — nunca para Solicitudes, Cotizaciones,
// Citas o Cobranza, donde siempre queremos la información más fresca posible.
const _cache = {};
const CACHE_TTL_MS = 20000; // 20 segundos
async function conCache(clave, fn) {
  const entrada = _cache[clave];
  if (entrada && Date.now() - entrada.tiempo < CACHE_TTL_MS) return entrada.valor;
  const valor = await fn();
  _cache[clave] = { valor, tiempo: Date.now() };
  return valor;
}
function invalidarCache(clave) {
  delete _cache[clave];
}

