/* ── Productividad / racha de días con "0 pendientes" por asesor ──
   Se guarda por separado de la agenda para que sobreviva sin importar cambios,
   borrados o duplicados de pendientes. */
function productividadKey(asesorId) { return `productividad-${asesorId}`; }

async function loadProductividad(asesorId) {
  try {
    const r = await withTimeout(window.storage.get(productividadKey(asesorId), true));
    return r ? JSON.parse(r.value) : { diasConsecutivosCero: 0, fechaUltimaEvaluacion: null, bajaAplicada: false };
  } catch {
    return { diasConsecutivosCero: 0, fechaUltimaEvaluacion: null, bajaAplicada: false };
  }
}
async function saveProductividad(asesorId, data) {
  try { await withTimeout(window.storage.set(productividadKey(asesorId), JSON.stringify(data), true)); } catch {}
}

// Evalúa y actualiza la racha de "0 pendientes" de un asesor. Nunca vuelve a evaluar el mismo
// día dos veces, y los días pasados se calculan de forma permanente (no se pierden al editar,
// borrar, mover o duplicar pendientes, porque solo se leen las fechas ya guardadas).
// opciones.pendientesHoyLive: si se conoce el indicador EXACTO de HOY (solo el propio asesor
// puede darlo, porque depende de "finalizados", que vive en su navegador), se usa para cerrar
// el día con precisión a partir de las 18:00. Si no se provee, se usa un cálculo aproximado.
async function evaluarProductividadAsesor(asesorId, opciones = {}) {
  const hoy = fechaLocalISO();
  const horaActual = new Date().getHours();

  let citas = opciones.citasPrecargadas;
  if (!citas) {
    try {
      citas = await loadCitas(asesorId);
    } catch { citas = []; }
  }

  const prod = await loadProductividad(asesorId);
  let diasConsecutivosCero = prod.diasConsecutivosCero || 0;
  let fechaUltimaEvaluacion = prod.fechaUltimaEvaluacion || null;
  let bajaAplicada = !!prod.bajaAplicada;

  // 1) Días pasados aún no evaluados (nunca incluye HOY, porque el día no ha terminado)
  if (fechaUltimaEvaluacion) {
    let cursor = new Date(fechaUltimaEvaluacion + "T00:00:00");
    cursor.setDate(cursor.getDate() + 1);
    let guard = 0;
    while (fechaLocalISO(cursor) < hoy && guard < 180) {
      const fechaCursor = fechaLocalISO(cursor);
      const huboActividad = citas.some((c) => c.fecha === fechaCursor);
      diasConsecutivosCero = huboActividad ? 0 : diasConsecutivosCero + 1;
      fechaUltimaEvaluacion = fechaCursor;
      cursor.setDate(cursor.getDate() + 1);
      guard++;
    }
  }

  // 2) Cerrar HOY si ya pasó la ventana de las 18:00 y aún no se evaluó ese día
  if (fechaUltimaEvaluacion !== hoy && horaActual >= 18) {
    const pendientesFinal = typeof opciones.pendientesHoyLive === "number"
      ? opciones.pendientesHoyLive
      : (citas.some((c) => c.fecha === hoy) ? 1 : 0);
    diasConsecutivosCero = pendientesFinal === 0 ? diasConsecutivosCero + 1 : 0;
    fechaUltimaEvaluacion = hoy;
  }

  // 3) Baja automática: ya se completaron 5 días consecutivos en 0 y ya inició un día posterior
  let bajaAhora = false;
  if (!bajaAplicada && diasConsecutivosCero >= 5 && fechaUltimaEvaluacion && fechaUltimaEvaluacion < hoy) {
    bajaAplicada = true;
    bajaAhora = true;
  }

  const actualizado = { diasConsecutivosCero, fechaUltimaEvaluacion, bajaAplicada };
  if (
    actualizado.diasConsecutivosCero !== prod.diasConsecutivosCero ||
    actualizado.fechaUltimaEvaluacion !== prod.fechaUltimaEvaluacion ||
    actualizado.bajaAplicada !== prod.bajaAplicada
  ) {
    await saveProductividad(asesorId, actualizado);
  }

  return { ...actualizado, bajaAhora };
}

// Recorre a todos los asesores activos y aplica la baja automática si corresponde.
// Se ejecuta al cargar la plataforma y periódicamente mientras hay un administrador conectado,
// para que la restricción se aplique aunque el propio asesor no vuelva a entrar.
async function sincronizarProductividadAsesores(advisorsList) {
  let cambios = false;
  const actualizados = [];
  for (const a of advisorsList) {
    if (!a.activo) { actualizados.push(a); continue; }
    try {
      const resultado = await evaluarProductividadAsesor(a.id, {});
      if (resultado.bajaAhora) { actualizados.push({ ...a, activo: false }); cambios = true; }
      else actualizados.push(a);
    } catch { actualizados.push(a); }
  }
  if (cambios) { try { await saveAdvisors(actualizados); } catch {} }
  return cambios ? actualizados : advisorsList;
}

