/* ── Conversores automáticos camelCase (JS) ↔ snake_case (columnas de Supabase) ──
   Así no hay que traducir a mano cada uno de los ~60 campos de una solicitud. ── */
function aSnakeCase(obj) {
  const out = {};
  for (const k in obj) {
    // Maneja tanto camelCase normal (montoContratado -> monto_contratado) como siglas
    // seguidas (fechaISO -> fecha_iso, no fecha_i_s_o) tratándolas como una sola palabra.
    const snake = k
      .replace(/([a-z0-9])([A-Z])/g, "$1_$2")
      .replace(/([A-Z]+)([A-Z][a-z])/g, "$1_$2")
      .toLowerCase();
    // "" se guarda como null — así una columna numérica o de fecha nunca la rechaza por venir vacía.
    out[snake] = obj[k] === "" ? null : obj[k];
  }
  return out;
}
function aCamelCase(obj) {
  const out = {};
  for (const k in obj) {
    const camel = k.replace(/_([a-z])/g, (_, c) => c.toUpperCase());
    out[camel] = obj[k];
  }
  return out;
}
// Reemplaza por completo el contenido de una tabla por la lista dada (agrega/actualiza lo
// que traiga la lista, y borra lo que ya no esté) — mismo comportamiento que tenía antes
// guardar "la lista completa", ahora usando consultas reales en vez de sobrescribir un bloque.
async function reemplazarTabla(tabla, list) {
  const idsNuevos = list.map((x) => x.id);
  if (idsNuevos.length > 0) {
    await supabase.from(tabla).delete().not("id", "in", `(${idsNuevos.map((id) => `"${id}"`).join(",")})`);
  } else {
    await supabase.from(tabla).delete().neq("id", "__ninguno__");
  }
  if (list.length > 0) {
    const filas = list.map(aSnakeCase);
    const { error } = await supabase.from(tabla).upsert(filas);
    if (error) throw error;
  }
}

