/* ── Papelera de reciclaje (Solicitudes y Cotizaciones): 30 días para restaurar antes de purgar ── */
const DIAS_RETENCION_PAPELERA = 30;
function diasRestantesPapelera(fechaEliminacionIso) {
  if (!fechaEliminacionIso) return DIAS_RETENCION_PAPELERA;
  const transcurridos = (Date.now() - new Date(fechaEliminacionIso).getTime()) / (1000 * 60 * 60 * 24);
  return Math.max(0, Math.ceil(DIAS_RETENCION_PAPELERA - transcurridos));
}
// Quita de forma permanente (purga) los registros eliminados hace más de 30 días. Se llama cada
// vez que se abre una papelera, así nunca hace falta un proceso aparte corriendo en segundo plano.
// Borra SOLO los que ya vencieron — nunca reescribe los que se quedan, para no ensuciar la bitácora.
async function purgarPapeleraSolicitudes() {
  const todas = await loadSolicitudes();
  const vencidas = todas.filter((s) => s.eliminada && diasRestantesPapelera(s.fechaEliminacionIso) <= 0);
  const vigentes = todas.filter((s) => !s.eliminada || diasRestantesPapelera(s.fechaEliminacionIso) > 0);
  if (vencidas.length > 0) {
    await supabase.from("solicitudes").delete().in("id", vencidas.map((s) => s.id));
  }
  return vigentes;
}
async function purgarPapeleraCotizaciones() {
  const todas = await loadCotizaciones();
  const vencidas = todas.filter((c) => c.eliminada && diasRestantesPapelera(c.fechaEliminacionIso) <= 0);
  const vigentes = todas.filter((c) => !c.eliminada || diasRestantesPapelera(c.fechaEliminacionIso) > 0);
  if (vencidas.length > 0) {
    await supabase.from("cotizaciones").delete().in("id", vencidas.map((c) => c.id));
  }
  return vigentes;
}
