async function resetPruebas() {
  // Borra solo los registros de prueba (008 y 009) y reinicia el contador a 72510007
  const solicitudes = await loadSolicitudes();
  const cotizaciones = await loadCotizaciones();
  await saveSolicitudes(solicitudes.filter((s) => !TEST_FOLIOS.includes(String(s.folioNumero))));
  await saveCotizaciones(cotizaciones.filter((c) => !TEST_FOLIOS.includes(String(c.noCaratula)) && !TEST_FOLIOS.includes(String(c.folioNumero))));
  const { error } = await supabase.rpc("reiniciar_contadores", { nuevo_folio: BASE_FOLIO - 1 });
  if (error) throw error;
}
async function getNextFolioPractica() {
  // Solo devuelve 72510008 o 72510009 — nunca un folio de producción.
  // Igual que el folio real, la alternancia se hace de forma atómica dentro de la base de datos.
  const { data: candidato, error } = await supabase.rpc("siguiente_folio_practica");
  if (error) throw error;
  const solicitudes = await loadSolicitudes();
  const usados = solicitudes.map((s) => String(s.folioNumero));
  if (usados.includes(String(candidato))) {
    // Ya estaba usado (caso raro: los 2 folios de práctica ocupados) — hay que reiniciar.
    return null;
  }
  return { numero: candidato, contrato: `AL${candidato}` };
}

