function HistorialCotizacionesPanel({ cotizaciones, showAsesor, onClose }) {
  const [query, setQuery] = useState("");

  const filtered = [...cotizaciones]
    .filter((c) => query ? (c.cliente || "").toLowerCase().includes(query.toLowerCase()) : true)
    .sort((a, b) => (b.fechaCreacion || "").localeCompare(a.fechaCreacion || ""));

  return (
    <div>
      {/* TopBar rojo estilo panel */}
      <div style={{ background: COLORS.red, color: "#fff", padding: "16px 20px" }} className="no-print">
        <div style={{ maxWidth: 1100, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div>
            <div style={{ fontSize: 11, letterSpacing: 3, color: "rgba(255,255,255,0.7)", textTransform: "uppercase", fontWeight: 600 }}>Autocon Management · Plataforma</div>
            <div className="display" style={{ fontSize: 20, fontWeight: 700 }}>📋 Historial Cotizaciones</div>
          </div>
          <button onClick={onClose} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: COLORS.navy, color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>
        </div>
      </div>

      <div style={{ maxWidth: 1000, margin: "0 auto", padding: "20px 20px" }}>
        {/* Buscador */}
        <input
          placeholder="Buscar por nombre de cliente…"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          style={{ width: "100%", padding: "10px 14px", border: `1px solid ${COLORS.line}`, borderRadius: 6, fontSize: 14, marginBottom: 16 }}
          autoFocus
        />

        {/* Lista */}
        {filtered.length === 0 ? (
          <div style={{ padding: 32, textAlign: "center", color: COLORS.slateSoft, fontSize: 14, background: "#fff", borderRadius: 6 }}>
            {query ? "No se encontró ninguna cotización con ese nombre." : "No hay cotizaciones en el historial."}
          </div>
        ) : (
          <div style={{ background: "#fff", borderRadius: 6, overflow: "hidden", border: `1px solid ${COLORS.line}` }}>
            {/* Encabezado columnas */}
            <div style={{ display: "grid", gridTemplateColumns: showAsesor ? "2fr 1fr 1fr 1fr 0.7fr" : "2fr 1fr 1fr 0.7fr", padding: "8px 16px", background: COLORS.navy, fontSize: 11, fontWeight: 700, color: "#fff", textTransform: "uppercase", letterSpacing: 0.5 }}>
              <div>Cliente</div>
              {showAsesor && <div>Asesor</div>}
              <div>Fecha</div>
              <div>Monto</div>
              <div style={{ textAlign: "center" }}>Estatus</div>
            </div>
            {filtered.map((c, i) => {
              const eliminada = c.eliminada === true;
              const monto = calcCotizador({ precio: c.precio, precioLleno: c.precioLleno }).maxAutorizado;
              return (
                <div key={c.id || i} style={{ display: "grid", gridTemplateColumns: showAsesor ? "2fr 1fr 1fr 1fr 0.7fr" : "2fr 1fr 1fr 0.7fr", padding: "7px 16px", borderBottom: `1px solid ${COLORS.line}`, fontSize: 13, background: eliminada ? "#FFF5F5" : i % 2 === 0 ? "#fff" : "#FAFAF7", alignItems: "center" }}>
                  <div style={{ fontWeight: 600, color: eliminada ? COLORS.slateSoft : COLORS.slate, textDecoration: eliminada ? "line-through" : "none" }}>{c.cliente || "(sin nombre)"}</div>
                  {showAsesor && <div style={{ fontSize: 12, color: COLORS.slateSoft }}>{c.asesorNombre || "—"}</div>}
                  <div style={{ fontSize: 12, color: COLORS.slateSoft }}>{c.fechaCreacion || "—"}</div>
                  <div style={{ fontWeight: 600, color: eliminada ? COLORS.slateSoft : COLORS.navy }}>{fmtMoney(monto)}</div>
                  <div style={{ textAlign: "center" }}>
                    {eliminada ? <span style={{ color: COLORS.red, fontWeight: 700, fontSize: 16 }}>✗</span> : <span style={{ color: COLORS.green, fontWeight: 700, fontSize: 16 }}>✓</span>}
                  </div>
                </div>
              );
            })}
          </div>
        )}
        <div style={{ marginTop: 12, fontSize: 11, color: COLORS.slateSoft, textAlign: "right" }}>
          ✓ Guardada &nbsp;·&nbsp; ✗ Eliminada &nbsp;·&nbsp; Total: {cotizaciones.length} cotizaciones
        </div>
      </div>
    </div>
  );
}

function CotizacionesTab({ cotizaciones, advisors, onPrint, canDelete, onRefresh, isGeneral }) {
  const [vista, setVista] = useState(null); // null (menú) | "diarias" | "historial"

  const activas = cotizaciones.filter((c) => !c.eliminada);

  // "Día en curso" = de 00:30 a 23:30 de la fecha de hoy (mismo criterio que Solicitudes).
  const ahora = new Date();
  const hoyInicio = new Date(ahora); hoyInicio.setHours(0, 30, 0, 0);
  const hoyFin = new Date(ahora); hoyFin.setHours(23, 30, 0, 0);
  const inicioAnio = new Date(ahora.getFullYear(), 0, 1, 0, 0, 0).getTime();

  const cotizacionesDiarias = activas
    .filter((c) => { const t = getCotTimestamp(c); return t >= hoyInicio.getTime() && t <= hoyFin.getTime(); })
    .sort((a, b) => getCotTimestamp(a) - getCotTimestamp(b));

  const cotizacionesHistorial = activas
    .filter((c) => { const t = getCotTimestamp(c); return t < hoyInicio.getTime() && t >= inicioAnio; })
    .sort((a, b) => getCotTimestamp(b) - getCotTimestamp(a));

  // Menú principal: los dos botones
  if (!vista) {
    return (
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: 16 }}>
        <div
          onClick={() => setVista("diarias")}
          style={{ background: "#F5C518", borderRadius: 12, padding: "26px 22px", cursor: "pointer", boxShadow: "0 2px 8px rgba(0,0,0,0.10)", transition: "transform 0.15s" }}
          onMouseOver={(e) => { e.currentTarget.style.transform = "scale(1.02)"; }}
          onMouseOut={(e) => { e.currentTarget.style.transform = "scale(1)"; }}
        >
          <div style={{ fontSize: 34, marginBottom: 6 }}>📋</div>
          <div className="display" style={{ fontWeight: 800, fontSize: 18, color: "#142B4D", textTransform: "uppercase", letterSpacing: 0.5 }}>Cotizaciones Diarias</div>
          <div style={{ fontSize: 12, color: "#142B4D", opacity: 0.82, marginTop: 6, lineHeight: 1.4 }}>{cotizacionesDiarias.length} cotización(es) guardada(s) hoy</div>
        </div>
        <div
          onClick={() => setVista("historial")}
          style={{ background: "#1A1A1A", borderRadius: 12, padding: "26px 22px", cursor: "pointer", boxShadow: "0 2px 8px rgba(0,0,0,0.10)", transition: "transform 0.15s" }}
          onMouseOver={(e) => { e.currentTarget.style.transform = "scale(1.02)"; }}
          onMouseOut={(e) => { e.currentTarget.style.transform = "scale(1)"; }}
        >
          <div style={{ fontSize: 34, marginBottom: 6 }}>🗂️</div>
          <div className="display" style={{ fontWeight: 800, fontSize: 18, color: "#fff", textTransform: "uppercase", letterSpacing: 0.5 }}>Historial de Cotizaciones</div>
          <div style={{ fontSize: 12, color: "#fff", opacity: 0.82, marginTop: 6, lineHeight: 1.4 }}>{cotizacionesHistorial.length} registrada(s) desde el inicio del año</div>
        </div>
      </div>
    );
  }

  const esDiarias = vista === "diarias";
  return (
    <ListaCotizaciones
      titulo={esDiarias ? "Cotizaciones Diarias" : "Historial de Cotizaciones"}
      colorAccento={esDiarias ? "#F5C518" : "#1A1A1A"}
      lista={esDiarias ? cotizacionesDiarias : cotizacionesHistorial}
      advisors={advisors}
      onPrint={onPrint}
      canDelete={canDelete}
      onRefresh={onRefresh}
      onBack={() => setVista(null)}
      isGeneral={isGeneral}
    />
  );
}

// Lista reutilizable con buscador propio (por nombre/apellido del cliente) y filtro por asesor.
// Usada tanto por "Cotizaciones Diarias" como por "Historial de Cotizaciones".
function ListaCotizaciones({ titulo, colorAccento, lista, advisors, onPrint, canDelete, onRefresh, onBack, isGeneral }) {
  const [query, setQuery] = useState("");
  const [filterAsesor, setFilterAsesor] = useState("");
  const [deleteTargetId, setDeleteTargetId] = useState(null);
  const [deleteCode, setDeleteCode] = useState("");
  const [deleteError, setDeleteError] = useState("");
  const [deleting, setDeleting] = useState(false);

  const filtered = lista
    .filter((c) => (filterAsesor ? c.asesorId === filterAsesor : true))
    .filter((c) => (query ? (c.cliente || "").toLowerCase().includes(query.trim().toLowerCase()) : true));

  const exportarPDF = () => {
    exportarListaComoPDF({
      titulo,
      subtitulo: `${filtered.length} de ${lista.length} cotización(es)${filterAsesor ? " · asesor filtrado" : ""}${query ? ` · búsqueda: "${query}"` : ""}`,
      columnas: ["Cliente", "Asesor", "No. Carátula", "No. Contrato", "Unidad", "Precio", "Fecha"],
      filas: filtered.map((c) => [
        c.cliente || "(sin nombre)",
        c.asesorNombre || "—",
        c.noCaratula || "—",
        c.noContrato || "—",
        [c.unidad, c.modelo, c.anio].filter(Boolean).join(" "),
        fmtMoney(c.precio),
        c.fechaCreacion || "—",
      ]),
    });
  };

  const confirmDelete = async (targetId) => {
    if (!window.confirm("¿Eliminar esta cotización? Se puede recuperar después desde la Papelera.")) return;
    setDeleting(true);
    setDeleteError("");
    try {
      const all = await loadCotizaciones();
      const now = new Date();
      const fechaEliminacion = `${String(now.getDate()).padStart(2,"0")}/${String(now.getMonth()+1).padStart(2,"0")}/${now.getFullYear()} ${String(now.getHours()).padStart(2,"0")}:${String(now.getMinutes()).padStart(2,"0")}`;
      await saveCotizaciones(all.map((c) => c.id === targetId ? { ...c, eliminada: true, fechaEliminacion, fechaEliminacionIso: now.toISOString() } : c));
      await onRefresh();
    } catch (err) {
      alert(err?.message || "No se pudo borrar. Intenta de nuevo.");
    }
    setDeleting(false);
  };

  return (
    <div>
      <button onClick={onBack} style={linkBtnStyle}>← Regresar</button>
      <div style={{ display: "flex", alignItems: "center", gap: 10, margin: "10px 0 16px", flexWrap: "wrap" }}>
        <div style={{ width: 10, height: 28, borderRadius: 3, background: colorAccento, flexShrink: 0 }} />
        <div className="display" style={{ fontSize: 19, fontWeight: 800, color: COLORS.navy, textTransform: "uppercase" }}>{titulo}</div>
        <div style={{ fontSize: 13, color: COLORS.slateSoft }}>· {filtered.length} de {lista.length}</div>
        {isGeneral && (
          <button onClick={exportarPDF} style={{ marginLeft: "auto", padding: "8px 14px", border: "none", borderRadius: 6, background: "#142B4D", color: "#fff", fontWeight: 700, fontSize: 12.5, cursor: "pointer", whiteSpace: "nowrap" }}>
            📥 Exportar PDF
          </button>
        )}
      </div>

      <div style={{ display: "flex", gap: 10, marginBottom: 16, flexWrap: "wrap" }}>
        <input
          placeholder="Buscar por nombre y apellido del cliente…"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          style={{ flex: 1, minWidth: 200, padding: "9px 12px", border: `1px solid ${COLORS.line}`, borderRadius: 4, fontSize: 14 }}
        />
        <select
          value={filterAsesor}
          onChange={(e) => setFilterAsesor(e.target.value)}
          style={{ padding: "9px 12px", border: `1px solid ${COLORS.line}`, borderRadius: 4, fontSize: 14 }}
        >
          <option value="">Todos los asesores</option>
          {advisors.map((a) => (
            <option key={a.id} value={a.id}>{a.nombre}</option>
          ))}
        </select>
      </div>

      {filtered.length === 0 ? (
        <EmptyState text="No se encontraron cotizaciones con estos filtros." />
      ) : (
        <div style={{ background: "#fff", borderRadius: 6, overflow: "hidden", border: `1px solid ${COLORS.line}` }}>
          {filtered.map((c, i) => {
            const m = calcCotizador({ precio: c.precio, precioLleno: c.precioLleno });
            return (
              <div key={c.id} style={{ borderTop: i === 0 ? "none" : `1px solid ${COLORS.line}` }}>
                <div
                  onClick={() => onPrint(c)}
                  style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "14px 16px", cursor: "pointer" }}
                  onMouseEnter={(e) => (e.currentTarget.style.background = COLORS.cream)}
                  onMouseLeave={(e) => (e.currentTarget.style.background = "#fff")}
                >
                  <div>
                    <div style={{ fontWeight: 600, fontSize: 15 }}>{c.cliente || "(sin nombre)"}</div>
                    <div style={{ fontSize: 12, color: COLORS.slateSoft, marginTop: 2 }}>
                      Asesor: {c.asesorNombre || "—"} · No. Carátula: {c.noCaratula || "—"} · {fmtHoraCot(c)}
                    </div>
                  </div>
                  <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
                    <div style={{ fontWeight: 700, fontSize: 14, color: COLORS.navy }}>{fmtMoney(m.maxAutorizado)}</div>
                    <button onClick={(e) => { e.stopPropagation(); onPrint(c); }} style={primaryBtnStyle}>🖨️ IMPRIMIR</button>
                    {canDelete && (
                      <button
                        onClick={(e) => { e.stopPropagation(); confirmDelete(c.id); }}
                        disabled={deleting}
                        style={{ ...secondaryBtnStyle, color: COLORS.red, borderColor: COLORS.red }}
                      >
                        Eliminar
                      </button>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

/* ── Papelera de Solicitudes eliminadas (30 días para restaurar) ── */
function PapeleraSolicitudes({ isGeneral, onClose, onRefresh }) {
  const [lista, setLista] = useState(null);
  const [error, setError] = useState(false);
  const [ocupado, setOcupado] = useState(null);
  const [confirmPurga, setConfirmPurga] = useState(null); // id pendiente de confirmar borrado permanente
  const [purgaCode, setPurgaCode] = useState("");
  const [purgaError, setPurgaError] = useState("");

  const cargar = async () => {
    try {
      const vigentes = await purgarPapeleraSolicitudes(); // limpia automáticamente lo que ya pasó de 30 días
      setLista(vigentes.filter((s) => s.eliminada));
    } catch {
      setError(true);
    }
  };

  useEffect(() => { cargar(); }, []);

  const restaurar = async (id) => {
    setOcupado(id);
    try {
      await restaurarSolicitud(id);
      await cargar();
      if (onRefresh) await onRefresh();
    } catch {}
    setOcupado(null);
  };

  const confirmarPurgaDefinitiva = async () => {
    if (purgaCode.trim() !== (await loadDeleteCode())) {
      setPurgaError("Contraseña de borrado incorrecta.");
      return;
    }
    setOcupado(confirmPurga);
    try {
      await eliminarSolicitudPermanente(confirmPurga);
      setConfirmPurga(null);
      setPurgaCode("");
      setPurgaError("");
      await cargar();
    } catch {
      setPurgaError("No se pudo eliminar. Intenta de nuevo.");
    }
    setOcupado(null);
  };

  return (
    <div>
      <TopBar title="🗑️ Papelera de Solicitudes" subtitle="Se eliminan para siempre 30 días después de moverse aquí" onLogout={null}
        right={<button onClick={onClose} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: COLORS.red, color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>} />
      <div style={{ maxWidth: 800, margin: "0 auto", padding: "24px 20px 40px" }}>
        {error ? (
          <div style={{ color: "#B91C1C", fontSize: 14 }}>No se pudo cargar la papelera. Intenta de nuevo.</div>
        ) : lista === null ? (
          <div style={{ color: "#6B7280", fontSize: 14 }}>Cargando…</div>
        ) : lista.length === 0 ? (
          <div style={{ background: "#F8FAFC", borderRadius: 8, padding: 24, textAlign: "center", color: "#6B7280", fontSize: 14, border: "1px dashed #E3DECF" }}>
            🗑️ La papelera de solicitudes está vacía.
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {lista.map((s) => {
              const dias = diasRestantesPapelera(s.fechaEliminacionIso);
              return (
                <div key={s.id} style={{ background: "#fff", border: "1px solid #E3DECF", borderRadius: 8, padding: "12px 14px" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 10, flexWrap: "wrap" }}>
                    <div>
                      <div style={{ fontWeight: 700, fontSize: 14, color: "#142B4D" }}>{s.nombre || "—"}</div>
                      <div style={{ fontSize: 11.5, color: "#6B7280", marginTop: 2 }}>
                        Folio {s.folioContrato || s.folioNumero || "—"} · Asesor: {s.asesorNombre || "—"} · {fmtMoney(s.montoContratado)}
                      </div>
                      <div style={{ fontSize: 11.5, color: "#6B7280" }}>Eliminada el {s.fechaEliminacion || "—"}{s.motivoEliminacion ? ` · Motivo: ${s.motivoEliminacion}` : ""}</div>
                      <div style={{ fontSize: 11, color: dias <= 5 ? "#B91C1C" : "#92400E", fontWeight: 700, marginTop: 4 }}>
                        {dias > 0 ? `Se elimina para siempre en ${dias} día${dias !== 1 ? "s" : ""}` : "Se eliminará para siempre muy pronto"}
                      </div>
                    </div>
                    {isGeneral && (
                      <div style={{ display: "flex", gap: 8, flexShrink: 0 }}>
                        <button onClick={() => restaurar(s.id)} disabled={ocupado === s.id} style={{ padding: "8px 14px", border: "none", borderRadius: 6, background: "#16A34A", color: "#fff", fontWeight: 700, fontSize: 12, cursor: "pointer" }}>
                          ♻️ Restaurar
                        </button>
                        <button onClick={() => { setConfirmPurga(s.id); setPurgaCode(""); setPurgaError(""); }} style={{ padding: "8px 14px", border: "1px solid #EF4444", borderRadius: 6, background: "#fff", color: "#EF4444", fontWeight: 700, fontSize: 12, cursor: "pointer" }}>
                          Eliminar ya
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {confirmPurga && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)", zIndex: 9700, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
          <div style={{ background: "#fff", borderRadius: 10, padding: 26, maxWidth: 420, width: "100%", boxShadow: "0 8px 32px rgba(0,0,0,0.25)" }}>
            <div style={{ fontSize: 17, fontWeight: 700, color: COLORS.red, marginBottom: 6 }}>⚠️ Eliminar para siempre</div>
            <div style={{ fontSize: 13, color: COLORS.slate, marginBottom: 14 }}>Esta solicitud se borrará de forma permanente, sin poder recuperarse. Escribe la contraseña de borrado para confirmar.</div>
            <input type="password" value={purgaCode} onChange={(e) => { setPurgaCode(e.target.value); setPurgaError(""); }} placeholder="Contraseña de borrado"
              style={{ width: "100%", padding: "10px 12px", border: `1.5px solid ${COLORS.line}`, borderRadius: 6, fontSize: 14 }} />
            {purgaError && <div style={{ color: COLORS.red, fontSize: 13, marginTop: 8 }}>{purgaError}</div>}
            <div style={{ display: "flex", gap: 10, marginTop: 16 }}>
              <button onClick={confirmarPurgaDefinitiva} disabled={ocupado === confirmPurga} style={{ padding: "10px 20px", border: "none", borderRadius: 6, background: COLORS.red, color: "#fff", fontWeight: 700, fontSize: 14, cursor: "pointer" }}>
                {ocupado === confirmPurga ? "Eliminando…" : "Sí, eliminar para siempre"}
              </button>
              <button onClick={() => setConfirmPurga(null)} style={{ padding: "10px 20px", border: `1px solid ${COLORS.line}`, borderRadius: 6, background: "#fff", cursor: "pointer", fontSize: 14 }}>Cancelar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

