/* ── Barra de progreso ── */
function BarraProgreso({ completados, total }) {
  const pct = total > 0 ? Math.round((completados / total) * 100) : 0;
  return (
    <div style={{ marginBottom: 4 }}>
      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: "#6B7280", marginBottom: 4 }}>
        <span>Tu progreso</span>
        <span style={{ fontWeight: 700, color: "#142B4D" }}>{completados} de {total} completados ({pct}%)</span>
      </div>
      <div style={{ height: 10, background: "#E3DECF", borderRadius: 6, overflow: "hidden" }}>
        <div style={{ height: "100%", width: `${pct}%`, background: "linear-gradient(90deg, #22C55E, #F5C518, #EF4444)", borderRadius: 6, transition: "width .3s" }} />
      </div>
    </div>
  );
}

/* ── Insignias ganadas ── */
function InsigniasStrip({ progreso }) {
  const ganadas = insigniasGanadas(progreso);
  if (ganadas.length === 0) return null;
  return (
    <div style={{ display: "flex", flexWrap: "wrap", gap: 8, margin: "10px 0 16px" }}>
      {ganadas.map((b) => (
        <div key={b.id} style={{ background: "#EFF6FF", border: "1px solid #93C5FD", borderRadius: 20, padding: "4px 12px", fontSize: 12, fontWeight: 700, color: "#1E40AF", display: "flex", alignItems: "center", gap: 6 }}>
          <span>{b.icono}</span>{b.nombre}
        </div>
      ))}
    </div>
  );
}

/* ── Quiz de un tema ── */
function QuizTema({ quizKey, mejorPuntaje, onFinish }) {
  const preguntas = QUIZZES_ENTRENAMIENTO[quizKey];
  const [respuestas, setRespuestas] = useState({});
  const [revisado, setRevisado] = useState(false);

  if (!preguntas || preguntas.length === 0) return null;

  const todasContestadas = preguntas.every((_, i) => respuestas[i] !== undefined);
  const correctas = preguntas.reduce((acc, q, i) => acc + (respuestas[i] === q.r ? 1 : 0), 0);

  return (
    <div style={{ marginTop: 24, border: "2px solid #E3DECF", borderRadius: 10, padding: 16, background: "#FAFAF7" }}>
      <div style={{ fontWeight: 800, fontSize: 15, color: "#142B4D", marginBottom: 4 }}>📝 Ponte a prueba</div>
      {mejorPuntaje != null && (
        <div style={{ fontSize: 12, color: "#6B7280", marginBottom: 10 }}>Tu mejor puntaje aquí: {mejorPuntaje.correctas}/{mejorPuntaje.total}</div>
      )}
      {preguntas.map((q, qi) => (
        <div key={qi} style={{ marginBottom: 14 }}>
          <div style={{ fontSize: 13.5, fontWeight: 700, color: "#142B4D", marginBottom: 6 }}>{qi + 1}. {q.p}</div>
          <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
            {q.o.map((op, oi) => {
              const elegida = respuestas[qi] === oi;
              let bg = "#fff", border = "#E3DECF", color = "#374151";
              if (revisado) {
                if (oi === q.r) { bg = "#F0FDF4"; border = "#16A34A"; color = "#15803D"; }
                else if (elegida) { bg = "#FEF2F2"; border = "#EF4444"; color = "#B91C1C"; }
              } else if (elegida) { bg = "#EFF6FF"; border = "#2563EB"; color = "#1E40AF"; }
              return (
                <button
                  key={oi}
                  disabled={revisado}
                  onClick={() => setRespuestas((r) => ({ ...r, [qi]: oi }))}
                  style={{ textAlign: "left", padding: "8px 12px", borderRadius: 6, border: `2px solid ${border}`, background: bg, color, fontSize: 13, cursor: revisado ? "default" : "pointer" }}
                >
                  {op}
                </button>
              );
            })}
          </div>
        </div>
      ))}
      {!revisado ? (
        <button
          disabled={!todasContestadas}
          onClick={() => setRevisado(true)}
          style={{ padding: "10px 20px", borderRadius: 6, border: "none", background: todasContestadas ? "#142B4D" : "#D1D5DB", color: "#fff", fontWeight: 700, cursor: todasContestadas ? "pointer" : "not-allowed", fontSize: 13 }}
        >
          Revisar respuestas
        </button>
      ) : (
        <div>
          <div style={{ fontWeight: 800, fontSize: 14, color: correctas === preguntas.length ? "#15803D" : "#92400E", marginBottom: 10 }}>
            {correctas === preguntas.length ? "🎉 ¡Perfecto! " : "Resultado: "}{correctas} de {preguntas.length} correctas.
          </div>
          <button
            onClick={() => onFinish(correctas, preguntas.length)}
            style={{ padding: "10px 20px", borderRadius: 6, border: "none", background: "#16A34A", color: "#fff", fontWeight: 700, cursor: "pointer", fontSize: 13 }}
          >
            Guardar y continuar
          </button>
        </div>
      )}
    </div>
  );
}

/* ── Simulador de Objeciones ── */
function SimuladorObjeciones({ onClose }) {
  const [idx, setIdx] = useState(0);
  const [elegida, setElegida] = useState(null);
  const [aciertos, setAciertos] = useState(0);
  const [terminado, setTerminado] = useState(false);
  const escenario = OBJECIONES_SIMULADOR[idx];

  const elegir = (i) => {
    if (elegida !== null) return;
    setElegida(i);
    if (escenario.opciones[i].correcta) setAciertos((a) => a + 1);
  };
  const siguiente = () => {
    if (idx + 1 < OBJECIONES_SIMULADOR.length) { setIdx(idx + 1); setElegida(null); }
    else setTerminado(true);
  };
  const reiniciar = () => { setIdx(0); setElegida(null); setAciertos(0); setTerminado(false); };

  return (
    <div>
      <TopBar title="🎯 Simulador de Objeciones" onLogout={null} right={<button onClick={onClose} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: COLORS.red, color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>} />
      <div style={{ maxWidth: 640, margin: "0 auto", padding: "24px 20px 40px" }}>
        {terminado ? (
          <div style={{ textAlign: "center", padding: "30px 20px" }}>
            <div style={{ fontSize: 40, marginBottom: 10 }}>{aciertos === OBJECIONES_SIMULADOR.length ? "🏆" : "💪"}</div>
            <div style={{ fontSize: 18, fontWeight: 800, color: "#142B4D", marginBottom: 6 }}>Terminaste la ronda</div>
            <div style={{ fontSize: 14, color: "#6B7280", marginBottom: 20 }}>Respondiste bien {aciertos} de {OBJECIONES_SIMULADOR.length} objeciones.</div>
            <button onClick={reiniciar} style={{ padding: "12px 24px", borderRadius: 6, border: "none", background: "#142B4D", color: "#fff", fontWeight: 700, cursor: "pointer" }}>Volver a intentar</button>
          </div>
        ) : (
          <div>
            <div style={{ fontSize: 12, color: "#6B7280", marginBottom: 10 }}>Escenario {idx + 1} de {OBJECIONES_SIMULADOR.length}</div>
            <div style={{ background: "#EFF6FF", border: "1px solid #93C5FD", borderRadius: 8, padding: 16, marginBottom: 16 }}>
              <div style={{ fontSize: 14, color: "#1E40AF", fontWeight: 700 }}>{escenario.situacion}</div>
            </div>
            <div style={{ fontSize: 13, color: "#6B7280", marginBottom: 8 }}>¿Cuál es la mejor respuesta?</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {escenario.opciones.map((op, i) => {
                let bg = "#fff", border = "#E3DECF", color = "#374151";
                if (elegida !== null) {
                  if (op.correcta) { bg = "#F0FDF4"; border = "#16A34A"; color = "#15803D"; }
                  else if (i === elegida) { bg = "#FEF2F2"; border = "#EF4444"; color = "#B91C1C"; }
                }
                return (
                  <button key={i} onClick={() => elegir(i)} disabled={elegida !== null}
                    style={{ textAlign: "left", padding: "10px 14px", borderRadius: 8, border: `2px solid ${border}`, background: bg, color, fontSize: 13.5, cursor: elegida === null ? "pointer" : "default" }}>
                    {op.texto}
                  </button>
                );
              })}
            </div>
            {elegida !== null && (
              <div style={{ marginTop: 14 }}>
                <div style={{ background: "#FFFBEB", borderLeft: "4px solid #F5C518", borderRadius: "0 6px 6px 0", padding: "10px 14px", fontSize: 13, color: "#374151", marginBottom: 14 }}>
                  {escenario.opciones[elegida].feedback}
                </div>
                <button onClick={siguiente} style={{ padding: "10px 20px", borderRadius: 6, border: "none", background: "#142B4D", color: "#fff", fontWeight: 700, cursor: "pointer", fontSize: 13 }}>
                  {idx + 1 < OBJECIONES_SIMULADOR.length ? "Siguiente escenario →" : "Ver resultado final"}
                </button>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

/* ── Flashcards de Cierres ── */
function FlashcardsCierres({ onClose }) {
  const [idx, setIdx] = useState(0);
  const [volteada, setVolteada] = useState(false);
  const card = FLASHCARDS_CIERRES[idx];

  const mover = (delta) => {
    setVolteada(false);
    setIdx((i) => (i + delta + FLASHCARDS_CIERRES.length) % FLASHCARDS_CIERRES.length);
  };

  return (
    <div>
      <TopBar title="🗂️ Flashcards de Cierres" onLogout={null} right={<button onClick={onClose} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: COLORS.red, color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>} />
      <div style={{ maxWidth: 480, margin: "0 auto", padding: "24px 20px 40px", display: "flex", flexDirection: "column", alignItems: "center" }}>
        <div style={{ fontSize: 12, color: "#6B7280", marginBottom: 14 }}>Tarjeta {idx + 1} de {FLASHCARDS_CIERRES.length} · toca la tarjeta para voltearla</div>
        <div
          onClick={() => setVolteada((v) => !v)}
          style={{
            width: "100%", minHeight: 220, borderRadius: 14, cursor: "pointer",
            background: volteada ? "#142B4D" : colorDegradadoVendedor(idx, FLASHCARDS_CIERRES.length),
            display: "flex", alignItems: "center", justifyContent: "center", padding: 24, textAlign: "center",
            boxShadow: "0 4px 14px rgba(0,0,0,0.18)",
          }}
        >
          <div style={{ color: "#fff", fontSize: volteada ? 14.5 : 19, fontWeight: volteada ? 500 : 800, lineHeight: 1.5 }}>
            {volteada ? card.atras : card.frente}
          </div>
        </div>
        <div style={{ display: "flex", gap: 12, marginTop: 20, width: "100%" }}>
          <button onClick={() => mover(-1)} style={{ flex: 1, padding: "12px", borderRadius: 6, border: "1px solid #E3DECF", background: "#fff", fontWeight: 700, cursor: "pointer" }}>← Anterior</button>
          <button onClick={() => mover(1)} style={{ flex: 1, padding: "12px", borderRadius: 6, border: "none", background: "#142B4D", color: "#fff", fontWeight: 700, cursor: "pointer" }}>Siguiente →</button>
        </div>
      </div>
    </div>
  );
}

/* ── Ranking de Capacitación (para administradores) ── */
/* ── Cobranza Mensual (solo administradores) ── */
const ESTADOS_PAGO_MES = [
  { id: "pagado",    color: "#22C55E", borderColor: "#16A34A", textColor: "#fff",    label: "Pagado" },
  { id: "pendiente", color: "#F5C518", borderColor: "#C9A013", textColor: "#1A1A1A", label: "Pendiente (día 1-3)" },
  { id: "atrasado",  color: "#EF4444", borderColor: "#DC2626", textColor: "#fff",    label: "Pago a destiempo" },
  { id: "no_pago",   color: "#1A1A1A", borderColor: "#000000", textColor: "#fff",    label: "No pagó" },
  { id: "futuro",    color: "#FFFFFF", borderColor: "#D1D5DB", textColor: "#374151", label: "Aún no llega" },
];
const ESTADOS_PAGO_MES_MAP = Object.fromEntries(ESTADOS_PAGO_MES.map((e) => [e.id, e]));

// Estatus a mostrar: si el admin ya lo definió manualmente (con el cuadro flotante), ese manda siempre.
// Si nunca se ha tocado ese mes, se calcula un estatus sugerido automático (pendiente/atrasado/futuro).
function estatusVisualMes(mesStr, pago) {
  if (pago && pago.estatus) return pago.estatus;
  const hoy = new Date();
  const mesActualStr = `${hoy.getFullYear()}-${String(hoy.getMonth() + 1).padStart(2, "0")}`;
  if (mesStr > mesActualStr) return "futuro";
  if (mesStr < mesActualStr) return "atrasado";
  return hoy.getDate() <= 3 ? "pendiente" : "atrasado";
}

// Comprime una imagen a un tamaño razonable (máx. 800px de ancho, JPEG calidad 0.6) antes de guardarla como texto base64.
function comprimirImagen(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onerror = () => reject(new Error("No se pudo leer la imagen."));
    reader.onload = () => {
      const img = new Image();
      img.onerror = () => reject(new Error("Archivo de imagen inválido."));
      img.onload = () => {
        const maxAncho = 800;
        const escala = img.width > maxAncho ? maxAncho / img.width : 1;
        const canvas = document.createElement("canvas");
        canvas.width = img.width * escala;
        canvas.height = img.height * escala;
        const ctx = canvas.getContext("2d");
        ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
        resolve(canvas.toDataURL("image/jpeg", 0.6));
      };
      img.src = reader.result;
    };
    reader.readAsDataURL(file);
  });
}
function leerArchivoComoTexto(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onerror = () => reject(new Error("No se pudo leer el archivo."));
    reader.onload = () => resolve(reader.result);
    reader.readAsDataURL(file);
  });
}

/* ── Cuadro flotante: elegir estatus del mes + subir/editar comprobante ── */
function ModalPagoMes({ mesStr, pagoActual, onGuardar, onCerrar }) {
  const [estatus, setEstatus] = useState(pagoActual?.estatus || "pendiente");
  const [comprobante, setComprobante] = useState(pagoActual?.comprobante || null);
  const [subiendo, setSubiendo] = useState(false);
  const [errorArchivo, setErrorArchivo] = useState("");
  const [guardando, setGuardando] = useState(false);

  const manejarArchivo = async (e) => {
    const file = e.target.files && e.target.files[0];
    e.target.value = "";
    if (!file) return;
    setErrorArchivo("");
    const esImagen = file.type.startsWith("image/");
    const esPdf = file.type === "application/pdf";
    if (!esImagen && !esPdf) {
      setErrorArchivo("Solo se aceptan imágenes o archivos PDF.");
      return;
    }
    if (esPdf && file.size > 1.5 * 1024 * 1024) {
      setErrorArchivo("El PDF pesa más de 1.5 MB. Usa un archivo más ligero.");
      return;
    }
    setSubiendo(true);
    try {
      const dataUrl = esImagen ? await comprimirImagen(file) : await leerArchivoComoTexto(file);
      setComprobante({ dataUrl, nombre: file.name, tipo: esImagen ? "image" : "pdf" });
    } catch {
      setErrorArchivo("No se pudo procesar el archivo. Intenta con otro.");
    }
    setSubiendo(false);
  };

  const aplicar = async () => {
    setGuardando(true);
    setErrorArchivo("");
    try {
      await onGuardar({
        estatus,
        fechaPago: estatus === "pagado" ? new Date().toISOString() : (pagoActual?.fechaPago || null),
        comprobante: comprobante || null,
      });
    } catch (err) {
      setErrorArchivo(err?.message || "No se pudo guardar. Revisa tu conexión o intenta con un comprobante más ligero.");
      setGuardando(false);
    }
  };

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)", zIndex: 9600, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
      <div style={{ background: "#fff", borderRadius: 12, padding: 24, maxWidth: 420, width: "100%", boxShadow: "0 10px 36px rgba(0,0,0,0.3)", maxHeight: "90vh", overflowY: "auto" }}>
        <div style={{ fontSize: 16, fontWeight: 800, color: "#142B4D", marginBottom: 4 }}>{MES_LABEL(mesStr)}</div>
        <div style={{ fontSize: 12, color: "#6B7280", marginBottom: 16 }}>Elige el estatus de este mes y, si aplica, adjunta el comprobante.</div>

        <div style={{ fontSize: 12, fontWeight: 700, color: "#142B4D", marginBottom: 8 }}>Estatus del mes</div>
        <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 20 }}>
          {ESTADOS_PAGO_MES.map((e) => (
            <button
              key={e.id}
              onClick={() => setEstatus(e.id)}
              style={{
                display: "flex", alignItems: "center", gap: 10, padding: "9px 12px", borderRadius: 8,
                border: estatus === e.id ? "2px solid #142B4D" : "1px solid #E3DECF",
                background: estatus === e.id ? "#EFF6FF" : "#fff", cursor: "pointer", textAlign: "left",
              }}
            >
              <div style={{ width: 22, height: 22, borderRadius: 5, background: e.color, border: `1px solid ${e.borderColor}`, flexShrink: 0 }} />
              <span style={{ fontSize: 13, fontWeight: estatus === e.id ? 700 : 500, color: "#142B4D" }}>{e.label}</span>
              {estatus === e.id && <span style={{ marginLeft: "auto", color: "#16A34A", fontWeight: 800 }}>✓</span>}
            </button>
          ))}
        </div>

        <div style={{ fontSize: 12, fontWeight: 700, color: "#142B4D", marginBottom: 8 }}>📎 Comprobante de Pago</div>
        {comprobante ? (
          <div style={{ border: "1px solid #E3DECF", borderRadius: 8, padding: 10, marginBottom: 10 }}>
            {comprobante.tipo === "image" ? (
              <img src={comprobante.dataUrl} alt="Comprobante de Pago" style={{ maxWidth: "100%", borderRadius: 6, display: "block", marginBottom: 8 }} />
            ) : (
              <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8, fontSize: 12, color: "#374151" }}>
                📄 <a href={comprobante.dataUrl} target="_blank" rel="noopener noreferrer" style={{ color: "#2563EB" }}>{comprobante.nombre}</a>
              </div>
            )}
            <div style={{ display: "flex", gap: 8 }}>
              <label style={{ fontSize: 11.5, padding: "6px 10px", borderRadius: 5, border: "1px solid #E3DECF", background: "#fff", cursor: "pointer" }}>
                Editar comprobante
                <input type="file" accept="image/*,application/pdf" onChange={manejarArchivo} style={{ display: "none" }} />
              </label>
              <button onClick={() => setComprobante(null)} style={{ fontSize: 11.5, padding: "6px 10px", borderRadius: 5, border: "1px solid #EF4444", background: "#fff", color: "#EF4444", cursor: "pointer" }}>
                Quitar
              </button>
            </div>
          </div>
        ) : (
          <label style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 6, border: "2px dashed #E3DECF", borderRadius: 8, padding: "18px 10px", marginBottom: 10, cursor: "pointer", color: "#6B7280" }}>
            <span style={{ fontSize: 22 }}>{subiendo ? "⏳" : "📎"}</span>
            <span style={{ fontSize: 12 }}>{subiendo ? "Procesando…" : "Subir imagen o PDF del comprobante"}</span>
            <input type="file" accept="image/*,application/pdf" onChange={manejarArchivo} disabled={subiendo} style={{ display: "none" }} />
          </label>
        )}
        {errorArchivo && <div style={{ color: "#B91C1C", fontSize: 12, marginBottom: 10 }}>{errorArchivo}</div>}

        <div style={{ display: "flex", gap: 10, marginTop: 16 }}>
          <button onClick={aplicar} disabled={guardando || subiendo} style={{ flex: 1, padding: "12px", border: "none", borderRadius: 8, background: "#F5923E", color: "#fff", fontWeight: 800, fontSize: 14, cursor: "pointer" }}>
            {guardando ? "Aplicando…" : "Aceptar"}
          </button>
          <button onClick={onCerrar} disabled={guardando} style={{ padding: "12px 18px", border: "1px solid #E3DECF", borderRadius: 8, background: "#fff", cursor: "pointer", fontSize: 14 }}>
            Cancelar
          </button>
        </div>
      </div>
    </div>
  );
}

function CobranzaMensual({ onClose }) {
  const [solicitudes, setSolicitudes] = useState(null);
  const [cobranzas, setCobranzas] = useState({}); // { [solicitudId]: { pagos: {...} } }
  const [expandidoAsesor, setExpandidoAsesor] = useState(null);
  const [error, setError] = useState(false);
  const [modal, setModal] = useState(null); // { solId, mes, pagoActual } | null

  useEffect(() => {
    let cancelado = false;
    (async () => {
      try {
        const lista = await loadSolicitudes();
        if (cancelado) return;
        // Solo solicitudes reales y activas — las de Área de Práctica y las de la papelera no generan cobranza.
        const reales = lista.filter((s) => s.esPractica !== true && !s.eliminada);
        setSolicitudes(reales);
        const mapa = await loadCobranzaBulk(reales.map((s) => s.id));
        if (!cancelado) setCobranzas(mapa);
      } catch {
        if (!cancelado) setError(true);
      }
    })();
    return () => { cancelado = true; };
  }, []);

  const guardarPagoMes = async (datosNuevos) => {
    if (!modal) return;
    const { solId, mes } = modal;
    const nuevo = await actualizarCobranza(solId, (actual) => ({
      pagos: { ...actual.pagos, [mes]: datosNuevos },
    }));
    setCobranzas((prev) => ({ ...prev, [solId]: nuevo }));
    setModal(null);
  };

  // Agrupar solicitudes por asesor
  const grupos = {};
  (solicitudes || []).forEach((s) => {
    const nombre = s.asesorNombre || "Sin asesor asignado";
    if (!grupos[nombre]) grupos[nombre] = [];
    grupos[nombre].push(s);
  });
  const nombresAsesores = Object.keys(grupos).sort((a, b) => a.localeCompare(b, "es"));

  return (
    <div>
      <TopBar title="💰 Cobranza Mensual" onLogout={null} right={<button onClick={onClose} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: COLORS.red, color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>} />
      <div style={{ maxWidth: 920, margin: "0 auto", padding: "24px 20px 40px" }}>
        <div style={{ fontSize: 12.5, color: "#6B7280", marginBottom: 16, lineHeight: 1.5 }}>
          Seguimiento de las 12 mensualidades de cada cliente, organizado por asesor — con base en las solicitudes que suben los asesores (no en la Agenda Virtual). La ventana de pago puntual es del día 1 al 3 de cada mes.
          El primer cobro se calcula según la fecha en que se guardó la solicitud: contratado del <strong>día 1 al 21</strong> → primer cobro el <strong>1 del mes siguiente</strong>; contratado del <strong>día 22 al 31</strong> → primer cobro el <strong>1 del mes subsecuente</strong> (se salta un mes).
          Toca cualquier casilla para elegir su estatus y, si aplica, adjuntar el comprobante de pago.
        </div>

        <div style={{ display: "flex", gap: 10, marginBottom: 16, flexWrap: "wrap" }}>
          {ESTADOS_PAGO_MES.map((e) => (
            <div key={e.id} style={{ display: "flex", alignItems: "center", gap: 5, fontSize: 11 }}>
              <div style={{ width: 12, height: 12, borderRadius: 3, background: e.color, border: `1px solid ${e.borderColor}` }} />
              <span style={{ color: "#6B7280" }}>{e.label}</span>
            </div>
          ))}
        </div>

        {error ? (
          <div style={{ color: "#B91C1C", fontSize: 14 }}>No se pudo cargar la cobranza. Intenta de nuevo.</div>
        ) : solicitudes === null ? (
          <div style={{ color: "#6B7280", fontSize: 14 }}>Cargando solicitudes…</div>
        ) : nombresAsesores.length === 0 ? (
          <div style={{ background: "#F8FAFC", borderRadius: 8, padding: 20, textAlign: "center", color: "#6B7280", fontSize: 14, border: "1px dashed #E3DECF" }}>
            Aún no hay solicitudes reales registradas.
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            {nombresAsesores.map((nombreAsesor) => {
              const lista = grupos[nombreAsesor];
              const abierto = expandidoAsesor === nombreAsesor;
              return (
                <div key={nombreAsesor} style={{ background: "#fff", border: "1px solid #E3DECF", borderRadius: 8, overflow: "hidden" }}>
                  <div
                    onClick={() => setExpandidoAsesor(abierto ? null : nombreAsesor)}
                    style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "12px 16px", cursor: "pointer", background: "#142B4D" }}
                  >
                    <div style={{ color: "#fff", fontWeight: 700, fontSize: 14 }}>👤 {nombreAsesor}</div>
                    <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                      <span style={{ color: "rgba(255,255,255,0.75)", fontSize: 12 }}>{lista.length} cliente{lista.length !== 1 ? "s" : ""}</span>
                      <span style={{ color: "#fff", fontSize: 12 }}>{abierto ? "▲" : "▼"}</span>
                    </div>
                  </div>
                  {abierto && (
                    <div style={{ padding: "12px 14px", display: "flex", flexDirection: "column", gap: 10 }}>
                      {lista.map((s) => {
                        const fContrato = new Date(s.fechaHoraCreacion || Date.now());
                        const meses = mesesDeCobranzaSolicitud(fContrato);
                        const cobranza = cobranzas[s.id] || { pagos: {} };
                        const { cuota: mensualidad } = calcMontos(s.montoContratado);
                        return (
                          <div key={s.id} style={{ border: "1px solid #E3DECF", borderRadius: 8, padding: "10px 12px" }}>
                            <div style={{ marginBottom: 8 }}>
                              <div style={{ fontWeight: 700, fontSize: 13.5, color: "#142B4D" }}>{s.nombre || "—"}</div>
                              <div style={{ fontSize: 11, color: "#6B7280" }}>
                                Folio {s.folioContrato || s.folioNumero || "—"} · Contratado el {fmtDate(fContrato)} · Primer cobro: {MES_LABEL(meses[0])} · Mensualidad: <strong>{fmtMoney(mensualidad)}</strong>
                              </div>
                            </div>
                            <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 5 }}>
                              {meses.map((mes, i) => {
                                const pago = cobranza.pagos[mes];
                                const est = estatusVisualMes(mes, pago);
                                const e2 = ESTADOS_PAGO_MES_MAP[est] || ESTADOS_PAGO_MES_MAP.futuro;
                                return (
                                  <button
                                    key={mes}
                                    onClick={() => setModal({ solId: s.id, mes, pagoActual: pago || null })}
                                    title={`${MES_LABEL(mes)} — ${e2.label} — ${fmtMoney(mensualidad)}`}
                                    style={{
                                      position: "relative",
                                      background: e2.color, border: `1px solid ${e2.borderColor}`, borderRadius: 5,
                                      padding: "6px 2px", cursor: "pointer", textAlign: "center",
                                      display: "flex", flexDirection: "column", alignItems: "center", gap: 1,
                                    }}
                                  >
                                    <span style={{ fontSize: 13, fontWeight: 800, color: e2.textColor, lineHeight: 1 }}>{est === "pagado" ? "✓" : i + 1}</span>
                                    <span style={{ fontSize: 8, fontWeight: 700, color: e2.textColor, opacity: 0.9 }}>{MES_LABEL_CORTO(mes)}</span>
                                    <span style={{ fontSize: 9, fontWeight: 800, color: e2.textColor }}>{fmtMoney(mensualidad)}</span>
                                    {pago?.comprobante && (
                                      <span style={{ position: "absolute", top: 1, right: 2, fontSize: 8 }}>📎</span>
                                    )}
                                  </button>
                                );
                              })}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>

      {modal && (
        <ModalPagoMes
          mesStr={modal.mes}
          pagoActual={modal.pagoActual}
          onGuardar={guardarPagoMes}
          onCerrar={() => setModal(null)}
        />
      )}
    </div>
  );
}

/* ── Respaldo Completo: descarga TODOS los datos de negocio en un solo archivo JSON ── */
function RespaldoCompleto({ session, onClose }) {
  const [estado, setEstado] = useState("listo"); // listo | generando | listo_descarga | error
  const [resumen, setResumen] = useState(null);

  // ── Restaurar ──
  const [archivo, setArchivo] = useState(null); // datos ya parseados del .json subido
  const [errorArchivo, setErrorArchivo] = useState("");
  const [modoRestaurar, setModoRestaurar] = useState(null); // "fusionar" | "reemplazar" | null
  const [codigoRestaurar, setCodigoRestaurar] = useState("");
  const [errorRestaurar, setErrorRestaurar] = useState("");
  const [restaurando, setRestaurando] = useState(false);
  const [resumenRestaurar, setResumenRestaurar] = useState(null);

  const leerArchivo = (e) => {
    const file = e.target.files && e.target.files[0];
    e.target.value = "";
    if (!file) return;
    setErrorArchivo(""); setArchivo(null); setResumenRestaurar(null);
    const reader = new FileReader();
    reader.onerror = () => setErrorArchivo("No se pudo leer el archivo.");
    reader.onload = () => {
      try {
        const datos = JSON.parse(reader.result);
        if (!Array.isArray(datos.solicitudes) || !Array.isArray(datos.cotizaciones)) {
          setErrorArchivo("Este archivo no tiene el formato de un respaldo de Autocon Management.");
          return;
        }
        setArchivo(datos);
      } catch {
        setErrorArchivo("El archivo no es un respaldo válido (JSON dañado o incorrecto).");
      }
    };
    reader.readAsText(file);
  };

  // Combina dos listas por "id": conserva lo que ya existe, agrega solo lo que falte del respaldo.
  const fusionarPorId = (actuales, delRespaldo) => {
    const idsActuales = new Set(actuales.map((x) => x.id));
    const nuevos = (delRespaldo || []).filter((x) => x.id && !idsActuales.has(x.id));
    return [...actuales, ...nuevos];
  };

  const ejecutarRestauracion = async () => {
    if (codigoRestaurar.trim() !== (await loadDeleteCode())) {
      setErrorRestaurar("Contraseña de borrado incorrecta.");
      return;
    }
    setRestaurando(true);
    setErrorRestaurar("");
    try {
      if (modoRestaurar === "reemplazar") {
        await saveSolicitudes(archivo.solicitudes || []);
        await saveCotizaciones(archivo.cotizaciones || []);
        await saveCancelaciones(archivo.cancelaciones || []);
      } else {
        const [solActuales, cotActuales, cancActuales] = await Promise.all([loadSolicitudes(), loadCotizaciones(), loadCancelaciones()]);
        await saveSolicitudes(fusionarPorId(solActuales, archivo.solicitudes));
        await saveCotizaciones(fusionarPorId(cotActuales, archivo.cotizaciones));
        await saveCancelaciones(fusionarPorId(cancActuales, archivo.cancelaciones));
      }

      // Cobranza: en ambos modos se fusiona mes por mes (nunca se borra un pago ya registrado hoy).
      const entradasCobranza = Object.entries(archivo.cobranza || {});
      await Promise.all(entradasCobranza.map(async ([solId, datosRespaldo]) => {
        await actualizarCobranza(solId, (actual) => ({
          pagos: modoRestaurar === "reemplazar"
            ? { ...(datosRespaldo.pagos || {}) }
            : { ...(datosRespaldo.pagos || {}), ...(actual.pagos || {}) }, // lo actual siempre gana en fusión
        }));
      }));

      // Agenda: mismo criterio — fusiona por id de cita, o reemplaza completo si se eligió reemplazar.
      const entradasAgenda = Object.entries(archivo.agenda || {});
      await Promise.all(entradasAgenda.map(async ([asesorId, citasRespaldo]) => {
        let citasFinal = citasRespaldo || [];
        if (modoRestaurar === "fusionar") {
          try {
            const citasActuales = await loadCitas(asesorId);
            citasFinal = fusionarPorId(citasActuales, citasRespaldo);
          } catch { citasFinal = citasRespaldo || []; }
        }
        await saveCitas(asesorId, citasFinal);
      }));

      setResumenRestaurar({
        solicitudes: (archivo.solicitudes || []).length,
        cotizaciones: (archivo.cotizaciones || []).length,
        cobranza: entradasCobranza.length,
        agenda: entradasAgenda.length,
        modo: modoRestaurar,
      });
      setModoRestaurar(null);
      setCodigoRestaurar("");
      setArchivo(null);
    } catch {
      setErrorRestaurar("No se pudo restaurar. Intenta de nuevo.");
    }
    setRestaurando(false);
  };

  const generarRespaldo = async () => {
    setEstado("generando");
    try {
      const [solicitudes, cotizaciones, cancelaciones, advisors] = await Promise.all([
        loadSolicitudes(), loadCotizaciones(), loadCancelaciones(), loadAdvisors(),
      ]);

      // Cobranza: una sola consulta para todas las solicitudes reales (no de práctica)
      const solicitudesReales = solicitudes.filter((s) => s.esPractica !== true);
      const cobranzaBulk = await loadCobranzaBulk(solicitudesReales.map((s) => s.id));
      const cobranza = {};
      Object.entries(cobranzaBulk).forEach(([id, c]) => {
        if (c && Object.keys(c.pagos || {}).length > 0) cobranza[id] = c;
      });

      // Agenda: una sola consulta para todos los asesores
      const agendaBulk = await loadCitasBulk(advisors.map((a) => a.id));
      const agenda = {};
      Object.entries(agendaBulk).forEach(([id, citas]) => {
        if (citas.length > 0) agenda[id] = citas;
      });

      const respaldo = {
        generadoEl: new Date().toISOString(),
        generadoPor: session.nombre,
        nota: "Este respaldo no incluye contraseñas ni códigos de acceso, por seguridad.",
        asesores: advisors.map((a) => ({ id: a.id, nombre: a.nombre, activo: a.activo })),
        solicitudes,
        cotizaciones,
        cancelaciones,
        cobranza,
        agenda,
      };

      const json = JSON.stringify(respaldo, null, 2);
      const blob = new Blob([json], { type: "application/json" });
      const url = URL.createObjectURL(blob);
      const fechaArchivo = new Date().toISOString().slice(0, 10);
      const a = document.createElement("a");
      a.href = url;
      a.download = `Respaldo_Autocon_${fechaArchivo}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      setTimeout(() => URL.revokeObjectURL(url), 2000);

      setResumen({
        solicitudes: solicitudes.length,
        cotizaciones: cotizaciones.length,
        cancelaciones: cancelaciones.length,
        cobranza: Object.keys(cobranza).length,
        agenda: Object.keys(agenda).length,
        asesores: advisors.length,
      });
      setEstado("listo_descarga");
    } catch (err) {
      setEstado("error");
    }
  };

  return (
    <div>
      <TopBar title="💾 Respaldo Completo" onLogout={null} right={<button onClick={onClose} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: COLORS.red, color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>} />
      <div style={{ maxWidth: 640, margin: "0 auto", padding: "24px 20px 40px" }}>
        <div style={{ background: "#F8FAFC", border: "1px solid #E3DECF", borderRadius: 10, padding: "18px 20px", marginBottom: 20 }}>
          <div style={{ fontSize: 14, fontWeight: 700, color: "#142B4D", marginBottom: 10 }}>Este respaldo incluye:</div>
          <ul style={{ margin: 0, paddingLeft: 20, fontSize: 13, color: "#374151", lineHeight: 1.9 }}>
            <li>Todas las <strong>Solicitudes</strong> (reales y de práctica, activas y en papelera)</li>
            <li>Todas las <strong>Cotizaciones</strong></li>
            <li>Historial de <strong>Cancelaciones</strong></li>
            <li><strong>Cobranza</strong> (pagos y comprobantes) de cada cliente</li>
            <li><strong>Agenda</strong> de cada asesor (citas y bitácora)</li>
            <li>Lista de asesores (nombre y estatus, <strong>sin</strong> sus códigos de acceso)</li>
          </ul>
          <div style={{ fontSize: 12, color: "#92400E", background: "#FFFBEB", border: "1px solid #F5C518", borderRadius: 6, padding: "8px 10px", marginTop: 14 }}>
            🔒 Por seguridad, este archivo <strong>no incluye contraseñas ni códigos de acceso</strong> de nadie.
          </div>
        </div>

        {estado === "error" && (
          <div style={{ color: "#B91C1C", fontSize: 13, marginBottom: 14 }}>No se pudo generar el respaldo. Revisa tu conexión e intenta de nuevo.</div>
        )}

        {estado === "listo_descarga" && resumen && (
          <div style={{ background: "#F0FDF4", border: "1px solid #86EFAC", borderRadius: 8, padding: "14px 16px", marginBottom: 16, fontSize: 13, color: "#15803D" }}>
            ✓ Respaldo descargado correctamente: {resumen.solicitudes} solicitudes, {resumen.cotizaciones} cotizaciones, {resumen.cancelaciones} cancelaciones, cobranza de {resumen.cobranza} cliente(s), agenda de {resumen.agenda} asesor(es).
          </div>
        )}

        <button
          onClick={generarRespaldo}
          disabled={estado === "generando"}
          style={{ width: "100%", padding: "14px", border: "none", borderRadius: 8, background: estado === "generando" ? "#9CA3AF" : "#142B4D", color: "#fff", fontWeight: 800, fontSize: 15, cursor: estado === "generando" ? "not-allowed" : "pointer" }}
        >
          {estado === "generando" ? "Generando respaldo…" : "💾 Descargar Respaldo Completo"}
        </button>

        {/* ── Restaurar desde archivo ── */}
        <div style={{ marginTop: 36, paddingTop: 24, borderTop: "2px dashed #E3DECF" }}>
          <div style={{ fontSize: 16, fontWeight: 800, color: "#142B4D", marginBottom: 6 }}>📤 Restaurar desde un archivo de respaldo</div>
          <div style={{ fontSize: 12.5, color: "#6B7280", marginBottom: 16 }}>
            Sube un archivo <strong>.json</strong> generado con "Descargar Respaldo Completo" (de esta plataforma o de otra) para recuperar su información.
          </div>

          {resumenRestaurar && (
            <div style={{ background: "#F0FDF4", border: "1px solid #86EFAC", borderRadius: 8, padding: "14px 16px", marginBottom: 16, fontSize: 13, color: "#15803D" }}>
              ✓ Restauración completada ({resumenRestaurar.modo === "reemplazar" ? "se reemplazó todo" : "se fusionó con lo existente"}): {resumenRestaurar.solicitudes} solicitudes y {resumenRestaurar.cotizaciones} cotizaciones del archivo, cobranza de {resumenRestaurar.cobranza} cliente(s), agenda de {resumenRestaurar.agenda} asesor(es). Sal y vuelve a entrar para ver los datos actualizados.
            </div>
          )}

          {!archivo ? (
            <label style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 6, border: "2px dashed #E3DECF", borderRadius: 8, padding: "22px 10px", cursor: "pointer", color: "#6B7280" }}>
              <span style={{ fontSize: 24 }}>📁</span>
              <span style={{ fontSize: 13 }}>Toca para elegir el archivo de respaldo (.json)</span>
              <input type="file" accept="application/json" onChange={leerArchivo} style={{ display: "none" }} />
            </label>
          ) : (
            <div style={{ border: "1px solid #E3DECF", borderRadius: 8, padding: "14px 16px" }}>
              <div style={{ fontSize: 13, fontWeight: 700, color: "#142B4D", marginBottom: 4 }}>Archivo cargado — vista previa</div>
              <div style={{ fontSize: 12.5, color: "#6B7280", marginBottom: 10 }}>
                Generado el {archivo.generadoEl ? fmtDateTime(new Date(archivo.generadoEl)) : "—"} por {archivo.generadoPor || "—"}
              </div>
              <div style={{ fontSize: 12.5, color: "#374151", marginBottom: 14, lineHeight: 1.8 }}>
                Contiene: <strong>{(archivo.solicitudes || []).length}</strong> solicitudes · <strong>{(archivo.cotizaciones || []).length}</strong> cotizaciones · <strong>{(archivo.cancelaciones || []).length}</strong> cancelaciones · cobranza de <strong>{Object.keys(archivo.cobranza || {}).length}</strong> cliente(s) · agenda de <strong>{Object.keys(archivo.agenda || {}).length}</strong> asesor(es)
              </div>
              <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                <button onClick={() => setModoRestaurar("fusionar")} style={{ padding: "9px 14px", border: "none", borderRadius: 6, background: "#16A34A", color: "#fff", fontWeight: 700, fontSize: 12.5, cursor: "pointer" }}>
                  🔗 Fusionar (recomendado)
                </button>
                <button onClick={() => setModoRestaurar("reemplazar")} style={{ padding: "9px 14px", border: "1px solid #EF4444", borderRadius: 6, background: "#fff", color: "#EF4444", fontWeight: 700, fontSize: 12.5, cursor: "pointer" }}>
                  ⚠️ Reemplazar todo
                </button>
                <button onClick={() => { setArchivo(null); setErrorArchivo(""); }} style={{ padding: "9px 14px", border: "1px solid #E3DECF", borderRadius: 6, background: "#fff", color: "#6B7280", fontSize: 12.5, cursor: "pointer" }}>
                  Cancelar
                </button>
              </div>
            </div>
          )}
          {errorArchivo && <div style={{ color: "#B91C1C", fontSize: 12.5, marginTop: 10 }}>{errorArchivo}</div>}
        </div>
      </div>

      {modoRestaurar && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)", zIndex: 9700, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
          <div style={{ background: "#fff", borderRadius: 10, padding: 26, maxWidth: 440, width: "100%", boxShadow: "0 8px 32px rgba(0,0,0,0.25)" }}>
            <div style={{ fontSize: 17, fontWeight: 700, color: modoRestaurar === "reemplazar" ? "#B91C1C" : "#142B4D", marginBottom: 8 }}>
              {modoRestaurar === "reemplazar" ? "⚠️ Reemplazar TODA la información actual" : "🔗 Fusionar con la información actual"}
            </div>
            <div style={{ fontSize: 13, color: "#374151", marginBottom: 16, lineHeight: 1.6 }}>
              {modoRestaurar === "reemplazar" ? (
                <>Esto <strong>borra las solicitudes y cotizaciones actuales</strong> y las sustituye por completo con las del archivo. La cobranza y la agenda se fusionan sin perder pagos ya registrados hoy. Esta acción no se puede deshacer.</>
              ) : (
                <>Se agregará al sistema lo que traiga el archivo <strong>y que aún no exista</strong> — nada de lo que ya tienes hoy se borra ni se sobrescribe.</>
              )}
            </div>
            <input
              type="password"
              value={codigoRestaurar}
              onChange={(e) => { setCodigoRestaurar(e.target.value); setErrorRestaurar(""); }}
              placeholder="Contraseña de borrado"
              style={{ width: "100%", padding: "10px 12px", border: "1.5px solid #E3DECF", borderRadius: 6, fontSize: 14 }}
            />
            {errorRestaurar && <div style={{ color: "#B91C1C", fontSize: 13, marginTop: 8 }}>{errorRestaurar}</div>}
            <div style={{ display: "flex", gap: 10, marginTop: 16 }}>
              <button onClick={ejecutarRestauracion} disabled={restaurando} style={{ padding: "10px 20px", border: "none", borderRadius: 6, background: modoRestaurar === "reemplazar" ? "#EF4444" : "#16A34A", color: "#fff", fontWeight: 700, fontSize: 14, cursor: "pointer" }}>
                {restaurando ? "Restaurando…" : "Sí, continuar"}
              </button>
              <button onClick={() => { setModoRestaurar(null); setCodigoRestaurar(""); setErrorRestaurar(""); }} disabled={restaurando} style={{ padding: "10px 20px", border: "1px solid #E3DECF", borderRadius: 6, background: "#fff", cursor: "pointer", fontSize: 14 }}>
                Cancelar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function RankingCapacitacion({ advisors, onClose }) {
  const [datos, setDatos] = useState(null);
  const [error, setError] = useState(false);

  useEffect(() => {
    let cancelado = false;
    (async () => {
      try {
        const activos = advisors.filter((a) => a.activo);
        const resultados = await loadProgresoDeTodos(activos);
        if (cancelado) return;
        const conPct = resultados.map((r) => ({
          ...r,
          completados: Object.keys(r.progreso.completados).length,
          pct: Math.round((Object.keys(r.progreso.completados).length / TEMAS_HOJA.length) * 100),
          insignias: insigniasGanadas(r.progreso).length,
        })).sort((a, b) => b.pct - a.pct);
        setDatos(conPct);
      } catch {
        if (!cancelado) setError(true);
      }
    })();
    return () => { cancelado = true; };
  }, [advisors]);

  return (
    <div>
      <TopBar title="🏆 Ranking de Capacitación" onLogout={null} right={<button onClick={onClose} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: COLORS.red, color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>} />
      <div style={{ maxWidth: 700, margin: "0 auto", padding: "24px 20px 40px" }}>
        {error ? (
          <div style={{ color: "#B91C1C", fontSize: 14 }}>No se pudo cargar el ranking. Intenta de nuevo.</div>
        ) : !datos ? (
          <div style={{ color: "#6B7280", fontSize: 14 }}>Cargando progreso de todos los asesores…</div>
        ) : datos.length === 0 ? (
          <div style={{ color: "#6B7280", fontSize: 14 }}>No hay asesores activos todavía.</div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {datos.map((d, i) => (
              <div key={d.asesorId} style={{ display: "flex", alignItems: "center", gap: 12, background: "#fff", border: "1px solid #E3DECF", borderRadius: 8, padding: "12px 14px" }}>
                <div style={{ width: 28, height: 28, borderRadius: "50%", background: i === 0 ? "#F5C518" : i === 1 ? "#CBD5E1" : i === 2 ? "#D97706" : "#E3DECF", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 800, fontSize: 13, color: "#142B4D", flexShrink: 0 }}>
                  {i + 1}
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 700, fontSize: 14, color: "#142B4D" }}>{d.nombre}</div>
                  <div style={{ height: 6, background: "#E3DECF", borderRadius: 4, marginTop: 4, overflow: "hidden" }}>
                    <div style={{ height: "100%", width: `${d.pct}%`, background: "#16A34A" }} />
                  </div>
                </div>
                <div style={{ textAlign: "right", flexShrink: 0 }}>
                  <div style={{ fontWeight: 800, fontSize: 14, color: "#142B4D" }}>{d.pct}%</div>
                  <div style={{ fontSize: 11, color: "#6B7280" }}>{d.completados}/{TEMAS_HOJA.length} · {d.insignias} 🏅</div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

/* ── Calculadora del Juego de Números (widget interactivo embebido en "Juego y Presentación de Números") ── */
function CalculadoraNumeros() {
  const [precio, setPrecio] = useState(500000);
  const [plazo, setPlazo] = useState(48);
  const [ancla, setAncla] = useState(650000);

  const mensualidad = plazo > 0 ? Math.round(precio / plazo) : 0;
  const porDia = mensualidad > 0 ? Math.round(mensualidad / 30) : 0;

  return (
    <div style={{ margin: "18px 0", border: "2px solid #E3DECF", borderRadius: 10, padding: 16, background: "#FAFAF7" }}>
      <div style={{ fontWeight: 800, fontSize: 15, color: "#142B4D", marginBottom: 10 }}>🧮 Practica el encuadre de números</div>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 14 }}>
        <label style={{ fontSize: 12, color: "#6B7280" }}>
          Precio del vehículo
          <CampoMoneda value={precio} onChange={(e) => setPrecio(Number(e.target.value) || 0)}
            style={{ display: "block", width: "100%", marginTop: 4, padding: "8px 10px", borderRadius: 6, border: "1px solid #E3DECF", fontSize: 13 }} />
        </label>
        <label style={{ fontSize: 12, color: "#6B7280" }}>
          Plazo (meses)
          <input type="number" value={plazo} onChange={(e) => setPlazo(Number(e.target.value) || 1)}
            style={{ display: "block", width: "100%", marginTop: 4, padding: "8px 10px", borderRadius: 6, border: "1px solid #E3DECF", fontSize: 13 }} />
        </label>
        <label style={{ fontSize: 12, color: "#6B7280", gridColumn: "1 / -1" }}>
          Precio "ancla" a mostrar primero (opción premium)
          <CampoMoneda value={ancla} onChange={(e) => setAncla(Number(e.target.value) || 0)}
            style={{ display: "block", width: "100%", marginTop: 4, padding: "8px 10px", borderRadius: 6, border: "1px solid #E3DECF", fontSize: 13 }} />
        </label>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
        <div style={{ background: "#FEF2F2", border: "1px solid #FCA5A5", borderRadius: 8, padding: 12 }}>
          <div style={{ fontSize: 11, color: "#991B1B", fontWeight: 700, marginBottom: 4 }}>❌ SIN ANCLA (empiezas por el precio)</div>
          <div style={{ fontSize: 13.5, color: "#374151" }}>"Son ${mensualidad.toLocaleString("es-MX")} al mes."</div>
          <div style={{ fontSize: 11.5, color: "#6B7280", marginTop: 4 }}>El cerebro se enfoca de inmediato en el gasto.</div>
        </div>
        <div style={{ background: "#F0FDF4", border: "1px solid #86EFAC", borderRadius: 8, padding: 12 }}>
          <div style={{ fontSize: 11, color: "#15803D", fontWeight: 700, marginBottom: 4 }}>✅ CON ANCLA + POR DÍA</div>
          <div style={{ fontSize: 13.5, color: "#374151" }}>
            "Este modelo equipado cuesta ${ancla.toLocaleString("es-MX")}. También existe esta alternativa por ${precio.toLocaleString("es-MX")}, que representa aproximadamente ${porDia.toLocaleString("es-MX")} al día."
          </div>
          <div style={{ fontSize: 11.5, color: "#6B7280", marginTop: 4 }}>La opción real se percibe accesible por contraste, y el gasto diario se siente pequeño.</div>
        </div>
      </div>
    </div>
  );
}

function EntrenamientoVentas({ session, onClose }) {
  const [seccion, setSeccion] = useState(null);
  const [temaSel, setTemaSel] = useState(null);
  const [sisSel, setSisSel] = useState(null);
  const [videoSel, setVideoSel] = useState(null);
  const [vistaExtra, setVistaExtra] = useState(null); // null | "simulador" | "flashcards"
  const [progreso, setProgreso] = useState(PROGRESO_VACIO);
  const [cargandoProgreso, setCargandoProgreso] = useState(true);

  useEffect(() => {
    let cancelado = false;
    (async () => {
      const p = await loadProgresoEntrenamiento(session.id);
      if (!cancelado) { setProgreso(p); setCargandoProgreso(false); }
    })();
    return () => { cancelado = true; };
  }, [session.id]);

  // Siempre lee el progreso más fresco antes de escribir, para no pisar avances de otra sesión/pestaña.
  const marcarCompletado = async (key, resultadoQuiz) => {
    const nuevo = await actualizarProgresoEntrenamiento(session.id, (actual) => {
      const completados = { ...actual.completados, [key]: true };
      const quizScores = { ...actual.quizScores };
      if (resultadoQuiz) {
        const anterior = quizScores[key];
        if (!anterior || resultadoQuiz.correctas > anterior.correctas) quizScores[key] = resultadoQuiz;
      }
      return { ...actual, completados, quizScores };
    });
    setProgreso(nuevo);
  };

  if (vistaExtra === "simulador") return <SimuladorObjeciones onClose={() => setVistaExtra(null)} />;
  if (vistaExtra === "flashcards") return <FlashcardsCierres onClose={() => setVistaExtra(null)} />;

  return (
    <div>
      <TopBar title="📚 Entrenamiento de Ventas" onLogout={null} right={<button onClick={onClose} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: COLORS.red, color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>} />

      <div style={{ maxWidth: 700, margin: "0 auto", padding: "24px 20px 40px" }}>
        {!seccion ? (
          <div>
            {!cargandoProgreso && (
              <div style={{ marginBottom: 18 }}>
                <BarraProgreso completados={Object.keys(progreso.completados).length} total={TEMAS_HOJA.length} />
                <InsigniasStrip progreso={progreso} />
              </div>
            )}
            <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
              <button onClick={() => setSeccion("autofinanciamiento")} style={{ background: "#EFF6FF", border: "2px solid #2563EB", borderRadius: 10, padding: "18px 20px", textAlign: "left", cursor: "pointer", width: "100%" }}>
                <div style={{ fontWeight: 700, fontSize: 16, color: "#1E40AF" }}>💡 ¿Cómo funciona el autofinanciamiento?</div>
                <div style={{ fontSize: 13, color: "#6B7280", marginTop: 4 }}>Aprende los fundamentos del sistema de autofinanciamiento.</div>
              </button>
              <button onClick={() => setSeccion("vendedor")} style={{ background: "#F0FDF4", border: "2px solid #16A34A", borderRadius: 10, padding: "18px 20px", textAlign: "left", cursor: "pointer", width: "100%" }}>
                <div style={{ fontWeight: 700, fontSize: 16, color: "#15803D" }}>🏆 ¿Cómo ser un mejor vendedor?</div>
                <div style={{ fontSize: 13, color: "#6B7280", marginTop: 4 }}>Técnicas y estrategias para mejorar tu desempeño en ventas.</div>
              </button>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                <button onClick={() => setVistaExtra("simulador")} style={{ background: "#FEF2F2", border: "2px solid #EF4444", borderRadius: 10, padding: "16px", textAlign: "left", cursor: "pointer" }}>
                  <div style={{ fontWeight: 700, fontSize: 14, color: "#B91C1C" }}>🎯 Simulador de Objeciones</div>
                  <div style={{ fontSize: 12, color: "#6B7280", marginTop: 4 }}>Practica respuestas en vivo.</div>
                </button>
                <button onClick={() => setVistaExtra("flashcards")} style={{ background: "#FFFBEB", border: "2px solid #F5C518", borderRadius: 10, padding: "16px", textAlign: "left", cursor: "pointer" }}>
                  <div style={{ fontWeight: 700, fontSize: 14, color: "#92400E" }}>🗂️ Flashcards de Cierres</div>
                  <div style={{ fontSize: 12, color: "#6B7280", marginTop: 4 }}>Memoriza los 11 cierres.</div>
                </button>
              </div>
            </div>
          </div>
        ) : seccion === "autofinanciamiento" ? (
          <div>
            <button onClick={() => setSeccion(null)} style={{ marginBottom: 16, padding: "8px 16px", border: "1px solid #E3DECF", borderRadius: 4, background: "#fff", cursor: "pointer", fontSize: 13 }}>← Volver</button>
            <div style={{ fontSize: 17, fontWeight: 700, color: "#142B4D", marginBottom: 12 }}>
              💡 ¿Cómo funciona el autofinanciamiento?
            </div>
            <div style={{ background: "#F8FAFC", borderRadius: 8, padding: 20, textAlign: "center", color: "#6B7280", fontSize: 14, border: "1px dashed #E3DECF" }}>
              <div style={{ fontSize: 32, marginBottom: 10 }}>🚧</div>
              <div style={{ fontWeight: 600, marginBottom: 6 }}>Contenido en preparación</div>
              <div>Videos, materiales y guías estarán disponibles aquí una vez que el sistema esté migrado a Firebase.</div>
            </div>
          </div>
        ) : temaSel === null ? (
          <div>
            <button onClick={() => setSeccion(null)} style={{ marginBottom: 16, padding: "8px 16px", border: "1px solid #E3DECF", borderRadius: 4, background: "#fff", cursor: "pointer", fontSize: 13 }}>← Volver</button>
            <div style={{ fontSize: 18, fontWeight: 800, color: "#142B4D", marginBottom: 20, lineHeight: 1.3 }}>
              ¿Quieres ser un mejor vendedor e incrementar tus ingresos de un 30 a 60%?
            </div>
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {TEMAS_VENDEDOR.map((tema, i) => {
                const esHoja = !tema.sistemas && !tema.videos;
                const completo = esHoja && !!progreso.completados[tema.key];
                return (
                  <div key={tema.id} style={{ position: "relative" }}>
                    <BotonDegradado
                      numero={tema.id}
                      titulo={tema.titulo + (completo ? " ✓" : "")}
                      total={TEMAS_VENDEDOR.length}
                      index={i}
                      onClick={() => { setTemaSel(i); setSisSel(null); setVideoSel(null); }}
                    />
                  </div>
                );
              })}
            </div>
          </div>
        ) : TEMAS_VENDEDOR[temaSel].sistemas ? (
          // Macro-sección "Sistemas de Venta del Mercado" / "Cierres Maestros": intro + sub-botones, o el contenido elegido
          sisSel === null ? (
            <div>
              <button onClick={() => setTemaSel(null)} style={{ marginBottom: 16, padding: "8px 16px", border: "1px solid #E3DECF", borderRadius: 4, background: "#fff", cursor: "pointer", fontSize: 13 }}>← Volver al listado</button>
              <div style={{ fontSize: 17, fontWeight: 700, color: "#142B4D", marginBottom: 16 }}>
                {TEMAS_VENDEDOR[temaSel].id}. {TEMAS_VENDEDOR[temaSel].titulo}
              </div>
              <div style={{ marginBottom: 18 }}>{renderContenido(TRAINING_CONTENT[TEMAS_VENDEDOR[temaSel].key])}</div>
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {TEMAS_VENDEDOR[temaSel].sistemas.map((sis, i) => {
                  const completo = !!progreso.completados[sis.key];
                  return (
                    <BotonDegradado
                      key={sis.id}
                      numero={sis.id}
                      titulo={sis.titulo + (completo ? " ✓" : "")}
                      total={TEMAS_VENDEDOR[temaSel].sistemas.length}
                      index={i}
                      onClick={() => setSisSel(i)}
                    />
                  );
                })}
              </div>
            </div>
          ) : (
            <div>
              <button onClick={() => setSisSel(null)} style={{ marginBottom: 16, padding: "8px 16px", border: "1px solid #E3DECF", borderRadius: 4, background: "#fff", cursor: "pointer", fontSize: 13 }}>← Volver al listado</button>
              <div style={{ fontSize: 17, fontWeight: 700, color: "#142B4D", marginBottom: 12 }}>
                {TEMAS_VENDEDOR[temaSel].sistemas[sisSel].id}. {TEMAS_VENDEDOR[temaSel].sistemas[sisSel].titulo}
              </div>
              <VisorTemaConQuiz
                key={TEMAS_VENDEDOR[temaSel].sistemas[sisSel].key}
                tKey={TEMAS_VENDEDOR[temaSel].sistemas[sisSel].key}
                progreso={progreso}
                onCompletar={marcarCompletado}
              />
            </div>
          )
        ) : TEMAS_VENDEDOR[temaSel].videos ? (
          // Macro-sección "Biblioteca de Videos": lista de videos (embebidos de YouTube) o el video elegido
          videoSel === null ? (
            <div>
              <button onClick={() => setTemaSel(null)} style={{ marginBottom: 16, padding: "8px 16px", border: "1px solid #E3DECF", borderRadius: 4, background: "#fff", cursor: "pointer", fontSize: 13 }}>← Volver al listado</button>
              <div style={{ fontSize: 17, fontWeight: 700, color: "#142B4D", marginBottom: 16 }}>
                {TEMAS_VENDEDOR[temaSel].id}. {TEMAS_VENDEDOR[temaSel].titulo}
              </div>
              {TEMAS_VENDEDOR[temaSel].videos.length === 0 ? (
                <div style={{ background: "#F8FAFC", borderRadius: 8, padding: 20, textAlign: "center", color: "#6B7280", fontSize: 14, border: "1px dashed #E3DECF" }}>
                  <div style={{ fontSize: 32, marginBottom: 10 }}>🎬</div>
                  <div style={{ fontWeight: 600, marginBottom: 6 }}>Aún no hay videos cargados</div>
                  <div>Pronto estarán disponibles aquí.</div>
                </div>
              ) : (
                <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                  {TEMAS_VENDEDOR[temaSel].videos.map((video, i) => (
                    <BotonDegradado
                      key={video.id}
                      numero={video.id}
                      titulo={video.titulo}
                      total={TEMAS_VENDEDOR[temaSel].videos.length}
                      index={i}
                      onClick={() => setVideoSel(i)}
                    />
                  ))}
                </div>
              )}
            </div>
          ) : (
            <div>
              <button onClick={() => setVideoSel(null)} style={{ marginBottom: 16, padding: "8px 16px", border: "1px solid #E3DECF", borderRadius: 4, background: "#fff", cursor: "pointer", fontSize: 13 }}>← Volver a Videos</button>
              <div style={{ fontSize: 17, fontWeight: 700, color: "#142B4D", marginBottom: 12 }}>
                {TEMAS_VENDEDOR[temaSel].videos[videoSel].id}. {TEMAS_VENDEDOR[temaSel].videos[videoSel].titulo}
              </div>
              <div style={{ position: "relative", width: "100%", paddingTop: "56.25%", borderRadius: 8, overflow: "hidden", background: "#000" }}>
                <iframe
                  src={`https://www.youtube.com/embed/${TEMAS_VENDEDOR[temaSel].videos[videoSel].youtubeId}`}
                  title={TEMAS_VENDEDOR[temaSel].videos[videoSel].titulo}
                  style={{ position: "absolute", inset: 0, width: "100%", height: "100%", border: "none" }}
                  allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
                  allowFullScreen
                />
              </div>
            </div>
          )
        ) : (
          <div>
            <button onClick={() => setTemaSel(null)} style={{ marginBottom: 16, padding: "8px 16px", border: "1px solid #E3DECF", borderRadius: 4, background: "#fff", cursor: "pointer", fontSize: 13 }}>← Volver al listado</button>
            <div style={{ fontSize: 17, fontWeight: 700, color: "#142B4D", marginBottom: 12 }}>
              {TEMAS_VENDEDOR[temaSel].id}. {TEMAS_VENDEDOR[temaSel].titulo}
            </div>
            <VisorTemaConQuiz
              key={TEMAS_VENDEDOR[temaSel].key}
              tKey={TEMAS_VENDEDOR[temaSel].key}
              progreso={progreso}
              onCompletar={marcarCompletado}
            />
          </div>
        )}
      </div>
    </div>
  );
}

// Muestra el contenido de un tema hoja + (si aplica) la calculadora de números + el quiz. Marca "visto" al abrir.
function VisorTemaConQuiz({ tKey, progreso, onCompletar }) {
  const yaCompletado = !!progreso.completados[tKey];
  const mejorPuntaje = progreso.quizScores[tKey] || null;

  useEffect(() => {
    if (!yaCompletado) onCompletar(tKey, null);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [tKey]);

  return (
    <div>
      {renderContenido(TRAINING_CONTENT[tKey])}
      {tKey === "juego" && <CalculadoraNumeros />}
      <QuizTema quizKey={tKey} mejorPuntaje={mejorPuntaje} onFinish={(correctas, total) => onCompletar(tKey, { correctas, total })} />
    </div>
  );
}


/* ── Agenda Virtual ── */
// Columna de día para Actividad de la Semana
// (se define aquí para acceder a citas, hoy, ESTADOS_CITA desde el closure de AgendaVirtual)
// Se usa como función interna pasada como prop — ver uso dentro de AgendaVirtual

// Paleta de estados para citas de agenda
const ESTADOS_CITA = [
  { id: "prospecto",       label: "Prospecto / Citado",  color: "#22C55E", text: "#fff" },
  { id: "confirmo",        label: "Confirmó Cita",        color: "#F5C518", text: "#142B4D" },
  { id: "contrato",        label: "Cliente contrató",     color: "#EF4444", text: "#fff" },
  { id: "cancelo",         label: "Canceló Cita",         color: "#1A1A1A", text: "#fff" },
  { id: "reagendo",        label: "Reagendó",             color: "#3B82F6", text: "#fff" },
  { id: "problematico",    label: "Problemático",         color: "#1F2937", text: "#fff" },
  { id: "cancelocontrato", label: "Canceló Contrato",     color: "#9CA3AF", text: "#fff" },
  { id: "llamada",         label: "Llamada",              color: "#EC4899", text: "#fff" },
  { id: "seguimiento",     label: "Seguimiento / Autorización", color: "#6B1E3C", color2: "#A3C400", text: "#fff" },
];

// Devuelve el relleno visual de un estado: bicolor (guinda/verde limón) si el estado
// define color2 (ej. "Seguimiento / Autorización"), o su color sólido normal.
// Se usa SOLO para fondos (background); bordes y texto siguen usando estado.color sólido,
// ya que un degradado no es un valor válido de color de borde o de texto en CSS.
function estadoBG(e) {
  return e && e.color2 ? `linear-gradient(90deg, ${e.color} 50%, ${e.color2} 50%)` : (e ? e.color : "#999");
}

function BadgeColor({ estado, count }) {
  return (
    <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:3 }}>
      <div style={{ width:12, height:12, borderRadius:"50%", background:estadoBG(estado), flexShrink:0 }} />
      <span style={{ fontSize:12, color:"#142B4D" }}><strong>{count}</strong> {estado.label}</span>
    </div>
  );
}

function AgendaVirtual({ session, onClose }) {
  const storageKey = `agenda-${session.id}`;
  const recordatorioKey = `agenda-recordatorio-${session.id}`;
  const statsKey = `agenda-stats-${session.id}`; // ledger permanente de estadísticas (nunca se borra)
  const [citas, setCitas] = useState([]);
  const [historicoEstados, setHistoricoEstados] = useState([]); // [{ estadoId, fecha }] — histórico acumulado
  const [loading, setLoading] = useState(true);
  const [diaSeleccionado, setDiaSeleccionado] = useState(null);
  const [showForm, setShowForm] = useState(false);
  const [nueva, setNueva] = useState({ cliente: "", hora: "", notas: "", estadoId: "prospecto" });
  const [guardando, setGuardando] = useState(false);
  const [errorFranja, setErrorFranja] = useState("");
  const [citaDetalle, setCitaDetalle] = useState(null);
  const [notifEstado, setNotifEstado] = useState("cargando"); // "cargando" | "activado" | "inactivo" | "no-soportado"

  useEffect(() => {
    notificacionesActivas().then((activo) => setNotifEstado(activo ? "activado" : "inactivo"));
  }, []);
  const handleActivarNotif = async () => {
    setNotifEstado("cargando");
    try {
      const resultado = await activarNotificaciones(session.id);
      setNotifEstado(resultado === "activado" ? "activado" : resultado === "denegado" ? "inactivo" : "no-soportado");
      if (resultado === "denegado") alert("El celular bloqueó el permiso de notificaciones. Actívalo desde la configuración del navegador para recibir recordatorios.");
      if (resultado === "no-soportado") alert("Este dispositivo no soporta notificaciones (en iPhone, asegúrate de haber instalado la plataforma como app desde Safari).");
    } catch {
      setNotifEstado("inactivo");
      alert("No se pudo activar. Intenta de nuevo.");
    }
  };
  const [nuevaNotaBitacora, setNuevaNotaBitacora] = useState("");
  const [guardandoBitacora, setGuardandoBitacora] = useState(false);
  const agregarNotaBitacora = async () => {
    const texto = nuevaNotaBitacora.trim();
    if (!texto || !citaDetalle) return;
    setGuardandoBitacora(true);
    try {
      const entrada = { fecha: new Date().toISOString(), texto };
      // Lee las citas más recientes de Supabase antes de escribir, para no pisar cambios hechos en otra pestaña/sesión.
      const citasFrescas = await loadCitas(session.id);
      const actualizadas = citasFrescas.map((c) => (c.id === citaDetalle.id ? { ...c, bitacora: [...(c.bitacora || []), entrada] } : c));
      await guardarCitas(actualizadas);
      setCitaDetalle({ ...citaDetalle, bitacora: [...(citaDetalle.bitacora || []), entrada] });
      setNuevaNotaBitacora("");
    } catch (e) {
      console.warn("Error al guardar nota de bitácora:", e);
      mostrarToast("Error al guardar la nota. Intenta de nuevo.");
    }
    setGuardandoBitacora(false);
  };
  const [modoEdicion, setModoEdicion] = useState(false);
  const [editData, setEditData] = useState({ estadoId: "prospecto", notas: "", cliente: "" });
  const [busquedaDia, setBusquedaDia] = useState("");
  const [filtroColor, setFiltroColor] = useState("");
  const [moviendoCita, setMoviendoCita] = useState(null);
  const [moverData, setMoverData] = useState({ fecha: "", hora: "" });
  const [moverConfirm, setMoverConfirm] = useState(false);
  const [toastMsg, setToastMsg] = useState("");
  const [alarmaProxima, setAlarmaProxima] = useState(null);

  const mostrarToast = (msg) => {
    setToastMsg(msg);
    setTimeout(() => setToastMsg(""), 2500);
  };
  const [mesConversionIdx, setMesConversionIdx] = useState(null);
  const [busquedaAnual, setBusquedaAnual] = useState("");
  const [resultadoBusqueda, setResultadoBusqueda] = useState(null);
  // vistaAgenda: null=menú 6 cuadros | "registro" | "pendientes-hoy" | "pendientes-semana" | "estadisticas" | "calendario" | "clientes-contratados"
  const [vistaAgenda, setVistaAgenda] = useState(null);
  const [mostrarCalendarioRegistro, setMostrarCalendarioRegistro] = useState(false);

  // ── Reloj interno: fuerza un recálculo cada 30s de los contadores que dependen de
  // la hora actual (PENDIENTES DE HOY, PENDIENTES SEMANAL, etc.), para que no se
  // queden con un número "congelado" mientras la pantalla permanece abierta sin
  // que ocurra otro cambio de estado. No afecta ningún otro dato ni vista. ──
  const [, relojTick] = useState(0);
  useEffect(() => {
    const iv = setInterval(() => relojTick((t) => t + 1), 30000);
    return () => clearInterval(iv);
  }, []);

  // ── Zoom con dos dedos SOLO para el calendario "Elige un día" (selector de fecha
  // al registrar un pendiente). No afecta ninguna otra vista ni ningún otro calendario. ──
  const [calendarZoom, setCalendarZoom] = useState(1);
  const pinchRef = React.useRef({ startDist: 0, startZoom: 1 });
  const distanciaDedos = (touches) => {
    const dx = touches[0].clientX - touches[1].clientX;
    const dy = touches[0].clientY - touches[1].clientY;
    return Math.sqrt(dx * dx + dy * dy);
  };
  const onCalendarTouchStart = (e) => {
    if (e.touches.length === 2) {
      pinchRef.current.startDist = distanciaDedos(e.touches);
      pinchRef.current.startZoom = calendarZoom;
    }
  };
  const onCalendarTouchMove = (e) => {
    if (e.touches.length === 2) {
      e.preventDefault();
      const dist = distanciaDedos(e.touches);
      if (pinchRef.current.startDist > 0) {
        const ratio = dist / pinchRef.current.startDist;
        const nuevoZoom = Math.min(2.5, Math.max(1, pinchRef.current.startZoom * ratio));
        setCalendarZoom(nuevoZoom);
      }
    }
  };


  // Extrae "Nombre PrimerApellido" para búsqueda
  const nombreConApellido = (nombre) => {
    const p = (nombre || "").trim().split(/\s+/);
    return p.length >= 2 ? `${p[0]} ${p[1]}`.toLowerCase() : p[0].toLowerCase();
  };


  const anio = new Date().getFullYear();
  const mesActual = new Date().getMonth();
  const hoy = fechaLocalISO();

  // ── finalizadosHoy: IDs marcados como "finalizado" visualmente en el día.
  // localStorage con clave que incluye la fecha → se resetea solo cada día nuevo.
  const finalizadosKey = `finalizados-${session.id}-${hoy}`;
  const [finalizadosHoy, setFinalizadosHoy] = useState(() => {
    try {
      // Limpiar claves de días anteriores
      Object.keys(localStorage).forEach(k => {
        if (k.startsWith(`finalizados-${session.id}-`) && k !== `finalizados-${session.id}-${fechaLocalISO()}`) {
          localStorage.removeItem(k);
        }
      });
      const raw = localStorage.getItem(`finalizados-${session.id}-${fechaLocalISO()}`);
      return raw ? new Set(JSON.parse(raw)) : new Set();
    } catch { return new Set(); }
  });
  const [confirmFinalizar, setConfirmFinalizar] = useState(null);
  const [confirmReactivar, setConfirmReactivar] = useState(null);
  const [notaVisible, setNotaVisible] = useState(null); // id de cita cuya nota se muestra
  const [editandoHoy, setEditandoHoy] = useState(null); // { id, cliente, hora, notas, estadoId }
  const [diaDetalleSemana, setDiaDetalleSemana] = useState(null); // fecha seleccionada en vista semanal
  const [diaDetalleCalendario, setDiaDetalleCalendario] = useState(null); // fecha seleccionada en calendario anual
  const [editCalendario, setEditCalendario] = useState(null); // pendiente editando desde calendario anual
  const [editSemana, setEditSemana] = useState(null); // pendiente editando desde vista semanal
  const [alertaVencidos, setAlertaVencidos] = useState(false); // cuadro "revise pendientes vencidos"
  const ultimaAlertaVencidosRef = useRef(null); // timestamp de la última vez que se mostró

  const marcarFinalizado = (id) => {
    setFinalizadosHoy(prev => {
      const nuevo = new Set(prev);
      nuevo.add(id);
      try { localStorage.setItem(finalizadosKey, JSON.stringify([...nuevo])); } catch {}
      return nuevo;
    });
  };

  const reactivarPendiente = (id) => {
    setFinalizadosHoy(prev => {
      const nuevo = new Set(prev);
      nuevo.delete(id);
      try { localStorage.setItem(finalizadosKey, JSON.stringify([...nuevo])); } catch {}
      return nuevo;
    });
  };

  const MESES = ["Enero","Febrero","Marzo","Abril","Mayo","Junio","Julio","Agosto","Septiembre","Octubre","Noviembre","Diciembre"];
  const DIAS_SEMANA = ["D","L","M","M","J","V","S"];

  // Días de la semana actual (lun-dom)
  const semanaActual = (() => {
    const d = new Date();
    const dia = d.getDay(); // 0=dom
    const lunes = new Date(d);
    lunes.setDate(d.getDate() - (dia === 0 ? 6 : dia - 1));
    return Array.from({length: 7}, (_, i) => {
      const f = new Date(lunes);
      f.setDate(lunes.getDate() + i);
      return fechaLocalISO(f);
    });
  })();

  // Citas del día de hoy (todas, sin límite, para conteo correcto)
  const citasHoy = citas
    .filter((c) => c.fecha === hoy)
    .sort((a, b) => a.hora.localeCompare(b.hora));

  // Pendientes = no contrató ni canceló contrato
  const pendientesIds = new Set(["prospecto", "confirmo", "reagendo"]);

  // Recordatorio automático a las 8am con vibración
  useEffect(() => {
    const checkRecordatorio = async () => {
      const ahora = new Date();
      if (ahora.getHours() === 8 && ahora.getMinutes() < 2) {
        try {
          const r = await withTimeout(window.storage.get(recordatorioKey, true));
          const ultimoMostrado = r ? r.value : "";
          if (ultimoMostrado !== hoy) {
            await withTimeout(window.storage.set(recordatorioKey, hoy, true));
            // Vibrar en móvil: patrón [200ms vibra, 100ms pausa, 200ms vibra]
            if ("vibrate" in navigator) {
              navigator.vibrate([300, 100, 300, 100, 300]);
            }
            // Notificación del sistema si está permitida
            if ("Notification" in window && Notification.permission === "granted") {
              new Notification("⏰ Autocon Management · Agenda del día", {
                body: `Tienes ${citasHoy.length} cliente${citasHoy.length !== 1 ? "s" : ""} hoy. ¿Ya confirmaste tus citas?`,
                icon: "/favicon.ico",
                requireInteraction: true,
              });
            }
          }
        } catch {}
      }
    };
    checkRecordatorio();
    const interval = setInterval(checkRecordatorio, 60000);
    return () => clearInterval(interval);
  }, [citas, hoy]);

  // Generar franjas horarias 00:00 - 23:30 cada 30 min
  const FRANJAS = [];
  for (let h = 0; h < 24; h++) {
    FRANJAS.push(`${String(h).padStart(2,"0")}:00`);
    FRANJAS.push(`${String(h).padStart(2,"0")}:30`);
  }

  useEffect(() => {
    let cancelado = false;
    (async () => {
      try {
        const lista = await loadCitas(session.id);
        if (!cancelado) setCitas(lista);
      } catch { if (!cancelado) setCitas([]); }
      if (!cancelado) setLoading(false);
    })();
    return () => { cancelado = true; };
  }, []);

  // Cargar histórico permanente de estadísticas (independiente de los pendientes activos)
  useEffect(() => {
    let cancelado = false;
    (async () => {
      try {
        const r = await withTimeout(window.storage.get(statsKey, true));
        if (!cancelado) setHistoricoEstados(r ? JSON.parse(r.value) : []);
      } catch { if (!cancelado) setHistoricoEstados([]); }
    })();
    return () => { cancelado = true; };
  }, []);

  useEffect(() => {
    if ("Notification" in window && Notification.permission === "default") Notification.requestPermission();
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      const ahora = new Date();
      // Recolectar TODAS las citas que están a 15 minutos o menos
      const proximasCitas = citas.filter((c) => {
        if (c.alertado || !c.fecha || !c.hora) return false;
        const diff = new Date(`${c.fecha}T${c.hora}`) - ahora;
        return diff > 0 && diff <= 15 * 60 * 1000;
      });

      if (proximasCitas.length > 0) {
        // Mostrar cuadro flotante
        setAlarmaProxima(proximasCitas);
        // Vibrar en móvil
        if ("vibrate" in navigator) navigator.vibrate([400, 100, 400, 100, 400]);
        // Notificación del sistema
        if ("Notification" in window && Notification.permission === "granted") {
          new Notification("⏰ Autocon Management — Citas próximas", {
            body: `En 15 min tienes ${proximasCitas.length} pendiente${proximasCitas.length !== 1 ? "s" : ""}: ${proximasCitas.map(c => c.cliente).join(", ")}`,
            requireInteraction: true,
          });
        }
        // Marcar como alertadas
        setCitas((prev) => prev.map((c) =>
          proximasCitas.find((p) => p.id === c.id) ? { ...c, alertado: true } : c
        ));
      }
    }, 60000);
    return () => clearInterval(interval);
  }, [citas]);

  // ── Alerta de pendientes vencidos: cada 15 min si hay activos sin finalizar con +1h de retraso ──
  useEffect(() => {
    const checkVencidos = () => {
      const ahora = new Date();
      const hayVencidos = citasHoy.some((c) => {
        if (finalizadosHoy.has(c.id)) return false; // ya finalizado
        const horaCita = new Date(`${hoy}T${c.hora}`);
        return (ahora - horaCita) > 60 * 60 * 1000; // más de 1 hora pasada
      });
      if (!hayVencidos) return;
      const ultima = ultimaAlertaVencidosRef.current;
      const ahora15 = Date.now();
      // Mostrar si nunca se mostró, o han pasado 15 min desde la última vez
      if (!ultima || (ahora15 - ultima) >= 15 * 60 * 1000) {
        setAlertaVencidos(true);
        ultimaAlertaVencidosRef.current = ahora15;
      }
    };
    checkVencidos(); // revisar al montar
    const iv = setInterval(checkVencidos, 60 * 1000); // revisar cada minuto
    return () => clearInterval(iv);
  }, [citasHoy, finalizadosHoy, hoy]);

  const guardarCitas = async (lista) => {
    // Ledger permanente de estadísticas: registra la PRIMERA vez que cada pendiente
    // alcanza cada color/estado (verde, amarillo, rojo, etc). Este registro histórico
    // NUNCA se borra ni se resta, aunque después el pendiente se elimine, se renombre,
    // se mueva de día/hora, se duplique o cambie de color otra vez.
    const hoyISO = fechaLocalISO();
    const nuevosEventos = [];
    const listaConContados = lista.map((c) => {
      const estadoActual = c.estadoId || "prospecto";
      const contados = c.contados || [];
      if (!contados.includes(estadoActual)) {
        nuevosEventos.push({ estadoId: estadoActual, fecha: hoyISO });
        return { ...c, contados: [...contados, estadoActual] };
      }
      return c;
    });
    if (nuevosEventos.length > 0) {
      const nuevoHistorico = [...historicoEstados, ...nuevosEventos];
      setHistoricoEstados(nuevoHistorico);
      try {
        await withTimeout(window.storage.set(statsKey, JSON.stringify(nuevoHistorico), true));
      } catch (e) {
        console.warn("Error al guardar histórico de estadísticas:", e);
      }
    }
    try {
      await saveCitas(session.id, listaConContados);
    } catch (e) {
      console.warn("Error al guardar citas en Supabase:", e);
    }
    setCitas(listaConContados); // actualizar estado local siempre, aunque falle el guardado
  };

  // Migración única: los pendientes que ya existían antes de esta actualización (sin marca
  // "contados") se registran en el histórico permanente usando su color actual, para no
  // perder estadísticas ya generadas. Solo se ejecuta una vez por cada pendiente antiguo.
  useEffect(() => {
    if (loading || citas.length === 0) return;
    if (citas.some((c) => !c.contados)) guardarCitas(citas);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [loading, citas]);

  const agregarCita = async () => {
    if (!nueva.cliente || !nueva.hora) return;
    // Validar que la franja no esté llena (máx 4)
    const citasFranja = citas.filter((c) => c.fecha === diaSeleccionado && c.hora === nueva.hora);
    if (citasFranja.length >= 4) {
      setErrorFranja(`La franja ${nueva.hora} ya tiene 4 citas (máximo). Elige otro horario.`);
      return;
    }
    setErrorFranja("");
    setGuardando(true);
    try {
      await guardarCitas([...citas, { ...nueva, fecha: diaSeleccionado, id: uid(), alertado: false }]
        .sort((a, b) => `${a.fecha}T${a.hora}`.localeCompare(`${b.fecha}T${b.hora}`)));
      setNueva({ cliente: "", hora: "", notas: "", estadoId: "prospecto" });
      setShowForm(false);
      mostrarToast("Pendiente guardado correctamente");
    } catch (e) {
      console.warn("Error al guardar cita:", e);
      mostrarToast("Error al guardar. Intenta de nuevo.");
    } finally {
      setGuardando(false); // siempre desbloquea el botón
    }
  };

  // Días con citas
  const diasConCita = new Set(citas.map((c) => c.fecha));
  const citasPorDia = citas.reduce((acc, c) => {
    acc[c.fecha] = (acc[c.fecha] || 0) + 1;
    return acc;
  }, {});

  // Color más frecuente por día
  const colorPorDia = citas.reduce((acc, c) => {
    if (!acc[c.fecha]) acc[c.fecha] = {};
    const id = c.estadoId || "prospecto";
    acc[c.fecha][id] = (acc[c.fecha][id] || 0) + 1;
    return acc;
  }, {});
  const colorFrecuente = (fecha) => {
    const mapa = colorPorDia[fecha];
    if (!mapa) return null;
    const maxId = Object.entries(mapa).sort((a,b) => b[1]-a[1])[0]?.[0];
    return ESTADOS_CITA.find(e => e.id === maxId)?.color || null;
  };

  // ── Número de pendientes de HOY con la MISMA lógica que "PENDIENTES SEMANAL" ──
  // (excluye finalizados, excluye estados que no son "pendiente" real, y excluye
  // citas cuya hora ya pasó hace más de 1 hora). Antes esta tarjeta usaba un conteo
  // distinto (citasHoy.length - finalizadosHoy.size) que no aplicaba esos filtros,
  // provocando que mostrara un número distinto al de la tarjeta Semanal para el mismo día.
  const pendientesHoyExacto = (() => {
    const ahora = new Date();
    return citasHoy.filter(c => {
      if (finalizadosHoy.has(c.id)) return false;
      if (!pendientesIds.has(c.estadoId || "prospecto")) return false;
      const horaCita = new Date(`${hoy}T${c.hora}`);
      return (ahora - horaCita) <= 60 * 60 * 1000;
    }).length;
  })();

  // ── Número de pendientes semanal (con lógica de exclusión temporal) ──
  const pendientesSemana = (() => {
    const ahora = new Date();
    return semanaActual.reduce((total, fecha) => {
      // Días completamente pasados (antes de hoy) → no cuentan
      if (fecha < hoy) return total;
      const citasDia = citas.filter(c => c.fecha === fecha);
      return total + citasDia.filter(c => {
        if (finalizadosHoy.has(c.id)) return false; // finalizado → no cuenta
        if (!pendientesIds.has(c.estadoId || "prospecto")) return false; // contratado/cancelado → no cuenta
        if (fecha === hoy) {
          // Día actual: excluir pendientes cuya hora pasó hace más de 1 hora
          const horaCita = new Date(`${fecha}T${c.hora}`);
          return (ahora - horaCita) <= 60 * 60 * 1000;
        }
        return true; // días futuros → todos cuentan
      }).length;
    }, 0);
  })();

  // Solo se pueden agregar pendientes desde la semana actual en adelante
  // Todo lo anterior al lunes de la semana en curso queda bloqueado para agregar
  const limiteAgregar = semanaActual[0]; // Lunes de la semana en curso
  const puedeAgregar = diaSeleccionado >= limiteAgregar;

  // Citas del día seleccionado
  const citasDelDia = citas.filter((c) => c.fecha === diaSeleccionado);

  // Renderizar un mes
  const renderMes = (mesIdx) => {
    const primerDia = new Date(anio, mesIdx, 1).getDay();
    const diasEnMes = new Date(anio, mesIdx + 1, 0).getDate();
    const celdas = [];
    for (let i = 0; i < primerDia; i++) celdas.push(null);
    for (let d = 1; d <= diasEnMes; d++) celdas.push(d);
    const fechaStr = (d) => `${anio}-${String(mesIdx+1).padStart(2,"0")}-${String(d).padStart(2,"0")}`;
    const esHoy = (d) => fechaStr(d) === hoy;
    const tieneCita = (d) => diasConCita.has(fechaStr(d));
    const esSeleccionado = (d) => diaSeleccionado === fechaStr(d);
    const esMesActual = mesIdx === mesActual;

    return (
      <div key={mesIdx} style={{ background: esMesActual ? "#FEF9C3" : "#F8FAFC", borderRadius: 8, padding: "10px 8px", border: esMesActual ? "2px solid #F5C518" : "1px solid #E5E7EB" }}>
        <div style={{ textAlign: "center", fontWeight: 700, fontSize: 13, color: esMesActual ? "#92400E" : "#142B4D", marginBottom: 6, textTransform: "uppercase", letterSpacing: 0.5 }}>
          {MESES[mesIdx]}
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 1, marginBottom: 2 }}>
          {DIAS_SEMANA.map((d, i) => <div key={i} style={{ textAlign: "center", fontSize: 9, color: "#9CA3AF", fontWeight: 600 }}>{d}</div>)}
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 1 }}>
          {celdas.map((d, i) => {
            if (!d) return <div key={i} />;
            const fStr = fechaStr(d);
            const pasado = fStr < hoy;
            return (
              <div
                key={i}
                onClick={() => { setDiaSeleccionado(fStr); setShowForm(false); setBusquedaDia(""); setFiltroColor(""); setMoviendoCita(null); setMostrarCalendarioRegistro(false); setCalendarZoom(1); if (vistaAgenda === "calendario") setDiaDetalleCalendario(fStr); }}
                style={{
                  textAlign: "center", fontSize: 11, borderRadius: 4, padding: "2px 0", cursor: "pointer",
                  background: esSeleccionado(d) ? "#1A1A1A" : esHoy(d) ? "#D6452B" : tieneCita(d) ? (pasado ? "#E5E7EB" : "#F0F0F0") : (!pasado && esMesActual ? "#FAFAF5" : "transparent"),
                  color: esSeleccionado(d) || esHoy(d) ? "#fff" : pasado ? "#D1D5DB" : tieneCita(d) ? "#1A1A1A" : "#374151",
                  fontWeight: esHoy(d) || esSeleccionado(d) ? 700 : tieneCita(d) ? 600 : 400,
                  position: "relative",
                }}
              >
                {d}
                {tieneCita(d) && !esSeleccionado(d) && (
                  <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 2 }}>
                    {colorFrecuente(fechaStr(d)) && <div style={{ width: 5, height: 5, borderRadius: "50%", background: colorFrecuente(fechaStr(d)), flexShrink: 0 }} />}
                    <span style={{ fontSize: 7, fontWeight: 800, color: esHoy(d) ? "#fff" : "#1A1A1A" }}>{citasPorDia[fechaStr(d)] || ""}</span>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  // ── Página de estadísticas ──
  if (vistaAgenda === "estadisticas") {
    const hoyDate = new Date();
    const mesActualIdx = hoyDate.getMonth();   // 0-indexed
    const diaHoy = hoyDate.getDate();
    const MESES_NOMBRES = ["Enero","Febrero","Marzo","Abril","Mayo","Junio","Julio","Agosto","Septiembre","Octubre","Noviembre","Diciembre"];

    // Mes a destacar: si es día 1 mostrar el mes anterior completo, si no el mes actual
    const mesDestacadoIdx = diaHoy === 1 && mesActualIdx > 0 ? mesActualIdx - 1 : mesActualIdx;
    const mesDestacadoNombre = MESES_NOMBRES[mesDestacadoIdx];

    // Construir estadísticas por mes a partir del histórico permanente (nunca se pierde,
    // aunque el pendiente se borre, se renombre, se mueva de día/hora o se duplique).
    // La fecha usada es la del día en que se alcanzó ese color por primera vez, por lo
    // que cada mes se reinicia solo de forma natural al cambiar de rango de fechas.
    const statsPorMes = MESES_NOMBRES.slice(0, mesActualIdx + 1).map((mes, idx) => {
      const inicio = `${anio}-${String(idx+1).padStart(2,"0")}-01`;
      const fin = `${anio}-${String(idx+1).padStart(2,"0")}-${String(new Date(anio,idx+1,0).getDate()).padStart(2,"0")}`;
      const eventosMes = historicoEstados.filter(e => e.fecha >= inicio && e.fecha <= fin);
      const porColor = {};
      eventosMes.forEach(e => {
        porColor[e.estadoId] = (porColor[e.estadoId] || 0) + 1;
      });
      return { mes, idx, porColor, total: eventosMes.length };
    });

    // Texto legible según el color de fondo de cada rebanada
    const textoSobre = (hex) => (hex === "#EF4444" || hex === "#1A1A1A" || hex === "#3B82F6") ? "#fff" : "#142B4D";

    // Función SVG pastel genérica de dos colores (usada por ambas gráficas)
    const PastelSVG = ({ valorA, valorB, colorA, colorB, total }) => {
      if (total === 0) return (
        <div style={{ width:220, height:220, display:"flex", alignItems:"center", justifyContent:"center", textAlign:"center", color:"#9CA3AF", padding:"20px 0", fontSize:13 }}>
          Sin datos para este período.
        </div>
      );
      const r = 90; const cx = 110; const cy = 110;
      const pctA = valorA / total;
      const pctB = valorB / total;
      // Si uno es 100%
      if (valorA === 0 || valorB === 0) {
        const color = valorA > 0 ? colorA : colorB;
        const label = valorA > 0 ? `${Math.round(pctA*100)}%` : `${Math.round(pctB*100)}%`;
        return (
          <svg width="220" height="220" viewBox="0 0 220 220">
            <circle cx={cx} cy={cy} r={r} fill={color} />
            <text x={cx} y={cy} textAnchor="middle" dominantBaseline="middle" fontSize="22" fontWeight="bold" fill={textoSobre(color)}>{label}</text>
          </svg>
        );
      }
      // Calcular arcos
      const angle1 = pctA * 2 * Math.PI;
      const x1 = cx + r * Math.sin(angle1); const y1 = cy - r * Math.cos(angle1);
      const largeArc1 = pctA > 0.5 ? 1 : 0;
      const largeArc2 = pctB > 0.5 ? 1 : 0;
      // Midpoint angles para labels
      const midA1 = angle1 / 2;
      const lx1 = cx + (r*0.65) * Math.sin(midA1); const ly1 = cy - (r*0.65) * Math.cos(midA1);
      const midA2 = angle1 + (2*Math.PI - angle1)/2;
      const lx2 = cx + (r*0.65) * Math.sin(midA2); const ly2 = cy - (r*0.65) * Math.cos(midA2);
      return (
        <svg width="220" height="220" viewBox="0 0 220 220">
          {/* Rebanada A */}
          <path d={`M ${cx} ${cy} L ${cx} ${cy-r} A ${r} ${r} 0 ${largeArc1} 1 ${x1} ${y1} Z`} fill={colorA} />
          {/* Rebanada B */}
          <path d={`M ${cx} ${cy} L ${x1} ${y1} A ${r} ${r} 0 ${largeArc2} 1 ${cx} ${cy-r} Z`} fill={colorB} />
          {/* Labels porcentaje */}
          <text x={lx1} y={ly1} textAnchor="middle" dominantBaseline="middle" fontSize="15" fontWeight="bold" fill={textoSobre(colorA)}>{Math.round(pctA*100)}%</text>
          <text x={lx2} y={ly2} textAnchor="middle" dominantBaseline="middle" fontSize="15" fontWeight="bold" fill={textoSobre(colorB)}>{Math.round(pctB*100)}%</text>
        </svg>
      );
    };

    return (
      <div>
        {/* Encabezado */}
        <div style={{ background: "#1A1A1A", color:"#fff", padding:"16px 20px" }}>
          <div style={{ maxWidth:900, margin:"0 auto", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
            <div>
              <div style={{ fontSize:11, letterSpacing:3, color:"rgba(255,255,255,0.6)", textTransform:"uppercase" }}>Autocon Management · Agenda Virtual</div>
              <div className="display" style={{ fontSize:20, fontWeight:700 }}>📊 Tus Estadísticas {anio}</div>
              <div style={{ fontSize:12, color:"rgba(255,255,255,0.6)", marginTop:2 }}>
                Estadísticas destacadas: <strong style={{color:"#F5C518"}}>{mesDestacadoNombre}</strong>
                {diaHoy === 1 && mesActualIdx > 0 && " (mes completado)"}
              </div>
            </div>
            <button onClick={() => setVistaAgenda(null)} style={{ padding:"12px 28px", border:"none", borderRadius:6, background:"#D6452B", color:"#fff", fontWeight:700, fontSize:15, cursor:"pointer" }}>← Salir</button>
          </div>
        </div>

        <div style={{ maxWidth:900, margin:"0 auto", padding:"24px 20px" }}>

          {/* Tabla mensual por colores */}
          <div style={{ background:"#fff", borderRadius:10, border:"1px solid #E5E7EB", overflow:"hidden", marginBottom:24 }}>
            <div style={{ background:"#1A1A1A", padding:"12px 20px" }}>
              <div className="display" style={{ color:"#fff", fontWeight:700, fontSize:15 }}>📅 Resumen Mensual por Estado</div>
            </div>
            {/* Encabezado tabla */}
            <div style={{ display:"grid", gridTemplateColumns:`120px repeat(${ESTADOS_CITA.length}, 1fr) 60px`, padding:"8px 16px", background:"#F8FAFC", fontSize:10, fontWeight:700, color:"#6B7280", borderBottom:"1px solid #E5E7EB", gap:4 }}>
              <div>MES</div>
              {ESTADOS_CITA.map(e => (
                <div key={e.id} style={{ textAlign:"center" }}>
                  <div style={{ width:10, height:10, borderRadius:"50%", background:estadoBG(e), margin:"0 auto 2px" }} />
                  <div style={{ fontSize:8, lineHeight:1.2 }}>{e.label.split("/")[0].split(" ")[0]}</div>
                </div>
              ))}
              <div style={{ textAlign:"center" }}>TOTAL</div>
            </div>
            {/* Filas por mes */}
            {statsPorMes.map(({ mes, idx, porColor, total }) => {
              const esDestacado = idx === mesDestacadoIdx;
              return (
                <div key={mes} style={{ display:"grid", gridTemplateColumns:`120px repeat(${ESTADOS_CITA.length}, 1fr) 60px`, padding:"8px 16px", background: esDestacado ? "#FFFBEB" : idx%2===0 ? "#fff" : "#FAFAFA", borderBottom:"1px solid #F3F4F6", fontSize:13, gap:4, alignItems:"center", border: esDestacado ? "2px solid #F5C518" : "none" }}>
                  <div style={{ fontWeight: esDestacado ? 700 : 500, color:"#142B4D", fontSize:13 }}>
                    {mes} {esDestacado && <span style={{ fontSize:9, background:"#F5C518", color:"#142B4D", borderRadius:4, padding:"1px 4px", fontWeight:700 }}>★</span>}
                  </div>
                  {ESTADOS_CITA.map(e => (
                    <div key={e.id} style={{ textAlign:"center" }}>
                      {porColor[e.id] ? (
                        <span style={{ background:estadoBG(e), color:e.text, borderRadius:10, padding:"1px 6px", fontSize:11, fontWeight:700 }}>
                          {porColor[e.id]}
                        </span>
                      ) : <span style={{ color:"#D1D5DB", fontSize:11 }}>—</span>}
                    </div>
                  ))}
                  <div style={{ textAlign:"center", fontWeight:700, color:"#142B4D", fontSize:14 }}>{total || "—"}</div>
                </div>
              );
            })}
          </div>

          {/* Vista detalle de un mes (nivel de conversión por mes) */}
          {mesConversionIdx !== null && (() => {
            const mes = MESES_NOMBRES[mesConversionIdx];
            const stats = statsPorMes[mesConversionIdx] || { porColor:{}, total:0 };
            const tProsp = stats.porColor["prospecto"] || 0;
            const tConf = stats.porColor["confirmo"] || 0;
            const tCont = stats.porColor["contrato"] || 0;
            const tPast = tConf + tCont;
            const tProspConf = tProsp + tConf;
            // Efectividad = contratos / (confirmos + contratos)
            // El cliente que contrató también llegó a la cita → cuenta en el denominador
            const pct = tPast > 0 ? Math.round((tCont/tPast)*100) : 0;
            const nivel = pct <= 20
              ? { icon:"😟", medalla:null, msg:"¿Qué sucede? ¿Por qué este resultado?", bg:"#FEF2F2", color:"#991B1B" }
              : pct <= 40
              ? { icon:"💪", medalla:null, msg:"Estás muy bajo aún. ¡Vamos, tú puedes!", bg:"#FFF7ED", color:"#C2410C" }
              : pct <= 60
              ? { icon:"📈", medalla:null, msg:"Vas mejorando. ¡Vamos, sí se puede!", bg:"#FFFBEB", color:"#B45309" }
              : pct <= 70
              ? { icon:"🥉", medalla:"Medalla de Cobre", msg:"Eres productivo. Pero puedes ser mejor.", bg:"#FEF3C7", color:"#92400E" }
              : pct <= 90
              ? { icon:"🥈", medalla:"Medalla de Bronce", msg:"Eres productivo. ¡Un Campeón de las ventas!", bg:"#F0F9FF", color:"#0369A1" }
              : { icon:"🥇", medalla:"Medalla de Oro", msg:"Eres el amo indiscutible de las ventas. ¡Excelente conversión! Felicidades.", bg:"#F0FDF4", color:"#15803D" };
            return (
              <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.7)", zIndex:9999, overflowY:"auto", display:"flex", alignItems:"flex-start", justifyContent:"center", padding:"20px 16px" }}>
                <div style={{ background:"#fff", borderRadius:12, width:"100%", maxWidth:680, boxShadow:"0 12px 40px rgba(0,0,0,0.4)", overflow:"hidden" }}>
                  {/* Encabezado */}
                  <div style={{ background:"#1A1A1A", padding:"16px 22px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                    <div>
                      <div style={{ fontSize:10, color:"rgba(255,255,255,0.6)", letterSpacing:2, textTransform:"uppercase" }}>Nivel de Conversión</div>
                      <div className="display" style={{ color:"#fff", fontSize:19, fontWeight:700 }}>🥧 {mes} {anio}</div>
                    </div>
                    <button onClick={() => setMesConversionIdx(null)} style={{ padding:"12px 24px", border:"none", borderRadius:6, background:"#D6452B", color:"#fff", fontWeight:700, fontSize:14, cursor:"pointer" }}>← Salir</button>
                  </div>
                  <div style={{ padding:"22px" }}>
                    {/* Tarjetas grandes de colores */}
                    <div style={{ display:"flex", gap:14, marginBottom:22, flexWrap:"wrap" }}>
                      <div style={{ background:"#F0FDF4", border:"2px solid #22C55E", borderRadius:10, padding:"14px 18px", flex:1, minWidth:160, textAlign:"center" }}>
                        <div style={{ fontSize:10, color:"#15803D", fontWeight:700, marginBottom:4 }}>PROSPECTO / CITADO</div>
                        <div style={{ fontSize:40, fontWeight:800, color:"#22C55E" }}>{tProsp}</div>
                      </div>
                      <div style={{ background:"#FFFBEB", border:"2px solid #F5C518", borderRadius:10, padding:"14px 18px", flex:1, minWidth:160, textAlign:"center" }}>
                        <div style={{ fontSize:10, color:"#92400E", fontWeight:700, marginBottom:4 }}>CONFIRMÓ CITA</div>
                        <div style={{ fontSize:40, fontWeight:800, color:"#F5C518" }}>{tConf}</div>
                      </div>
                      <div style={{ background:"#FEF2F2", border:"2px solid #EF4444", borderRadius:10, padding:"14px 18px", flex:1, minWidth:160, textAlign:"center" }}>
                        <div style={{ fontSize:10, color:"#991B1B", fontWeight:700, marginBottom:4 }}>CLIENTE CONTRATÓ</div>
                        <div style={{ fontSize:40, fontWeight:800, color:"#EF4444" }}>{tCont}</div>
                      </div>
                      <div style={{ background:"#EFF6FF", border:"2px solid #2563EB", borderRadius:10, padding:"14px 18px", flex:1, minWidth:160, textAlign:"center" }}>
                        <div style={{ fontSize:10, color:"#1D4ED8", fontWeight:700, marginBottom:4 }}>EFECTIVIDAD</div>
                        <div style={{ fontSize:40, fontWeight:800, color:"#2563EB" }}>{tPast > 0 ? `${pct}%` : "—"}</div>
                      </div>
                    </div>

                    {/* Gráfico 1: Prospecto/Citado vs. Confirmó Cita */}
                    <div style={{ marginBottom:24 }}>
                      <div style={{ fontSize:12, fontWeight:700, color:"#6B7280", marginBottom:10, textAlign:"center", letterSpacing:0.5 }}>NIVEL DE CONVERSIÓN · PROSPECTOS AGENDADOS vs. CONFIRMACIONES</div>
                      <div style={{ display:"flex", gap:24, alignItems:"center", justifyContent:"center", flexWrap:"wrap" }}>
                        <PastelSVG valorA={tProsp} valorB={tConf} colorA="#22C55E" colorB="#F5C518" total={tProspConf} />
                        <div style={{ display:"flex", flexDirection:"column", gap:12 }}>
                          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                            <div style={{ width:18, height:18, borderRadius:3, background:"#22C55E" }} />
                            <span style={{ fontSize:13, fontWeight:600, color:"#142B4D" }}>Prospecto / Citado — {tProsp} · {tProspConf>0?Math.round((tProsp/tProspConf)*100):0}%</span>
                          </div>
                          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                            <div style={{ width:18, height:18, borderRadius:3, background:"#F5C518" }} />
                            <span style={{ fontSize:13, fontWeight:600, color:"#142B4D" }}>Confirmó Cita — {tConf} · {tProspConf>0?Math.round((tConf/tProspConf)*100):0}%</span>
                          </div>
                        </div>
                      </div>
                    </div>

                    <div style={{ borderTop:"1px dashed #E5E7EB", margin:"0 0 24px" }} />

                    {/* Gráfico 2: Confirmó Cita vs. Cliente Contrató + medalla de efectividad */}
                    <div>
                      <div style={{ fontSize:12, fontWeight:700, color:"#6B7280", marginBottom:10, textAlign:"center", letterSpacing:0.5 }}>NIVEL DE CONVERSIÓN · CONFIRMACIONES vs. CONTRATOS (EFECTIVIDAD DE CIERRE)</div>
                      <div style={{ display:"flex", gap:24, alignItems:"center", justifyContent:"center", flexWrap:"wrap", marginBottom:16 }}>
                        <PastelSVG valorA={tConf} valorB={tCont} colorA="#F5C518" colorB="#EF4444" total={tPast} />
                        <div style={{ display:"flex", flexDirection:"column", gap:12 }}>
                          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                            <div style={{ width:18, height:18, borderRadius:3, background:"#F5C518" }} />
                            <span style={{ fontSize:13, fontWeight:600, color:"#142B4D" }}>Confirmó Cita — {tConf} · {tPast>0?Math.round((tConf/tPast)*100):0}%</span>
                          </div>
                          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                            <div style={{ width:18, height:18, borderRadius:3, background:"#EF4444" }} />
                            <span style={{ fontSize:13, fontWeight:600, color:"#142B4D" }}>Cliente contrató — {tCont} · {tPast>0?Math.round((tCont/tPast)*100):0}%</span>
                          </div>
                          {tPast > 0 && (
                            <div style={{ background:nivel.bg, borderRadius:10, padding:"12px 16px", border:`1px solid ${nivel.color}33` }}>
                              <div style={{ fontSize:11, fontWeight:800, color:nivel.color, letterSpacing:1, textTransform:"uppercase", marginBottom:4 }}>Efectividad de cierre: {pct}%</div>
                              <div style={{ fontSize:26, marginBottom:4 }}>{nivel.icon}</div>
                              {nivel.medalla && <div style={{ fontSize:13, fontWeight:800, color:nivel.color, marginBottom:3 }}>🏅 {nivel.medalla}</div>}
                              <div style={{ fontSize:12, color:nivel.color, fontWeight:600, lineHeight:1.4 }}>{nivel.msg}</div>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                    {/* Resumen todos los estados */}
                    <div style={{ borderTop:"1px solid #F3F4F6", paddingTop:14 }}>
                      <div style={{ fontSize:12, fontWeight:700, color:"#6B7280", marginBottom:8 }}>RESUMEN COMPLETO DEL MES</div>
                      <div style={{ display:"flex", flexWrap:"wrap", gap:8 }}>
                        {ESTADOS_CITA.map(e => {
                          const cnt = stats.porColor[e.id] || 0;
                          return (
                            <div key={e.id} style={{ display:"flex", alignItems:"center", gap:6, background:"#F8FAFC", borderRadius:8, padding:"6px 10px", border:"1px solid #E5E7EB" }}>
                              <div style={{ width:10, height:10, borderRadius:"50%", background:estadoBG(e) }} />
                              <span style={{ fontSize:12, color:"#142B4D" }}>{e.label}:</span>
                              <span style={{ fontSize:13, fontWeight:700, color:cnt>0?e.color:"#D1D5DB" }}>{cnt||"—"}</span>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })()}

          {/* Nivel de conversión por mes — botones */}
          <div style={{ background:"#fff", borderRadius:10, border:"1px solid #E5E7EB", overflow:"hidden", marginTop:24 }}>
            <div style={{ background:"#1A1A1A", padding:"12px 20px" }}>
              <div className="display" style={{ color:"#fff", fontWeight:700, fontSize:15 }}>🥧 Nivel de Conversión por Mes</div>
              <div style={{ color:"rgba(255,255,255,0.6)", fontSize:11, marginTop:2 }}>Toca un mes para ver sus estadísticas detalladas</div>
            </div>
            <div style={{ padding:"16px 20px", display:"flex", flexWrap:"wrap", gap:10 }}>
              {MESES_NOMBRES.map((mes, idx) => {
                const stats = statsPorMes[idx];
                const disponible = !!stats;
                const tConf = stats?.porColor["confirmo"] || 0;
                const tCont = stats?.porColor["contrato"] || 0;
                const tPastBtn = tConf + tCont;
                const pct = tPastBtn > 0 ? Math.round((tCont/tPastBtn)*100) : null;
                const esDestacado = idx === mesDestacadoIdx;
                return (
                  <button
                    key={mes}
                    onClick={() => disponible && setMesConversionIdx(idx)}
                    disabled={!disponible}
                    style={{
                      padding:"10px 16px", border:"none", borderRadius:8, cursor: disponible ? "pointer" : "not-allowed",
                      background: esDestacado ? "#F5C518" : disponible ? "#1A1A1A" : "#F3F4F6",
                      color: esDestacado ? "#142B4D" : disponible ? "#fff" : "#9CA3AF",
                      fontWeight:700, fontSize:13, minWidth:90, textAlign:"center",
                      boxShadow: esDestacado ? "0 2px 8px rgba(245,197,24,0.4)" : "none",
                      transition:"transform 0.15s",
                    }}
                    onMouseOver={(e) => disponible && (e.currentTarget.style.transform="scale(1.05)")}
                    onMouseOut={(e) => e.currentTarget.style.transform="scale(1)"}
                  >
                    <div>{mes}</div>
                    {pct !== null && <div style={{ fontSize:10, marginTop:2, opacity:0.85 }}>{pct}% conv.</div>}
                    {disponible && pct === null && <div style={{ fontSize:9, marginTop:2, opacity:0.7 }}>Sin datos</div>}
                    {!disponible && <div style={{ fontSize:9, marginTop:2 }}>Próximo</div>}
                  </button>
                );
              })}
            </div>
          </div>
        </div>
      </div>
    );
  }


  // ── VISTA: Menú principal 6 cuadros ──
  if (vistaAgenda === null) {
    const CardAgenda = ({ color, textColor = "#fff", emoji, title, onClick, badge }) => (
      <div
        onClick={onClick}
        style={{
          background: color, borderRadius: 14, padding: "28px 20px",
          cursor: "pointer", display: "flex", flexDirection: "column",
          alignItems: "center", justifyContent: "center", gap: 10,
          boxShadow: "0 4px 16px rgba(0,0,0,0.18)", transition: "transform 0.15s",
          userSelect: "none", minHeight: 170, position: "relative",
        }}
        onMouseOver={(e) => { e.currentTarget.style.transform = "scale(1.03)"; }}
        onMouseOut={(e) => { e.currentTarget.style.transform = "scale(1)"; }}
      >
        <div style={{ fontSize: 44, lineHeight: 1 }}>{emoji}</div>
        <div className="display" style={{
          fontWeight: 800, fontSize: 16, color: textColor,
          textTransform: "uppercase", letterSpacing: 0.8,
          textAlign: "center", lineHeight: 1.25,
        }}>{title}</div>
        {badge !== undefined && (
          <div style={{
            fontSize: 52, fontWeight: 900, color: textColor,
            lineHeight: 1, marginTop: 4, letterSpacing: -2,
            fontFamily: "Oswald, sans-serif",
          }}>{badge}</div>
        )}
      </div>
    );

    return (
      <div>
        {/* Alarma 15 min */}
        {alarmaProxima && (
          <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.75)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
            <div style={{ background: "#fff", borderRadius: 14, width: "100%", maxWidth: 420, boxShadow: "0 16px 48px rgba(0,0,0,0.45)", overflow: "hidden" }}>
              <div style={{ background: "#C0392B", padding: "18px 22px", textAlign: "center" }}>
                <div style={{ fontSize: 32, marginBottom: 6 }}>⏰</div>
                <div className="display" style={{ color: "#fff", fontSize: 17, fontWeight: 800, lineHeight: 1.3 }}>
                  ¡En 15 minutos tienes{" "}
                  <span style={{ color: "#F5C518" }}>{alarmaProxima.length} pendiente{alarmaProxima.length !== 1 ? "s" : ""}</span> por atender!
                </div>
              </div>
              <div style={{ padding: "16px 22px" }}>
                {alarmaProxima.map((c, idx) => (
                  <div key={idx} style={{ background: "#F8FAFC", borderRadius: 8, padding: "10px 14px", marginBottom: 8, border: "1px solid #E5E7EB" }}>
                    <div style={{ fontWeight: 700, fontSize: 14, color: "#142B4D" }}>{c.cliente}</div>
                    <div style={{ fontSize: 12, color: "#6B7280", marginTop: 2 }}>⏰ {c.hora}{c.notas ? ` · ${c.notas}` : ""}</div>
                  </div>
                ))}
              </div>
              <div style={{ padding: "0 22px 18px" }}>
                <button onClick={() => setAlarmaProxima(null)} style={{ width: "100%", padding: "11px", border: "none", borderRadius: 8, background: "#C0392B", color: "#fff", fontWeight: 800, fontSize: 14, cursor: "pointer" }}>
                  ✓ ENTENDIDO
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Toast */}
        {toastMsg && (
          <div style={{ position: "fixed", top: 16, left: "50%", transform: "translateX(-50%)", background: "#22C55E", color: "#fff", padding: "10px 24px", borderRadius: 8, fontSize: 14, fontWeight: 700, zIndex: 99999, boxShadow: "0 4px 16px rgba(0,0,0,0.2)" }}>
            ✓ {toastMsg}
          </div>
        )}

        {/* Modal: pendientes vencidos sin marcar */}
        {alertaVencidos && (
          <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.65)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
            <div style={{ background: "#fff", borderRadius: 14, padding: 28, maxWidth: 340, width: "100%", boxShadow: "0 12px 40px rgba(0,0,0,0.4)", textAlign: "center" }}>
              <div style={{ fontSize: 38, marginBottom: 12 }}>⚠️</div>
              <div className="display" style={{ fontSize: 16, fontWeight: 800, color: "#142B4D", marginBottom: 10, lineHeight: 1.4 }}>
                Revise su lista de pendientes hoy. Hay pendientes activos cuyo horario ya se cumplió.
              </div>
              <button
                onClick={() => setAlertaVencidos(false)}
                style={{ marginTop: 8, width: "100%", padding: "13px", border: "none", borderRadius: 8, background: "#F5C518", color: "#142B4D", fontWeight: 800, fontSize: 15, cursor: "pointer" }}
              >
                ✓ Aceptar
              </button>
            </div>
          </div>
        )}

        {/* TopBar */}
        <div style={{ background: "#1A1A1A", color: "#fff", padding: "16px 20px" }} className="no-print">
          <div style={{ maxWidth: 900, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div>
              <div style={{ fontSize: 11, letterSpacing: 3, color: "rgba(255,255,255,0.7)", textTransform: "uppercase" }}>Autocon Management · Agenda Virtual</div>
              <div className="display" style={{ fontSize: 20, fontWeight: 700 }}>📅 CALENDARIO {anio} — AGENDA VIRTUAL</div>
            </div>
            <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
              {notifEstado === "activado" ? (
                <span style={{ fontSize: 12, color: "#7BC67E", fontWeight: 700 }}>🔔 Recordatorios activados</span>
              ) : notifEstado === "no-soportado" ? null : (
                <button onClick={handleActivarNotif} disabled={notifEstado === "cargando"} style={{ padding: "10px 18px", border: "1px solid #fff", borderRadius: 6, background: "transparent", color: "#fff", cursor: "pointer", fontSize: 13, fontWeight: 700 }}>
                  🔔 {notifEstado === "cargando" ? "..." : "Activar recordatorios"}
                </button>
              )}
              <button onClick={onClose} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: "#D6452B", color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>
            </div>
          </div>
        </div>

        {/* Grid 3×2 */}
        <div style={{ maxWidth: 900, margin: "0 auto", padding: "28px 20px" }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 16 }}>
            {/* Fila 1 */}
            <CardAgenda color="#1A1A1A" emoji="📋" title="REGISTRO DE PENDIENTES" onClick={() => { setDiaSeleccionado(hoy); setMostrarCalendarioRegistro(false); setShowForm(true); setVistaAgenda("registro"); }} />
            <CardAgenda color="#F5C518" textColor="#142B4D" emoji="⌚" title="PENDIENTES DE HOY" onClick={() => setVistaAgenda("pendientes-hoy")} badge={pendientesHoyExacto} />
            <CardAgenda color="#1A1A1A" emoji="📆" title="PENDIENTES SEMANAL" onClick={() => setVistaAgenda("pendientes-semana")} badge={pendientesSemana} />
            {/* Fila 2 */}
            <CardAgenda color="#F5C518" textColor="#142B4D" emoji="📊" title="TUS ESTADÍSTICAS" onClick={() => setVistaAgenda("estadisticas")} />
            <CardAgenda color="#1A1A1A" emoji="📅" title="CALENDARIO" onClick={() => setVistaAgenda("calendario")} />
            <CardAgenda color="#F5C518" textColor="#142B4D" emoji="🤝" title="CLIENTES CONTRATADOS" onClick={() => setVistaAgenda("clientes-contratados")} />
          </div>
        </div>
      </div>
    );
  }

  // ── VISTA: Registro de Pendientes (seleccionar día + agregar) ──
  if (vistaAgenda === "registro") {
    // Si no hay día seleccionado, preseleccionar HOY automáticamente
    if (!diaSeleccionado) {
      setDiaSeleccionado(hoy);
      return null;
    }

    // Mostrar calendario para cambiar día (se activa con el botón "Cambiar día")
    if (mostrarCalendarioRegistro) {
      return (
        <div>
          <div style={{ background: "#1A1A1A", color: "#fff", padding: "16px 20px" }}>
            <div style={{ maxWidth: 900, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div>
                <div style={{ fontSize: 11, letterSpacing: 3, color: "rgba(255,255,255,0.7)", textTransform: "uppercase" }}>Autocon Management · Registro de Pendientes</div>
                <div className="display" style={{ fontSize: 19, fontWeight: 700 }}>📅 ELIGE UN DÍA</div>
                <div style={{ fontSize: 12, color: "rgba(255,255,255,0.65)", marginTop: 2 }}>Toca el día donde quieres agregar el pendiente</div>
              </div>
              <button onClick={() => { setMostrarCalendarioRegistro(false); setCalendarZoom(1); }} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: "#D6452B", color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Cancelar</button>
            </div>
          </div>
          <div style={{ maxWidth: 900, margin: "0 auto", padding: "20px" }}>
            {loading ? (
              <div style={{ textAlign: "center", color: "#6B7280", padding: 32 }}>Cargando…</div>
            ) : (
              <>
                <div
                  onTouchStart={onCalendarTouchStart}
                  onTouchMove={onCalendarTouchMove}
                  style={{
                    overflow: "auto",
                    WebkitOverflowScrolling: "touch",
                    touchAction: "pan-x pan-y",
                    maxHeight: "70vh",
                    border: calendarZoom > 1 ? "1px dashed #F5C518" : "none",
                    borderRadius: 8,
                  }}
                >
                  <div style={{
                    display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 10,
                    transform: `scale(${calendarZoom})`, transformOrigin: "top center",
                    transition: "transform 0.1s ease-out",
                  }}>
                    {Array.from({length: 12}, (_, i) => renderMes(i))}
                  </div>
                </div>
                <div style={{ marginTop: 14, background: "#FFFBEB", border: "1px solid #F5C518", borderRadius: 8, padding: "10px 16px", fontSize: 12, color: "#92400E", textAlign: "center", fontWeight: 500 }}>
                  📅 Toca cualquier día del calendario para seleccionarlo y regresar al formulario.
                  {" "}Pellizca con dos dedos para acercar y seleccionar con más precisión.
                  {calendarZoom > 1 && (
                    <div style={{ marginTop: 8 }}>
                      <button onClick={() => setCalendarZoom(1)} style={{ padding: "6px 16px", border: "none", borderRadius: 6, background: "#F5C518", color: "#142B4D", fontWeight: 700, fontSize: 12, cursor: "pointer" }}>
                        ↺ Restablecer tamaño ({Math.round(calendarZoom * 100)}%)
                      </button>
                    </div>
                  )}
                </div>
              </>
            )}
          </div>
        </div>
      );
    }

    // Vista principal del formulario de agregar
    const nombreDia = new Date(diaSeleccionado + "T12:00:00").toLocaleDateString("es-MX", { weekday: "long", day: "numeric", month: "long" });
    const pendientesActivosDia = citasDelDia.filter((c) => pendientesIds.has(c.estadoId || "prospecto")).length;

    return (
      <div>
        {/* Toast */}
        {toastMsg && (
          <div style={{ position: "fixed", top: 16, left: "50%", transform: "translateX(-50%)", background: "#22C55E", color: "#fff", padding: "10px 24px", borderRadius: 8, fontSize: 14, fontWeight: 700, zIndex: 99999, boxShadow: "0 4px 16px rgba(0,0,0,0.2)" }}>
            ✓ {toastMsg}
          </div>
        )}
        {/* Ventana detalle de cita (modal) */}
        {citaDetalle && (
          <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
            <div style={{ background: "#fff", borderRadius: 10, padding: 22, maxWidth: 380, width: "100%", boxShadow: "0 8px 32px rgba(0,0,0,0.3)" }}>
              {!modoEdicion ? (
                <>
                  <div style={{ fontWeight: 700, fontSize: 16, color: "#142B4D", marginBottom: 10 }}>
                    {ESTADOS_CITA.find((e) => e.id === (citaDetalle.estadoId || "prospecto"))?.label || "Prospecto"}
                  </div>
                  <div style={{ fontSize: 14, marginBottom: 5 }}><strong>Cliente:</strong> {citaDetalle.cliente}</div>
                  <div style={{ fontSize: 14, marginBottom: 5 }}><strong>Fecha:</strong> {citaDetalle.fecha}</div>
                  <div style={{ fontSize: 14, marginBottom: 5 }}><strong>Hora:</strong> {citaDetalle.hora}</div>
                  {citaDetalle.notas && <div style={{ fontSize: 13, color: "#6B7280", marginBottom: 10 }}>📝 {citaDetalle.notas}</div>}

                  <div style={{ marginTop: 12, paddingTop: 12, borderTop: "1px solid #E3DECF" }}>
                    <div style={{ fontSize: 12, fontWeight: 700, color: "#142B4D", marginBottom: 8 }}>📒 Bitácora de seguimiento</div>
                    <div style={{ display: "flex", gap: 6, marginBottom: 10 }}>
                      <input
                        value={nuevaNotaBitacora}
                        onChange={(e) => setNuevaNotaBitacora(e.target.value)}
                        onKeyDown={(e) => { if (e.key === "Enter") agregarNotaBitacora(); }}
                        placeholder="Ej: Llamé, dijo que lo pensaría. Volver a marcar el jueves."
                        style={{ flex: 1, padding: "7px 10px", border: "1px solid #E3DECF", borderRadius: 6, fontSize: 12 }}
                      />
                      <button onClick={agregarNotaBitacora} disabled={!nuevaNotaBitacora.trim() || guardandoBitacora} style={{ padding: "7px 12px", border: "none", borderRadius: 6, background: "#142B4D", color: "#fff", fontWeight: 700, fontSize: 11, cursor: "pointer" }}>
                        + Agregar
                      </button>
                    </div>
                    <div style={{ maxHeight: 160, overflowY: "auto", display: "flex", flexDirection: "column", gap: 6 }}>
                      {(citaDetalle.bitacora || []).length === 0 ? (
                        <div style={{ fontSize: 11.5, color: "#9CA3AF", fontStyle: "italic" }}>Aún no hay notas de seguimiento.</div>
                      ) : (
                        [...(citaDetalle.bitacora || [])].reverse().map((n, i) => (
                          <div key={i} style={{ background: "#F8FAFC", border: "1px solid #E3DECF", borderRadius: 6, padding: "6px 9px" }}>
                            <div style={{ fontSize: 10, color: "#9CA3AF", marginBottom: 2 }}>{fmtDateTime(new Date(n.fecha))}</div>
                            <div style={{ fontSize: 12, color: "#374151" }}>{n.texto}</div>
                          </div>
                        ))
                      )}
                    </div>
                  </div>

                  <div style={{ display: "flex", gap: 8, marginTop: 14 }}>
                    <button onClick={() => { setEditData({ estadoId: citaDetalle.estadoId || "prospecto", notas: citaDetalle.notas || "", cliente: citaDetalle.cliente || "" }); setModoEdicion(true); }} style={{ flex: 1, padding: "8px", border: "none", borderRadius: 6, background: "#2563EB", color: "#fff", fontWeight: 700, cursor: "pointer", fontSize: 11 }}>✏️ Editar</button>
                    <button onClick={() => { setMoverData({ fecha: citaDetalle.fecha, hora: citaDetalle.hora }); setMoverConfirm(false); setMoviendoCita(citaDetalle); setCitaDetalle(null); setModoEdicion(false); }} style={{ flex: 1, padding: "8px", border: "none", borderRadius: 6, background: "#F5C518", color: "#142B4D", fontWeight: 700, cursor: "pointer", fontSize: 11 }}>🔄 Mover</button>
                    <button onClick={() => setCitaDetalle(null)} style={{ flex: 1, padding: "8px", border: "none", borderRadius: 6, background: "#6B7280", color: "#fff", fontWeight: 700, cursor: "pointer", fontSize: 11 }}>✕ Cerrar</button>
                  </div>
                </>
              ) : (
                <>
                  <div style={{ fontWeight: 700, fontSize: 15, color: "#142B4D", marginBottom: 10 }}>✏️ Editar pendiente</div>
                  <div style={{ marginBottom: 10 }}>
                    <label style={{ fontSize: 12, fontWeight: 600, color: "#2E3744", display: "block", marginBottom: 4 }}>Nombre del cliente</label>
                    <input value={editData.cliente} onChange={(e) => setEditData({ ...editData, cliente: e.target.value })} style={{ width: "100%", padding: "9px 12px", border: "1px solid #E3DECF", borderRadius: 6, fontSize: 14 }} />
                  </div>
                  <div style={{ marginBottom: 12 }}>
                    <label style={{ fontSize: 12, fontWeight: 600, color: "#2E3744", display: "block", marginBottom: 6 }}>Estado / Color</label>
                    <div style={{ display: "flex", flexWrap: "wrap", gap: 5 }}>
                      {ESTADOS_CITA.map((e) => {
                        const COLORES_PASADO = ["contrato", "cancelocontrato"];
                        let bloqueado = false;
                        if (COLORES_PASADO.includes(e.id) && citaDetalle) {
                          const horaLimite = new Date(`${citaDetalle.fecha}T${citaDetalle.hora}`);
                          horaLimite.setSeconds(horaLimite.getSeconds() - 5);
                          bloqueado = new Date() < horaLimite;
                        }
                        return (
                          <div key={e.id}
                            onClick={() => !bloqueado && setEditData({ ...editData, estadoId: e.id })}
                            title={bloqueado ? `"${e.label}" solo disponible después de que pase la hora de la cita` : ""}
                            style={{ background: bloqueado ? "#D1D5DB" : estadoBG(e), color: bloqueado ? "#6B7280" : e.text, padding: "4px 9px", borderRadius: 16, fontSize: 10, fontWeight: 700, cursor: bloqueado ? "not-allowed" : "pointer", border: editData.estadoId === e.id ? "3px solid #142B4D" : "3px solid transparent", userSelect: "none", opacity: bloqueado ? 0.5 : 1 }}>
                            {bloqueado ? "🔒 " : (editData.estadoId === e.id ? "✓ " : "")}{e.label}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                  <div style={{ marginBottom: 14 }}>
                    <label style={{ fontSize: 12, fontWeight: 600, color: "#2E3744", display: "block", marginBottom: 4 }}>Notas</label>
                    <textarea value={editData.notas} onChange={(e) => { const palabras = e.target.value.trim().split(/\s+/).filter(Boolean); if (palabras.length <= 120 || e.target.value.length < editData.notas.length) setEditData({ ...editData, notas: e.target.value }); }} rows={3} style={{ width: "100%", padding: "9px 12px", border: "1px solid #E3DECF", borderRadius: 6, fontSize: 13, resize: "none", fontFamily: "inherit" }} />
                  </div>
                  <div style={{ display: "flex", gap: 8 }}>
                    <button onClick={async () => {
                      const ts = new Date().toISOString();
                      const historialEntry = { de: citaDetalle.estadoId || "prospecto", a: editData.estadoId, fecha: ts };
                      try {
                        await guardarCitas(citas.map(c => c.id === citaDetalle.id ? { ...c, cliente: editData.cliente || c.cliente, estadoId: editData.estadoId, notas: editData.notas, historial: [...(c.historial || []), historialEntry] } : c));
                        setCitaDetalle({ ...citaDetalle, cliente: editData.cliente || citaDetalle.cliente, estadoId: editData.estadoId, notas: editData.notas });
                        setModoEdicion(false); mostrarToast("Pendiente actualizado");
                      } catch (e) { console.warn("Error al editar:", e); mostrarToast("Error al guardar. Intenta de nuevo."); }
                    }} style={{ flex: 1, padding: "9px", border: "none", borderRadius: 6, background: "#16A34A", color: "#fff", fontWeight: 700, cursor: "pointer", fontSize: 12 }}>✓ Guardar</button>
                    <button onClick={() => setModoEdicion(false)} style={{ flex: 1, padding: "9px", border: "none", borderRadius: 6, background: "#6B7280", color: "#fff", fontWeight: 700, cursor: "pointer", fontSize: 12 }}>✕ Cancelar</button>
                  </div>
                  <button onClick={async () => { if (window.confirm("¿Eliminar este pendiente?")) { try { await guardarCitas(citas.filter(c => c.id !== citaDetalle.id)); setCitaDetalle(null); mostrarToast("Pendiente eliminado"); } catch(e) { console.warn("Error al eliminar:",e); mostrarToast("Error al eliminar. Intenta de nuevo."); } } }} style={{ width: "100%", marginTop: 8, padding: "9px", border: "1px solid #EF4444", borderRadius: 6, background: "#fff", color: "#EF4444", fontWeight: 700, cursor: "pointer", fontSize: 12 }}>🗑 Eliminar pendiente</button>
                </>
              )}
            </div>
          </div>
        )}

        <div style={{ background: "#1A1A1A", color: "#fff", padding: "16px 20px" }}>
          <div style={{ maxWidth: 700, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 10 }}>
            <div>
              <div style={{ fontSize: 11, letterSpacing: 3, color: "rgba(255,255,255,0.7)", textTransform: "uppercase" }}>Autocon Management · Registro de Pendientes</div>
              <div className="display" style={{ fontSize: 18, fontWeight: 700, textTransform: "capitalize" }}>📋 {nombreDia}</div>
              {pendientesActivosDia > 0 && (
                <div style={{ fontSize: 12, color: "#F5C518", fontWeight: 700, marginTop: 2 }}>
                  ⚡ {pendientesActivosDia} pendiente{pendientesActivosDia !== 1 ? "s" : ""} activo{pendientesActivosDia !== 1 ? "s" : ""} hoy
                </div>
              )}
            </div>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
              <button onClick={() => { setMostrarCalendarioRegistro(true); setShowForm(false); }} style={{ padding: "10px 16px", border: "none", borderRadius: 6, background: "#F5C518", color: "#142B4D", cursor: "pointer", fontSize: 13, fontWeight: 700 }}>
                📅 Cambiar día
              </button>
              <button onClick={() => { setDiaSeleccionado(null); setShowForm(false); setMostrarCalendarioRegistro(false); setVistaAgenda(null); }} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: "#D6452B", color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>
            </div>
          </div>
        </div>

        <div style={{ maxWidth: 700, margin: "0 auto", padding: "20px" }}>
          {/* Botón agregar */}
          {puedeAgregar ? (
            <button onClick={() => setShowForm(!showForm)} style={{ padding: "10px 18px", border: "none", borderRadius: 6, background: "#F5C518", color: "#142B4D", cursor: "pointer", fontSize: 13, fontWeight: 700, marginBottom: 14, width: "100%" }}>
              {showForm ? "✕ Cerrar formulario" : "+ Agregar pendiente en este día"}
            </button>
          ) : (
            <div style={{ background: "#FEF3C7", border: "1px solid #F5C518", borderRadius: 8, padding: "10px 14px", marginBottom: 10, fontSize: 12, color: "#92400E", display: "flex", alignItems: "center", gap: 8 }}>
              <span style={{ fontSize: 16 }}>🔒</span>
              <span>Este día es anterior a la semana en curso. Solo puedes <strong>ver, editar, mover o eliminar</strong> pendientes existentes.</span>
            </div>
          )}

          {showForm && (
            <div style={{ background: "#F5F5F5", borderRadius: 8, padding: 16, marginBottom: 16, border: "1px solid #DDD6FE" }}>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
                <div style={{ gridColumn: "1/-1" }}>
                  <label style={{ fontSize: 12, fontWeight: 600, color: "#2E3744" }}>Nombre del cliente *</label>
                  <input value={nueva.cliente} onChange={(e) => setNueva({...nueva, cliente: e.target.value})} placeholder="Nombre completo" style={{ width: "100%", padding: "9px 12px", border: "1px solid #E3DECF", borderRadius: 4, fontSize: 14, marginTop: 4 }} />
                </div>
                <div>
                  <label style={{ fontSize: 12, fontWeight: 600, color: "#2E3744" }}>Hora *</label>
                  <select value={nueva.hora} onChange={(e) => { setNueva({...nueva, hora: e.target.value}); setErrorFranja(""); }} style={{ width: "100%", padding: "9px 12px", border: errorFranja ? "1.5px solid #D6452B" : "1px solid #E3DECF", borderRadius: 4, fontSize: 14, marginTop: 4 }}>
                    <option value="">Selecciona hora…</option>
                    {FRANJAS.map((f) => {
                      const ocupadas = citas.filter((c) => c.fecha === diaSeleccionado && c.hora === f).length;
                      const llena = ocupadas >= 4;
                      return <option key={f} value={f} disabled={llena}>{f}{llena ? " — LLENA" : ocupadas > 0 ? ` (${ocupadas}/4)` : ""}</option>;
                    })}
                  </select>
                  {errorFranja && <div style={{ fontSize: 11, color: "#D6452B", marginTop: 4, fontWeight: 600 }}>{errorFranja}</div>}
                </div>
                <div>
                  <label style={{ fontSize: 12, fontWeight: 600, color: "#2E3744" }}>Notas</label>
                  <textarea value={nueva.notas} onChange={(e) => { const palabras = e.target.value.trim().split(/\s+/).filter(Boolean); if (palabras.length <= 120 || e.target.value.length < nueva.notas.length) setNueva({...nueva, notas: e.target.value}); }} placeholder="Observaciones..." rows={2} style={{ width: "100%", padding: "9px 12px", border: "1px solid #E3DECF", borderRadius: 4, fontSize: 14, marginTop: 4, resize: "none", fontFamily: "inherit" }} />
                  {(() => { const palabras = nueva.notas.trim().split(/\s+/).filter(Boolean).length; const restantes = 120 - palabras; return (<div style={{ textAlign: "right", fontSize: 10, marginTop: 2, color: restantes <= 10 ? "#D6452B" : "#C0C0C0", fontWeight: restantes <= 10 ? 700 : 400 }}>{nueva.notas.trim() ? `${restantes} palabra${restantes !== 1 ? "s" : ""} restante${restantes !== 1 ? "s" : ""}` : "Máx. 120 palabras"}</div>); })()}
                </div>
                <div style={{ gridColumn: "1/-1" }}>
                  <label style={{ fontSize: 12, fontWeight: 600, color: "#2E3744", display: "block", marginBottom: 6 }}>Estado / Color del cliente *</label>
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
                    {ESTADOS_CITA.map((e) => {
                      const COLORES_PASADO = ["contrato", "cancelocontrato"];
                      let bloqueadoNueva = false;
                      if (COLORES_PASADO.includes(e.id) && diaSeleccionado && nueva.hora) {
                        const horaLimiteNueva = new Date(`${diaSeleccionado}T${nueva.hora}`);
                        horaLimiteNueva.setSeconds(horaLimiteNueva.getSeconds() - 5);
                        bloqueadoNueva = new Date() < horaLimiteNueva;
                      } else if (COLORES_PASADO.includes(e.id) && (!diaSeleccionado || !nueva.hora)) {
                        bloqueadoNueva = true;
                      }
                      return (
                        <div key={e.id} onClick={() => !bloqueadoNueva && setNueva({...nueva, estadoId: e.id})} title={bloqueadoNueva ? `"${e.label}" solo disponible después de que pase la hora de la cita` : ""} style={{ background: bloqueadoNueva ? "#D1D5DB" : estadoBG(e), color: bloqueadoNueva ? "#6B7280" : e.text, padding: "5px 10px", borderRadius: 20, fontSize: 11, fontWeight: 700, cursor: bloqueadoNueva ? "not-allowed" : "pointer", border: nueva.estadoId === e.id ? "3px solid #142B4D" : "3px solid transparent", boxShadow: nueva.estadoId === e.id ? "0 0 0 2px #fff inset" : "none", transition: "all 0.15s", userSelect: "none", opacity: bloqueadoNueva ? 0.5 : 1 }}>
                          {bloqueadoNueva ? "🔒 " : (nueva.estadoId === e.id ? "✓ " : "")}{e.label}
                        </div>
                      );
                    })}
                  </div>
                </div>
              </div>
              <button onClick={agregarCita} disabled={guardando || !nueva.cliente || !nueva.hora} style={{ background: "#1A1A1A", color: "#fff", border: "none", borderRadius: 6, padding: "10px 16px", fontWeight: 700, cursor: "pointer", width: "100%", fontSize: 14, marginTop: 12 }}>
                {guardando ? "Guardando…" : "✓ Guardar pendiente"}
              </button>
            </div>
          )}

          {/* Leyenda */}
          <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 12 }}>
            {ESTADOS_CITA.map((e) => (
              <div key={e.id} style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 10, color: "#6B7280" }}>
                <div style={{ width: 12, height: 12, borderRadius: 3, background: estadoBG(e), flexShrink: 0 }} />
                {e.label}
              </div>
            ))}
          </div>

          {/* Modal mover cita */}
          {moviendoCita && (
            <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.6)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
              <div style={{ background: "#fff", borderRadius: 10, padding: 24, maxWidth: 400, width: "100%", boxShadow: "0 8px 32px rgba(0,0,0,0.3)" }}>
                {!moverConfirm ? (
                  <>
                    <div style={{ fontSize: 17, fontWeight: 700, color: "#142B4D", marginBottom: 4 }}>🔄 Mover cita</div>
                    <div style={{ fontSize: 13, color: "#6B7280", marginBottom: 16 }}>Cliente: <strong>{moviendoCita.cliente}</strong><br />Actualmente: {moviendoCita.fecha} · {moviendoCita.hora}</div>
                    <div style={{ display: "flex", flexDirection: "column", gap: 12, marginBottom: 16 }}>
                      <div>
                        <label style={{ fontSize: 12, fontWeight: 600, color: "#2E3744", display: "block", marginBottom: 4 }}>Nueva fecha *</label>
                        <input type="date" value={moverData.fecha} onChange={(e) => setMoverData({ ...moverData, fecha: e.target.value })} min={`${anio}-01-01`} max={`${anio}-12-31`} style={{ width: "100%", padding: "9px 12px", border: "1px solid #E3DECF", borderRadius: 6, fontSize: 14 }} />
                      </div>
                      <div>
                        <label style={{ fontSize: 12, fontWeight: 600, color: "#2E3744", display: "block", marginBottom: 4 }}>Nueva hora *</label>
                        <select value={moverData.hora} onChange={(e) => setMoverData({ ...moverData, hora: e.target.value })} style={{ width: "100%", padding: "9px 12px", border: "1px solid #E3DECF", borderRadius: 6, fontSize: 14 }}>
                          <option value="">Selecciona hora…</option>
                          {FRANJAS.map((f) => { const ocupadas = citas.filter((c) => c.fecha === moverData.fecha && c.hora === f && c.id !== moviendoCita.id).length; const llena = ocupadas >= 4; return <option key={f} value={f} disabled={llena}>{f}{llena ? " — LLENA" : ocupadas > 0 ? ` (${ocupadas}/4)` : ""}</option>; })}
                        </select>
                      </div>
                    </div>
                    <div style={{ display: "flex", gap: 8 }}>
                      <button onClick={() => { if (moverData.fecha && moverData.hora) setMoverConfirm(true); }} disabled={!moverData.fecha || !moverData.hora} style={{ flex: 1, padding: "10px", border: "none", borderRadius: 6, background: moverData.fecha && moverData.hora ? "#F5C518" : "#E5E7EB", color: moverData.fecha && moverData.hora ? "#142B4D" : "#9CA3AF", fontWeight: 700, cursor: moverData.fecha && moverData.hora ? "pointer" : "not-allowed", fontSize: 13 }}>Confirmar →</button>
                      <button onClick={() => { setMoviendoCita(null); setMoverData({ fecha: "", hora: "" }); setMoverConfirm(false); }} style={{ flex: 1, padding: "10px", border: "none", borderRadius: 6, background: "#6B7280", color: "#fff", fontWeight: 700, cursor: "pointer", fontSize: 13 }}>Cancelar</button>
                    </div>
                  </>
                ) : (
                  <>
                    <div style={{ fontSize: 16, fontWeight: 700, color: "#142B4D", marginBottom: 12 }}>¿Confirmar movimiento?</div>
                    <div style={{ fontSize: 13, color: "#6B7280", marginBottom: 16 }}>
                      <strong>{moviendoCita.cliente}</strong><br />
                      De: {moviendoCita.fecha} · {moviendoCita.hora}<br />
                      A: {moverData.fecha} · {moverData.hora}
                    </div>
                    <div style={{ display: "flex", gap: 8 }}>
                      <button onClick={async () => {
                        try {
                          await guardarCitas(citas.map(c => c.id === moviendoCita.id ? { ...c, fecha: moverData.fecha, hora: moverData.hora } : c));
                          setMoviendoCita(null); setMoverData({ fecha: "", hora: "" }); setMoverConfirm(false);
                          mostrarToast("Cita movida correctamente");
                          setDiaSeleccionado(null);
                          requestAnimationFrame(() => setDiaSeleccionado(moverData.fecha));
                        } catch(e) { console.warn("Error al mover:",e); mostrarToast("Error al mover. Intenta de nuevo."); }
                      }} style={{ flex: 1, padding: "10px", border: "none", borderRadius: 6, background: "#16A34A", color: "#fff", fontWeight: 700, cursor: "pointer", fontSize: 13 }}>✓ Mover</button>
                      <button onClick={() => setMoverConfirm(false)} style={{ flex: 1, padding: "10px", border: "none", borderRadius: 6, background: "#6B7280", color: "#fff", fontWeight: 700, cursor: "pointer", fontSize: 13 }}>← Editar</button>
                    </div>
                  </>
                )}
              </div>
            </div>
          )}

        </div>
      </div>
    );
  }

  // ── VISTA: Pendientes de Hoy ──
  if (vistaAgenda === "pendientes-hoy") {
    const pendientesRestantes = Math.max(0, citasHoy.length - finalizadosHoy.size);
    const fechaLargaHoy = new Date(hoy + "T12:00:00").toLocaleDateString("es-MX", { weekday: "long", day: "numeric", month: "long", year: "numeric" });

    return (
      <div style={{ minHeight: "100vh", background: "#FFFBEB" }}>

        {/* Modal: pendientes vencidos sin marcar */}
        {alertaVencidos && (
          <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.65)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
            <div style={{ background: "#fff", borderRadius: 14, padding: 28, maxWidth: 340, width: "100%", boxShadow: "0 12px 40px rgba(0,0,0,0.4)", textAlign: "center" }}>
              <div style={{ fontSize: 38, marginBottom: 12 }}>⚠️</div>
              <div className="display" style={{ fontSize: 16, fontWeight: 800, color: "#142B4D", marginBottom: 10, lineHeight: 1.4 }}>
                Revise su lista de pendientes hoy. Hay pendientes activos cuyo horario ya se cumplió.
              </div>
              <button
                onClick={() => setAlertaVencidos(false)}
                style={{ marginTop: 8, width: "100%", padding: "13px", border: "none", borderRadius: 8, background: "#F5C518", color: "#142B4D", fontWeight: 800, fontSize: 15, cursor: "pointer" }}
              >
                ✓ Aceptar
              </button>
            </div>
          </div>
        )}

        {/* Modal: ver nota */}
        {notaVisible && (() => {
          const cNota = citasHoy.find(c => c.id === notaVisible);
          return cNota ? (
            <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.6)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
              <div style={{ background: "#fff", borderRadius: 14, padding: 26, maxWidth: 340, width: "100%", boxShadow: "0 12px 40px rgba(0,0,0,0.35)" }}>
                <div style={{ fontSize: 13, fontWeight: 700, color: "#6B7280", marginBottom: 6, textTransform: "uppercase", letterSpacing: 1 }}>📝 Nota — {cNota.cliente}</div>
                <div style={{ fontSize: 14, color: "#142B4D", lineHeight: 1.6, marginBottom: 20 }}>{cNota.notas}</div>
                <button onClick={() => setNotaVisible(null)} style={{ width: "100%", padding: "12px", border: "none", borderRadius: 8, background: "#1A1A1A", color: "#fff", fontWeight: 800, fontSize: 14, cursor: "pointer" }}>
                  ✓ Aceptar
                </button>
              </div>
            </div>
          ) : null;
        })()}

        {/* Modal: confirmar finalizar */}
        {confirmFinalizar && (
          <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.6)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
            <div style={{ background: "#fff", borderRadius: 14, padding: 28, maxWidth: 340, width: "100%", boxShadow: "0 12px 40px rgba(0,0,0,0.35)", textAlign: "center" }}>
              <div style={{ fontSize: 36, marginBottom: 12 }}>✅</div>
              <div className="display" style={{ fontSize: 17, fontWeight: 800, color: "#142B4D", marginBottom: 8 }}>
                ¿Gusta finalizar esta actividad?
              </div>
              <div style={{ fontSize: 13, color: "#6B7280", marginBottom: 22 }}>
                El pendiente seguirá en la agenda pero se descontará del contador de hoy.
              </div>
              <div style={{ display: "flex", gap: 10 }}>
                <button onClick={() => { marcarFinalizado(confirmFinalizar); setConfirmFinalizar(null); }} style={{ flex: 1, padding: "12px", border: "none", borderRadius: 8, background: "#16A34A", color: "#fff", fontWeight: 800, fontSize: 14, cursor: "pointer" }}>
                  ✓ Aceptar
                </button>
                <button onClick={() => setConfirmFinalizar(null)} style={{ flex: 1, padding: "12px", border: "none", borderRadius: 8, background: "#6B7280", color: "#fff", fontWeight: 700, fontSize: 14, cursor: "pointer" }}>
                  Cancelar
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Modal: confirmar reactivar */}
        {confirmReactivar && (
          <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.6)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
            <div style={{ background: "#fff", borderRadius: 14, padding: 28, maxWidth: 340, width: "100%", boxShadow: "0 12px 40px rgba(0,0,0,0.35)", textAlign: "center" }}>
              <div style={{ fontSize: 36, marginBottom: 12 }}>🔄</div>
              <div className="display" style={{ fontSize: 17, fontWeight: 800, color: "#142B4D", marginBottom: 8 }}>
                ¿Gusta reactivar esta actividad?
              </div>
              <div style={{ fontSize: 13, color: "#6B7280", marginBottom: 22 }}>
                El pendiente volverá al contador de hoy.
              </div>
              <div style={{ display: "flex", gap: 10 }}>
                <button onClick={() => { reactivarPendiente(confirmReactivar); setConfirmReactivar(null); }} style={{ flex: 1, padding: "12px", border: "none", borderRadius: 8, background: "#F5C518", color: "#142B4D", fontWeight: 800, fontSize: 14, cursor: "pointer" }}>
                  ✓ Aceptar
                </button>
                <button onClick={() => setConfirmReactivar(null)} style={{ flex: 1, padding: "12px", border: "none", borderRadius: 8, background: "#6B7280", color: "#fff", fontWeight: 700, fontSize: 14, cursor: "pointer" }}>
                  Cancelar
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Modal: editar pendiente desde Pendientes de Hoy */}
        {editandoHoy && (() => {
          const COLORES_PASADO = ["contrato", "cancelocontrato"];
          const palabrasNota = (editandoHoy.notas || "").trim().split(/\s+/).filter(Boolean).length;
          const restantesNota = 120 - palabrasNota;
          return (
            <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.65)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center", padding: 16, overflowY: "auto" }}>
              <div style={{ background: "#fff", borderRadius: 14, padding: 24, maxWidth: 400, width: "100%", boxShadow: "0 12px 40px rgba(0,0,0,0.4)" }}>
                <div className="display" style={{ fontSize: 16, fontWeight: 800, color: "#142B4D", marginBottom: 16 }}>✏️ Editar pendiente</div>

                {/* Nombre */}
                <div style={{ marginBottom: 12 }}>
                  <label style={{ fontSize: 12, fontWeight: 700, color: "#2E3744", display: "block", marginBottom: 4 }}>Nombre del cliente *</label>
                  <input
                    value={editandoHoy.cliente}
                    onChange={(e) => setEditandoHoy({ ...editandoHoy, cliente: e.target.value })}
                    style={{ width: "100%", padding: "9px 12px", border: "1px solid #E3DECF", borderRadius: 6, fontSize: 14, boxSizing: "border-box" }}
                  />
                </div>

                {/* Hora */}
                <div style={{ marginBottom: 12 }}>
                  <label style={{ fontSize: 12, fontWeight: 700, color: "#2E3744", display: "block", marginBottom: 4 }}>Horario *</label>
                  <select
                    value={editandoHoy.hora}
                    onChange={(e) => setEditandoHoy({ ...editandoHoy, hora: e.target.value })}
                    style={{ width: "100%", padding: "9px 12px", border: "1px solid #E3DECF", borderRadius: 6, fontSize: 14 }}
                  >
                    {FRANJAS.map((f) => {
                      const ocupadas = citas.filter((c) => c.fecha === hoy && c.hora === f && c.id !== editandoHoy.id).length;
                      const llena = ocupadas >= 4;
                      return <option key={f} value={f} disabled={llena}>{f}{llena ? " — LLENA" : ocupadas > 0 ? ` (${ocupadas}/4)` : ""}</option>;
                    })}
                  </select>
                </div>

                {/* Notas */}
                <div style={{ marginBottom: 12 }}>
                  <label style={{ fontSize: 12, fontWeight: 700, color: "#2E3744", display: "block", marginBottom: 4 }}>Notas</label>
                  <textarea
                    value={editandoHoy.notas}
                    onChange={(e) => {
                      const palabras = e.target.value.trim().split(/\s+/).filter(Boolean);
                      if (palabras.length <= 120 || e.target.value.length < (editandoHoy.notas || "").length)
                        setEditandoHoy({ ...editandoHoy, notas: e.target.value });
                    }}
                    rows={3}
                    placeholder="Observaciones..."
                    style={{ width: "100%", padding: "9px 12px", border: "1px solid #E3DECF", borderRadius: 6, fontSize: 13, resize: "none", fontFamily: "inherit", boxSizing: "border-box" }}
                  />
                  <div style={{ textAlign: "right", fontSize: 10, marginTop: 2, color: restantesNota <= 10 ? "#D6452B" : "#C0C0C0", fontWeight: restantesNota <= 10 ? 700 : 400 }}>
                    {editandoHoy.notas?.trim() ? `${restantesNota} palabra${restantesNota !== 1 ? "s" : ""} restante${restantesNota !== 1 ? "s" : ""}` : "Máx. 120 palabras"}
                  </div>
                </div>

                {/* Paleta de colores */}
                <div style={{ marginBottom: 18 }}>
                  <label style={{ fontSize: 12, fontWeight: 700, color: "#2E3744", display: "block", marginBottom: 6 }}>Estado / Color *</label>
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
                    {ESTADOS_CITA.map((e) => {
                      let bloqueado = false;
                      if (COLORES_PASADO.includes(e.id)) {
                        const horaLimite = new Date(`${hoy}T${editandoHoy.hora}`);
                        horaLimite.setSeconds(horaLimite.getSeconds() - 5);
                        bloqueado = new Date() < horaLimite;
                      }
                      return (
                        <div
                          key={e.id}
                          onClick={() => !bloqueado && setEditandoHoy({ ...editandoHoy, estadoId: e.id })}
                          title={bloqueado ? `"${e.label}" disponible solo después de que pase la hora` : ""}
                          style={{
                            background: bloqueado ? "#D1D5DB" : estadoBG(e),
                            color: bloqueado ? "#6B7280" : e.text,
                            padding: "5px 10px", borderRadius: 20, fontSize: 11, fontWeight: 700,
                            cursor: bloqueado ? "not-allowed" : "pointer",
                            border: editandoHoy.estadoId === e.id ? "3px solid #142B4D" : "3px solid transparent",
                            boxShadow: editandoHoy.estadoId === e.id ? "0 0 0 2px #fff inset" : "none",
                            userSelect: "none", opacity: bloqueado ? 0.5 : 1, transition: "all 0.15s",
                          }}
                        >
                          {bloqueado ? "🔒 " : editandoHoy.estadoId === e.id ? "✓ " : ""}{e.label}
                        </div>
                      );
                    })}
                  </div>
                </div>

                {/* Botones */}
                <div style={{ display: "flex", gap: 10 }}>
                  <button
                    onClick={async () => {
                      if (!editandoHoy.cliente.trim()) return;
                      const ts = new Date().toISOString();
                      const orig = citas.find(c => c.id === editandoHoy.id);
                      const historialEntry = { de: orig?.estadoId || "prospecto", a: editandoHoy.estadoId, fecha: ts };
                      try {
                        await guardarCitas(citas.map(c => c.id === editandoHoy.id
                          ? { ...c, cliente: editandoHoy.cliente, hora: editandoHoy.hora, notas: editandoHoy.notas, estadoId: editandoHoy.estadoId, historial: [...(c.historial || []), historialEntry] }
                          : c
                        ));
                        mostrarToast("Pendiente actualizado");
                      } catch(err) { mostrarToast("Error al guardar. Intenta de nuevo."); }
                      setEditandoHoy(null);
                    }}
                    disabled={!editandoHoy.cliente.trim()}
                    style={{ flex: 1, padding: "12px", border: "none", borderRadius: 8, background: editandoHoy.cliente.trim() ? "#16A34A" : "#E5E7EB", color: editandoHoy.cliente.trim() ? "#fff" : "#9CA3AF", fontWeight: 800, fontSize: 14, cursor: editandoHoy.cliente.trim() ? "pointer" : "not-allowed" }}
                  >
                    ✓ Guardar
                  </button>
                  <button
                    onClick={() => setEditandoHoy(null)}
                    style={{ flex: 1, padding: "12px", border: "none", borderRadius: 8, background: "#6B7280", color: "#fff", fontWeight: 700, fontSize: 14, cursor: "pointer" }}
                  >
                    Cancelar
                  </button>
                </div>
                <button
                  onClick={async () => {
                    if (!window.confirm("¿Eliminar este pendiente? Esta acción no se puede deshacer.")) return;
                    try {
                      await guardarCitas(citas.filter(c => c.id !== editandoHoy.id));
                      mostrarToast("Pendiente eliminado");
                    } catch { mostrarToast("Error al eliminar. Intenta de nuevo."); }
                    setEditandoHoy(null);
                  }}
                  style={{ width: "100%", marginTop: 10, padding: "10px", border: "1px solid #EF4444", borderRadius: 8, background: "#fff", color: "#EF4444", fontWeight: 700, fontSize: 13, cursor: "pointer" }}
                >
                  🗑 Eliminar pendiente
                </button>
              </div>
            </div>
          );
        })()}

        {/* TopBar amarillo */}
        <div style={{ background: "#F5C518", padding: "16px 20px" }}>
          <div style={{ maxWidth: 700, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div>
              <div style={{ fontSize: 11, letterSpacing: 3, color: "rgba(0,0,0,0.45)", textTransform: "uppercase" }}>Autocon Management · Agenda Virtual</div>
              <div className="display" style={{ fontSize: 19, fontWeight: 800, color: "#142B4D" }}>⌚ PENDIENTES DE HOY</div>
              <div style={{ fontSize: 12, color: "#142B4D", opacity: 0.65, marginTop: 1, textTransform: "capitalize" }}>{fechaLargaHoy}</div>
            </div>
            <button onClick={() => setVistaAgenda(null)} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: "#1A1A1A", color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>
          </div>
        </div>

        {/* Número grande */}
        <div style={{ background: "#F5C518", paddingBottom: 24, textAlign: "center" }}>
          <div style={{ fontSize: 96, fontWeight: 900, color: "#142B4D", lineHeight: 1, fontFamily: "Oswald, sans-serif", letterSpacing: -4 }}>
            {pendientesRestantes}
          </div>
          <div style={{ fontSize: 13, fontWeight: 700, color: "#142B4D", opacity: 0.65, marginTop: 4, letterSpacing: 1, textTransform: "uppercase" }}>
            pendiente{pendientesRestantes !== 1 ? "s" : ""} activo{pendientesRestantes !== 1 ? "s" : ""}
          </div>
        </div>

        {/* Lista de pendientes */}
        <div style={{ maxWidth: 700, margin: "0 auto", padding: "20px 16px" }}>
          {citasHoy.length === 0 ? (
            <div style={{ textAlign: "center", color: "#9CA3AF", padding: "40px 0", fontSize: 15 }}>
              <div style={{ fontSize: 40, marginBottom: 12 }}>📭</div>
              No hay pendientes registrados para hoy.
            </div>
          ) : (
            <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
              {citasHoy
                .slice()
                .sort((a, b) => a.hora.localeCompare(b.hora))
                .map((c) => {
                  const estado = ESTADOS_CITA.find((e) => e.id === (c.estadoId || "prospecto")) || ESTADOS_CITA[0];
                  const finalizado = finalizadosHoy.has(c.id);
                  return (
                    <div
                      key={c.id}
                      style={{
                        background: finalizado ? "#F0FDF4" : "#fff",
                        border: finalizado ? "2px solid #86EFAC" : `2px solid ${estado.color}`,
                        borderRadius: 12,
                        padding: "12px 14px",
                        display: "flex",
                        flexDirection: "column",
                        gap: 10,
                        opacity: finalizado ? 0.7 : 1,
                        transition: "all 0.2s",
                        boxShadow: "0 1px 6px rgba(0,0,0,0.07)",
                      }}
                    >
                      {/* Fila 1: checkbox + nombre + hora (el nombre SIEMPRE tiene espacio garantizado) */}
                      <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                        {/* Celdita checkbox — finalizar o reactivar */}
                        <div
                          onClick={() => finalizado ? setConfirmReactivar(c.id) : setConfirmFinalizar(c.id)}
                          title={finalizado ? "Toca para reactivar" : "Toca para finalizar"}
                          style={{
                            width: 28, height: 28, borderRadius: 6, flexShrink: 0,
                            border: finalizado ? "2px solid #16A34A" : "2px solid #D1D5DB",
                            background: finalizado ? "#16A34A" : "#fff",
                            display: "flex", alignItems: "center", justifyContent: "center",
                            cursor: "pointer",
                            transition: "all 0.2s",
                            fontSize: 16, fontWeight: 900, color: "#fff",
                          }}
                        >
                          {finalizado ? "✓" : ""}
                        </div>

                        {/* Dot de color */}
                        <div style={{ width: 12, height: 12, borderRadius: "50%", background: estadoBG(estado), flexShrink: 0 }} />

                        {/* Info — sin notas visibles */}
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <div style={{
                            fontWeight: 700, fontSize: 15, color: "#142B4D",
                            textDecoration: finalizado ? "line-through" : "none",
                            whiteSpace: "normal", wordBreak: "break-word",
                          }}>
                            {c.cliente}
                          </div>
                          <div style={{ fontSize: 12, color: "#6B7280", marginTop: 2 }}>
                            ⏰ {c.hora}
                          </div>
                        </div>
                      </div>

                      {/* Fila 2: acciones (NOTA / EDITAR / estado) — en su propia fila, ya no le quitan espacio al nombre */}
                      <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap", paddingLeft: 40 }}>
                        {/* Botón NOTA (solo si tiene notas) */}
                        {c.notas && (
                          <button
                            onClick={() => setNotaVisible(c.id)}
                            style={{
                              padding: "3px 9px", border: "1px solid #D1D5DB",
                              borderRadius: 8, background: "#F8FAFC",
                              color: "#6B7280", fontSize: 10, fontWeight: 700,
                              cursor: "pointer", flexShrink: 0, whiteSpace: "nowrap",
                            }}
                          >
                            📝 NOTA
                          </button>
                        )}

                        {/* Botón EDITAR */}
                        <button
                          onClick={() => setEditandoHoy({ id: c.id, cliente: c.cliente, hora: c.hora, notas: c.notas || "", estadoId: c.estadoId || "prospecto" })}
                          style={{
                            padding: "3px 9px", border: "1px solid #D1D5DB",
                            borderRadius: 8, background: "#F8FAFC",
                            color: "#2563EB", fontSize: 10, fontWeight: 700,
                            cursor: "pointer", flexShrink: 0, whiteSpace: "nowrap",
                          }}
                        >
                          ✏️ EDITAR
                        </button>

                        {/* Badge estado */}
                        <div style={{
                          background: estadoBG(estado), color: estado.text,
                          borderRadius: 10, padding: "3px 10px",
                          fontSize: 10, fontWeight: 700, whiteSpace: "nowrap", flexShrink: 0,
                        }}>
                          {estado.label}
                        </div>
                      </div>
                    </div>
                  );
                })
              }
            </div>
          )}

          {/* Resumen al pie */}
          {citasHoy.length > 0 && (
            <div style={{ marginTop: 20, background: "#fff", borderRadius: 10, padding: "12px 16px", border: "1px solid #E5E7EB", fontSize: 12, color: "#6B7280", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <span>Total del día: <strong style={{ color: "#142B4D" }}>{citasHoy.length}</strong></span>
              <span>Finalizados: <strong style={{ color: "#16A34A" }}>{finalizadosHoy.size}</strong></span>
              <span>Pendientes: <strong style={{ color: "#C0392B" }}>{pendientesRestantes}</strong></span>
            </div>
          )}
        </div>
      </div>
    );
  }

  // ── VISTA: Pendientes Semanal ──
  if (vistaAgenda === "pendientes-semana") {
    const fmt = (d) => new Date(d + "T12:00:00").toLocaleDateString("es-MX", { day: "numeric", month: "long" });
    const DIAS_ABREV = ["Dom","Lun","Mar","Mié","Jue","Vie","Sáb"];
    const COLORES_DIA = ["#6366F1","#0EA5E9","#10B981","#F59E0B","#EF4444","#EC4899","#8B5CF6"];
    const ahora = new Date();

    // Si hay día seleccionado, mostrar detalle completo de ese día (00:00–23:30)
    if (diaDetalleSemana) {
      const fechaObj = new Date(diaDetalleSemana + "T12:00:00");
      const nombreDiaLargo = fechaObj.toLocaleDateString("es-MX", { weekday: "long", day: "numeric", month: "long" });
      const esPasado = diaDetalleSemana < hoy;
      const citasDia = citas.filter(c => c.fecha === diaDetalleSemana);
      const diaIdx = fechaObj.getDay();
      const colorDia = COLORES_DIA[diaIdx];
      const tieneMadrugada = citasDia.some(c => parseInt(c.hora) < 7);
      const tieneNocheAlta = citasDia.some(c => parseInt(c.hora) >= 19);

      const DetalleDiaView = () => {
        const [verMadrugada, setVerMadrugada] = React.useState(tieneMadrugada);
        const [verNocheAlta, setVerNocheAlta] = React.useState(tieneNocheAlta);
        const franjasVisibles = FRANJAS.filter(f => {
          const h = parseInt(f);
          if (h < 7) return verMadrugada;
          if (h >= 19) return verNocheAlta;
          return true;
        });
        const ctMadrugada = citasDia.filter(c => parseInt(c.hora) < 7).length;
        const ctNoche = citasDia.filter(c => parseInt(c.hora) >= 19).length;

        return (
          <div style={{ minHeight: "100vh", background: "#F8FAFC" }}>
            {/* TopBar */}
            <div style={{ background: colorDia, padding: "16px 20px" }}>
              <div style={{ maxWidth: 700, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <div>
                  <div style={{ fontSize: 11, letterSpacing: 3, color: "rgba(255,255,255,0.7)", textTransform: "uppercase" }}>Agenda Semanal</div>
                  <div className="display" style={{ fontSize: 19, fontWeight: 800, color: "#fff", textTransform: "capitalize" }}>{nombreDiaLargo}</div>
                  {esPasado && <div style={{ fontSize: 11, color: "rgba(255,255,255,0.8)", marginTop: 2, background: "rgba(0,0,0,0.2)", borderRadius: 6, padding: "2px 8px", display: "inline-block" }}>Día pasado</div>}
                </div>
                <button onClick={() => setDiaDetalleSemana(null)} style={{ padding: "10px 20px", border: "none", borderRadius: 6, background: "rgba(0,0,0,0.3)", color: "#fff", cursor: "pointer", fontSize: 14, fontWeight: 700 }}>Salir</button>
              </div>
            </div>

            <div style={{ maxWidth: 700, margin: "0 auto", padding: "12px 16px" }}>
              {/* Toggle madrugada */}
              <div onClick={() => setVerMadrugada(v => !v)} style={{ display: "flex", alignItems: "center", gap: 8, padding: "8px 12px", background: "#fff", borderRadius: 8, border: "1px solid #E5E7EB", cursor: "pointer", marginBottom: 8, userSelect: "none" }}>
                <span style={{ fontSize: 13, color: colorDia }}>{verMadrugada ? "▲" : "▼"}</span>
                <span style={{ fontSize: 12, fontWeight: 700, color: "#6B7280", flex: 1 }}>Madrugada 00:00 – 06:30</span>
                {ctMadrugada > 0 && <span style={{ fontSize: 10, background: colorDia, color: "#fff", borderRadius: 10, padding: "2px 8px", fontWeight: 700 }}>{ctMadrugada} cita{ctMadrugada !== 1 ? "s" : ""}</span>}
              </div>

              {franjasVisibles.map((franja) => {
                const h = parseInt(franja);
                const citasFranja = citasDia.filter(c => c.hora === franja);
                const franjaObj = new Date(`${diaDetalleSemana}T${franja}:00`);
                const pasadaUnaHora = diaDetalleSemana === hoy && (ahora - franjaObj) > 60 * 60 * 1000;
                const esInicioNoche = h === 19 && franja === "19:00";

                return (
                  <React.Fragment key={franja}>
                    {esInicioNoche && (
                      <div onClick={() => setVerNocheAlta(v => !v)} style={{ display: "flex", alignItems: "center", gap: 8, padding: "8px 12px", background: "#fff", borderRadius: 8, border: "1px solid #E5E7EB", cursor: "pointer", margin: "8px 0", userSelect: "none" }}>
                        <span style={{ fontSize: 13, color: colorDia }}>▲</span>
                        <span style={{ fontSize: 12, fontWeight: 700, color: "#6B7280", flex: 1 }}>Noche 19:00 – 23:30</span>
                        {ctNoche > 0 && <span style={{ fontSize: 10, background: colorDia, color: "#fff", borderRadius: 10, padding: "2px 8px", fontWeight: 700 }}>{ctNoche} cita{ctNoche !== 1 ? "s" : ""}</span>}
                      </div>
                    )}
                    <div style={{ display: "flex", gap: 8, marginBottom: citasFranja.length > 0 ? 6 : 1, alignItems: "flex-start" }}>
                      <div style={{ width: 52, flexShrink: 0, textAlign: "right", paddingTop: 8, fontSize: 14, fontWeight: 700, color: citasFranja.length > 0 ? colorDia : "#94A3B8", letterSpacing: 0.3 }}>{franja}</div>
                      <div style={{ flex: 1 }}>
                        {citasFranja.length === 0 ? (
                          <div style={{ height: 1, background: "#F0F0F0", marginTop: 12 }} />
                        ) : (
                          <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 4 }}>
                            {citasFranja.slice(0, 4).map(c => {
                              const estado = ESTADOS_CITA.find(e => e.id === (c.estadoId || "prospecto")) || ESTADOS_CITA[0];
                              const finalizado = finalizadosHoy.has(c.id);
                              return (
                                <div key={c.id}
                                  onClick={() => setEditSemana({ id: c.id, cliente: c.cliente, hora: c.hora, notas: c.notas || "", estadoId: c.estadoId || "prospecto", fechaOrig: c.fecha })}
                                  style={{ background: finalizado ? "#F0FDF4" : "#fff", border: `2px solid ${finalizado ? "#86EFAC" : estado.color}`, borderTop: `4px solid ${colorDia}`, borderRadius: 8, padding: "6px 7px", opacity: (pasadaUnaHora || esPasado) && !finalizado ? 0.5 : 1, boxShadow: "0 1px 4px rgba(0,0,0,0.07)", cursor: "pointer", transition: "transform 0.1s" }}
                                  onMouseOver={e => e.currentTarget.style.transform = "scale(1.03)"}
                                  onMouseOut={e => e.currentTarget.style.transform = "scale(1)"}
                                >
                                  <div style={{ display: "flex", alignItems: "center", gap: 4, marginBottom: 2 }}>
                                    <div style={{ width: 8, height: 8, borderRadius: "50%", background: estadoBG(estado), flexShrink: 0 }} />
                                    {finalizado && <span style={{ fontSize: 9, color: "#16A34A", fontWeight: 900 }}>✓</span>}
                                  </div>
                                  <div style={{ fontSize: 10, fontWeight: 700, color: "#142B4D", textDecoration: finalizado ? "line-through" : "none", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{c.cliente}</div>
                                  <div style={{ background: estadoBG(estado), color: estado.text, borderRadius: 6, padding: "1px 4px", fontSize: 8, fontWeight: 700, display: "inline-block", marginTop: 3, whiteSpace: "nowrap" }}>{estado.label}</div>
                                </div>
                              );
                            })}
                            {Array.from({ length: Math.max(0, 4 - citasFranja.length) }).map((_, i) => (
                              <div key={`empty-${i}`} style={{ borderRadius: 8, border: "1.5px dashed #E5E7EB", minHeight: 52, opacity: 0.35 }} />
                            ))}
                          </div>
                        )}
                      </div>
                    </div>
                  </React.Fragment>
                );
              })}

              {!verNocheAlta && (
                <div onClick={() => setVerNocheAlta(true)} style={{ display: "flex", alignItems: "center", gap: 8, padding: "8px 12px", background: "#fff", borderRadius: 8, border: "1px solid #E5E7EB", cursor: "pointer", marginTop: 8, userSelect: "none" }}>
                  <span style={{ fontSize: 13, color: colorDia }}>▼</span>
                  <span style={{ fontSize: 12, fontWeight: 700, color: "#6B7280", flex: 1 }}>Noche 19:00 – 23:30</span>
                  {ctNoche > 0 && <span style={{ fontSize: 10, background: colorDia, color: "#fff", borderRadius: 10, padding: "2px 8px", fontWeight: 700 }}>{ctNoche} cita{ctNoche !== 1 ? "s" : ""}</span>}
                </div>
              )}

              {citasDia.length === 0 && (
                <div style={{ textAlign: "center", color: "#9CA3AF", padding: "40px 0", fontSize: 14 }}>
                  <div style={{ fontSize: 36, marginBottom: 10 }}>📭</div>
                  Sin pendientes registrados este día.
                </div>
              )}
            </div>
          </div>
        );
      };

      const COLORES_PASADO_SEM = ["contrato", "cancelocontrato"];
      return (
        <>
          {/* ── Modal editar pendiente (fuera de DetalleDiaView para evitar re-mount) ── */}
          {editSemana && (() => {
            const palabrasNota = (editSemana.notas || "").trim().split(/\s+/).filter(Boolean).length;
            const restantes = 120 - palabrasNota;
            return (
              <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.65)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center", padding: 16, overflowY: "auto" }}>
                <div style={{ background: "#fff", borderRadius: 14, padding: 22, maxWidth: 400, width: "100%", boxShadow: "0 12px 40px rgba(0,0,0,0.4)", maxHeight: "90vh", overflowY: "auto" }}>
                  <div className="display" style={{ fontSize: 15, fontWeight: 800, color: "#142B4D", marginBottom: 16 }}>✏️ Editar pendiente</div>

                  {/* Nombre */}
                  <div style={{ marginBottom: 12 }}>
                    <label style={{ fontSize: 11, fontWeight: 700, color: "#6B7280", display: "block", marginBottom: 4, textTransform: "uppercase", letterSpacing: 0.5 }}>Nombre</label>
                    <input
                      value={editSemana.cliente}
                      onChange={e => setEditSemana({ ...editSemana, cliente: e.target.value })}
                      style={{ width: "100%", padding: "10px 12px", border: "1.5px solid #E3DECF", borderRadius: 8, fontSize: 14, boxSizing: "border-box", outline: "none" }}
                    />
                  </div>

                  {/* Nota */}
                  <div style={{ marginBottom: 12 }}>
                    <label style={{ fontSize: 11, fontWeight: 700, color: "#6B7280", display: "block", marginBottom: 4, textTransform: "uppercase", letterSpacing: 0.5 }}>Nota</label>
                    <textarea
                      value={editSemana.notas}
                      onChange={e => {
                        const p = e.target.value.trim().split(/\s+/).filter(Boolean);
                        if (p.length <= 120 || e.target.value.length < (editSemana.notas || "").length)
                          setEditSemana({ ...editSemana, notas: e.target.value });
                      }}
                      rows={3} placeholder="Observaciones..."
                      style={{ width: "100%", padding: "10px 12px", border: "1.5px solid #E3DECF", borderRadius: 8, fontSize: 13, resize: "none", fontFamily: "inherit", boxSizing: "border-box", outline: "none" }}
                    />
                    <div style={{ textAlign: "right", fontSize: 10, marginTop: 2, color: restantes <= 10 ? "#D6452B" : "#C0C0C0", fontWeight: restantes <= 10 ? 700 : 400 }}>
                      {editSemana.notas?.trim() ? `${restantes} palabra${restantes !== 1 ? "s" : ""} restante${restantes !== 1 ? "s" : ""}` : "Máx. 120 palabras"}
                    </div>
                  </div>

                  {/* Día de la semana */}
                  <div style={{ marginBottom: 12 }}>
                    <label style={{ fontSize: 11, fontWeight: 700, color: "#6B7280", display: "block", marginBottom: 6, textTransform: "uppercase", letterSpacing: 0.5 }}>Día de la semana</label>
                    <div style={{ display: "flex", gap: 4 }}>
                      {semanaActual.map(fecha => {
                        const fo = new Date(fecha + "T12:00:00");
                        const ABREV = ["Dom","Lun","Mar","Mié","Jue","Vie","Sáb"];
                        const selec = editSemana.fechaOrig === fecha;
                        return (
                          <div key={fecha} onClick={() => setEditSemana({ ...editSemana, fechaOrig: fecha })}
                            style={{ flex: 1, textAlign: "center", padding: "6px 2px", borderRadius: 8, cursor: "pointer", userSelect: "none",
                              background: selec ? colorDia : "#F8FAFC",
                              border: `2px solid ${selec ? colorDia : "#E5E7EB"}`,
                              color: selec ? "#fff" : "#142B4D", fontWeight: selec ? 800 : 500, fontSize: 10 }}>
                            <div>{ABREV[fo.getDay()]}</div>
                            <div style={{ fontSize: 15, fontWeight: 900 }}>{fo.getDate()}</div>
                          </div>
                        );
                      })}
                    </div>
                  </div>

                  {/* Horario */}
                  <div style={{ marginBottom: 12 }}>
                    <label style={{ fontSize: 11, fontWeight: 700, color: "#6B7280", display: "block", marginBottom: 4, textTransform: "uppercase", letterSpacing: 0.5 }}>Horario</label>
                    <select value={editSemana.hora} onChange={e => setEditSemana({ ...editSemana, hora: e.target.value })}
                      style={{ width: "100%", padding: "10px 12px", border: "1.5px solid #E3DECF", borderRadius: 8, fontSize: 14 }}>
                      {FRANJAS.map(f => {
                        const ocupadas = citas.filter(c => c.fecha === editSemana.fechaOrig && c.hora === f && c.id !== editSemana.id).length;
                        const llena = ocupadas >= 4;
                        return <option key={f} value={f} disabled={llena}>{f}{llena ? " — LLENA" : ocupadas > 0 ? ` (${ocupadas}/4)` : ""}</option>;
                      })}
                    </select>
                  </div>

                  {/* Paleta de colores — chips horizontales compactos */}
                  <div style={{ marginBottom: 14 }}>
                    <label style={{ fontSize: 11, fontWeight: 700, color: "#6B7280", display: "block", marginBottom: 6, textTransform: "uppercase", letterSpacing: 0.5 }}>Color / Estado</label>
                    <div style={{ display: "flex", flexWrap: "wrap", gap: 5 }}>
                      {ESTADOS_CITA.map(e => {
                        let bloqueado = false;
                        if (COLORES_PASADO_SEM.includes(e.id)) {
                          const horaLimite = new Date(`${editSemana.fechaOrig}T${editSemana.hora}:00`);
                          horaLimite.setSeconds(horaLimite.getSeconds() - 5);
                          bloqueado = new Date() < horaLimite;
                        }
                        const selec = editSemana.estadoId === e.id;
                        return (
                          <div key={e.id} onClick={() => !bloqueado && setEditSemana({ ...editSemana, estadoId: e.id })}
                            title={bloqueado ? `"${e.label}" disponible solo después de que pase la hora` : e.label}
                            style={{ display: "flex", alignItems: "center", gap: 5, padding: "4px 10px", borderRadius: 20,
                              cursor: bloqueado ? "not-allowed" : "pointer", userSelect: "none",
                              background: bloqueado ? "#E5E7EB" : estadoBG(e),
                              color: bloqueado ? "#9CA3AF" : e.text,
                              border: selec ? "3px solid #142B4D" : "3px solid transparent",
                              opacity: bloqueado ? 0.5 : 1, fontSize: 11, fontWeight: 700,
                              boxShadow: selec ? "0 0 0 2px #fff inset" : "none",
                              transition: "all 0.12s" }}>
                            {bloqueado ? "🔒" : selec ? "✓ " : ""}{e.label}
                          </div>
                        );
                      })}
                    </div>
                  </div>

                  {/* Aceptar */}
                  <button
                    onClick={async () => {
                      if (!editSemana.cliente.trim()) return;
                      const ts = new Date().toISOString();
                      const orig = citas.find(c => c.id === editSemana.id);
                      const historialEntry = { de: orig?.estadoId || "prospecto", a: editSemana.estadoId, fecha: ts };
                      try {
                        await guardarCitas(citas.map(c => c.id === editSemana.id
                          ? { ...c, cliente: editSemana.cliente, hora: editSemana.hora, notas: editSemana.notas, estadoId: editSemana.estadoId, fecha: editSemana.fechaOrig, historial: [...(c.historial || []), historialEntry] }
                          : c
                        ));
                        mostrarToast("Pendiente actualizado");
                      } catch { mostrarToast("Error al guardar. Intenta de nuevo."); }
                      setEditSemana(null);
                    }}
                    disabled={!editSemana.cliente.trim()}
                    style={{ width: "100%", padding: "13px", border: "none", borderRadius: 8, background: editSemana.cliente.trim() ? colorDia : "#E5E7EB", color: editSemana.cliente.trim() ? "#fff" : "#9CA3AF", fontWeight: 800, fontSize: 15, cursor: editSemana.cliente.trim() ? "pointer" : "not-allowed", marginBottom: 8 }}
                  >
                    ✓ Aceptar
                  </button>
                  <button onClick={() => setEditSemana(null)}
                    style={{ width: "100%", padding: "11px", border: "none", borderRadius: 8, background: "#F1F5F9", color: "#6B7280", fontWeight: 700, fontSize: 14, cursor: "pointer" }}>
                    Cancelar
                  </button>
                  <button
                    onClick={async () => {
                      if (!window.confirm("¿Eliminar este pendiente? Esta acción no se puede deshacer.")) return;
                      try {
                        await guardarCitas(citas.filter(c => c.id !== editSemana.id));
                        mostrarToast("Pendiente eliminado");
                      } catch { mostrarToast("Error al eliminar. Intenta de nuevo."); }
                      setEditSemana(null);
                    }}
                    style={{ width: "100%", marginTop: 8, padding: "10px", border: "1px solid #EF4444", borderRadius: 8, background: "#fff", color: "#EF4444", fontWeight: 700, fontSize: 13, cursor: "pointer" }}
                  >
                    🗑 Eliminar pendiente
                  </button>
                </div>
              </div>
            );
          })()}
          <DetalleDiaView />
        </>
      );
    }


    // Vista principal: calendario semanal de 7 tarjetas
    return (
      <div style={{ minHeight: "100vh", background: "#F8FAFC" }}>
        {/* TopBar claro */}
        <div style={{ background: "#1A1A1A", padding: "16px 20px", borderBottom: "1px solid #E5E7EB" }}>
          <div style={{ maxWidth: 700, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div>
              <div style={{ fontSize: 10, letterSpacing: 3, color: "rgba(255,255,255,0.6)", textTransform: "uppercase" }}>Autocon Management · Agenda Virtual</div>
              <div className="display" style={{ fontSize: 19, fontWeight: 800, color: "#fff" }}>📆 PENDIENTES SEMANAL</div>
              <div style={{ fontSize: 12, color: "rgba(255,255,255,0.65)", marginTop: 2 }}>{fmt(semanaActual[0])} — {fmt(semanaActual[6])}</div>
            </div>
            <div style={{ textAlign: "right" }}>
              <div style={{ fontSize: 36, fontWeight: 900, color: "#F5C518", lineHeight: 1, fontFamily: "Oswald, sans-serif" }}>{pendientesSemana}</div>
              <div style={{ fontSize: 10, color: "rgba(255,255,255,0.5)", textTransform: "uppercase", letterSpacing: 1 }}>pendientes</div>
            </div>
          </div>
          <div style={{ maxWidth: 700, margin: "10px auto 0", display: "flex", justifyContent: "flex-end" }}>
            <button onClick={() => setVistaAgenda(null)} style={{ padding: "10px 22px", border: "none", borderRadius: 6, background: "#D6452B", color: "#fff", cursor: "pointer", fontSize: 14, fontWeight: 700 }}>← Salir</button>
          </div>
        </div>

        {/* Grid 7 días — cuadrículas 4+3 */}
        <div style={{ maxWidth: 700, margin: "0 auto", padding: "16px" }}>
          {[semanaActual.slice(0,4), semanaActual.slice(4,7)].map((grupo, gi) => (
            <div key={gi} style={{ display: "grid", gridTemplateColumns: `repeat(${grupo.length}, 1fr)`, gap: 10, marginBottom: 10 }}>
              {grupo.map((fecha) => {
                const fechaObj = new Date(fecha + "T12:00:00");
                const diaAbrev = DIAS_ABREV[fechaObj.getDay()];
                const numDia = fechaObj.getDate();
                const esPasado = fecha < hoy;
                const esHoyFecha = fecha === hoy;
                const colorCard = COLORES_DIA[fechaObj.getDay()];
                const citasDia = citas.filter(c => c.fecha === fecha);
                const pendActivosDia = citasDia.filter(c => {
                  if (finalizadosHoy.has(c.id)) return false;
                  if (!pendientesIds.has(c.estadoId || "prospecto")) return false;
                  if (esPasado) return false;
                  if (esHoyFecha) {
                    const horaCita = new Date(`${fecha}T${c.hora}`);
                    return (ahora - horaCita) <= 60 * 60 * 1000;
                  }
                  return true;
                }).length;

                return (
                  <div
                    key={fecha}
                    onClick={() => setDiaDetalleSemana(fecha)}
                    style={{
                      borderRadius: 16,
                      background: esHoyFecha ? colorCard : esPasado ? "#F1F5F9" : "#fff",
                      border: esHoyFecha ? `3px solid ${colorCard}` : `2px solid ${esPasado ? "#E2E8F0" : colorCard}`,
                      padding: "14px 10px",
                      cursor: "pointer",
                      textAlign: "center",
                      boxShadow: esHoyFecha ? `0 4px 20px ${colorCard}55` : "0 1px 4px rgba(0,0,0,0.06)",
                      transition: "transform 0.15s, box-shadow 0.15s",
                      opacity: esPasado ? 0.55 : 1,
                      userSelect: "none",
                    }}
                    onMouseOver={e => { if (!esPasado) { e.currentTarget.style.transform = "translateY(-2px)"; e.currentTarget.style.boxShadow = `0 6px 20px ${colorCard}44`; }}}
                    onMouseOut={e => { e.currentTarget.style.transform = "translateY(0)"; e.currentTarget.style.boxShadow = esHoyFecha ? `0 4px 20px ${colorCard}55` : "0 1px 4px rgba(0,0,0,0.06)"; }}
                  >
                    {/* Nombre del día */}
                    <div style={{
                      fontSize: 13, fontWeight: 800, letterSpacing: 1,
                      textTransform: "uppercase",
                      color: esHoyFecha ? "rgba(255,255,255,0.9)" : colorCard,
                      marginBottom: 4,
                    }}>{diaAbrev}</div>

                    {/* Número del día */}
                    <div style={{
                      fontSize: 38, fontWeight: 900, lineHeight: 1,
                      color: esHoyFecha ? "#fff" : esPasado ? "#CBD5E1" : "#142B4D",
                      fontFamily: "Oswald, sans-serif",
                      marginBottom: 10,
                    }}>{numDia}</div>

                    {/* Badge pendientes */}
                    <div style={{
                      width: 40, height: 40, borderRadius: "50%", margin: "0 auto",
                      background: esHoyFecha
                        ? "rgba(255,255,255,0.25)"
                        : pendActivosDia > 0 ? colorCard : "#E2E8F0",
                      display: "flex", flexDirection: "column",
                      alignItems: "center", justifyContent: "center",
                    }}>
                      <div style={{
                        fontSize: 17, fontWeight: 900, lineHeight: 1,
                        color: (esHoyFecha || pendActivosDia > 0) ? "#fff" : "#94A3B8",
                      }}>{pendActivosDia}</div>
                    </div>
                    <div style={{
                      fontSize: 9, fontWeight: 700, marginTop: 5,
                      textTransform: "uppercase", letterSpacing: 0.5,
                      color: esHoyFecha ? "rgba(255,255,255,0.7)" : "#94A3B8",
                    }}>
                      {pendActivosDia === 1 ? "pendiente" : "pendientes"}
                    </div>

                    {/* Indicador HOY */}
                    {esHoyFecha && (
                      <div style={{ marginTop: 8, background: "rgba(255,255,255,0.3)", borderRadius: 20, padding: "2px 10px", display: "inline-block", fontSize: 9, fontWeight: 800, color: "#fff", letterSpacing: 2 }}>
                        HOY
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          ))}
          <div style={{ marginTop: 4, fontSize: 10, color: "#94A3B8", textAlign: "center", letterSpacing: 1, textTransform: "uppercase" }}>
            Toca cualquier día para ver el horario completo · Se actualiza cada hora
          </div>
        </div>
      </div>
    );
  }

  // ── VISTA: Clientes Contratados (Mis Solicitudes) ──
  if (vistaAgenda === "clientes-contratados") {
    return (
      <div>
        <div style={{ background: "#F5C518", padding: "16px 20px" }}>
          <div style={{ maxWidth: 900, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div>
              <div style={{ fontSize: 11, letterSpacing: 3, color: "rgba(0,0,0,0.5)", textTransform: "uppercase" }}>Autocon Management · Agenda Virtual</div>
              <div className="display" style={{ fontSize: 19, fontWeight: 700, color: "#142B4D" }}>🤝 CLIENTES CONTRATADOS</div>
              <div style={{ fontSize: 12, color: "#142B4D", opacity: 0.7, marginTop: 2 }}>Citas marcadas como "Cliente contrató" en tu agenda</div>
            </div>
            <button onClick={() => setVistaAgenda(null)} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: "#1A1A1A", color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>
          </div>
        </div>
        <div style={{ maxWidth: 900, margin: "0 auto", padding: "24px 20px" }}>
          {(() => {
            const contratados = citas.filter(c => c.estadoId === "contrato").sort((a,b) => b.fecha.localeCompare(a.fecha) || b.hora.localeCompare(a.hora));
            if (contratados.length === 0) return (
              <div style={{ textAlign: "center", color: "#6B7280", padding: 48, fontSize: 15 }}>
                <div style={{ fontSize: 40, marginBottom: 12 }}>🤝</div>
                Aún no tienes clientes marcados como contratados.
              </div>
            );
            return (
              <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                {contratados.map((c, i) => {
                  const fechaObj = new Date(c.fecha + "T12:00:00");
                  const fechaLarga = fechaObj.toLocaleDateString("es-MX", { weekday: "long", day: "numeric", month: "long", year: "numeric" });
                  return (
                    <div key={c.id || i} style={{ background: "#fff", borderRadius: 10, padding: "14px 18px", border: "2px solid #EF4444", boxShadow: "0 2px 8px rgba(0,0,0,0.07)" }}>
                      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 6 }}>
                        <div style={{ width: 14, height: 14, borderRadius: "50%", background: "#EF4444", flexShrink: 0 }} />
                        <div style={{ fontWeight: 800, fontSize: 15, color: "#142B4D" }}>{c.cliente}</div>
                      </div>
                      <div style={{ fontSize: 13, color: "#6B7280", textTransform: "capitalize" }}>📅 {fechaLarga}</div>
                      <div style={{ fontSize: 13, color: "#6B7280", marginTop: 2 }}>⏰ {c.hora}</div>
                      {c.notas && <div style={{ fontSize: 12, color: "#9CA3AF", marginTop: 6, fontStyle: "italic" }}>📝 {c.notas}</div>}
                    </div>
                  );
                })}
              </div>
            );
          })()}
        </div>
      </div>
    );
  }

  // ── VISTA: Día desde Calendario Anual ──
  if (diaDetalleCalendario) {
    const fechaObj = new Date(diaDetalleCalendario + "T12:00:00");
    const nombreDiaLargo = fechaObj.toLocaleDateString("es-MX", { weekday: "long", day: "numeric", month: "long", year: "numeric" });
    const esPasado = diaDetalleCalendario < hoy;
    const citasDia = citas.filter(c => c.fecha === diaDetalleCalendario);
    const COLORES_DIA_CAL = ["#6366F1","#0EA5E9","#10B981","#F59E0B","#EF4444","#EC4899","#8B5CF6"];
    const colorDia = COLORES_DIA_CAL[fechaObj.getDay()];
    const tieneMadrugada = citasDia.some(c => parseInt(c.hora) < 7);
    const tieneNocheAlta = citasDia.some(c => parseInt(c.hora) >= 19);
    const COLORES_PASADO_CAL = ["contrato", "cancelocontrato"];

    const DetalleDiaCalendario = () => {
      const [verMadrugada, setVerMadrugada] = React.useState(tieneMadrugada);
      const [verNocheAlta, setVerNocheAlta] = React.useState(tieneNocheAlta);
      const franjasVisibles = FRANJAS.filter(f => {
        const h = parseInt(f);
        if (h < 7) return verMadrugada;
        if (h >= 19) return verNocheAlta;
        return true;
      });
      const ctMadrugada = citasDia.filter(c => parseInt(c.hora) < 7).length;
      const ctNoche = citasDia.filter(c => parseInt(c.hora) >= 19).length;
      const ahora = new Date();

      return (
        <div style={{ minHeight: "100vh", background: "#F8FAFC" }}>
          <div style={{ background: colorDia, padding: "16px 20px" }}>
            <div style={{ maxWidth: 700, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div>
                <div style={{ fontSize: 11, letterSpacing: 3, color: "rgba(255,255,255,0.7)", textTransform: "uppercase" }}>Calendario Anual {anio}</div>
                <div className="display" style={{ fontSize: 18, fontWeight: 800, color: "#fff", textTransform: "capitalize" }}>{nombreDiaLargo}</div>
                {esPasado && <div style={{ fontSize: 11, color: "rgba(255,255,255,0.85)", marginTop: 2, background: "rgba(0,0,0,0.2)", borderRadius: 6, padding: "2px 8px", display: "inline-block" }}>Día pasado</div>}
              </div>
              <button onClick={() => { setDiaDetalleCalendario(null); setDiaSeleccionado(null); }} style={{ padding: "10px 20px", border: "none", borderRadius: 6, background: "rgba(0,0,0,0.3)", color: "#fff", cursor: "pointer", fontSize: 14, fontWeight: 700 }}>Salir</button>
            </div>
          </div>

          <div style={{ maxWidth: 700, margin: "0 auto", padding: "12px 16px" }}>
            {/* Toggle madrugada */}
            <div onClick={() => setVerMadrugada(v => !v)} style={{ display: "flex", alignItems: "center", gap: 8, padding: "8px 12px", background: "#fff", borderRadius: 8, border: "1px solid #E5E7EB", cursor: "pointer", marginBottom: 8, userSelect: "none" }}>
              <span style={{ fontSize: 13, color: colorDia }}>{verMadrugada ? "▲" : "▼"}</span>
              <span style={{ fontSize: 12, fontWeight: 700, color: "#6B7280", flex: 1 }}>Madrugada 00:00 – 06:30</span>
              {ctMadrugada > 0 && <span style={{ fontSize: 10, background: colorDia, color: "#fff", borderRadius: 10, padding: "2px 8px", fontWeight: 700 }}>{ctMadrugada} cita{ctMadrugada !== 1 ? "s" : ""}</span>}
            </div>

            {franjasVisibles.map((franja) => {
              const h = parseInt(franja);
              const citasFranja = citasDia.filter(c => c.hora === franja);
              const franjaObj = new Date(`${diaDetalleCalendario}T${franja}:00`);
              const pasadaUnaHora = diaDetalleCalendario === hoy && (ahora - franjaObj) > 60 * 60 * 1000;
              const esInicioNoche = h === 19 && franja === "19:00";
              return (
                <React.Fragment key={franja}>
                  {esInicioNoche && (
                    <div onClick={() => setVerNocheAlta(v => !v)} style={{ display: "flex", alignItems: "center", gap: 8, padding: "8px 12px", background: "#fff", borderRadius: 8, border: "1px solid #E5E7EB", cursor: "pointer", margin: "8px 0", userSelect: "none" }}>
                      <span style={{ fontSize: 13, color: colorDia }}>▲</span>
                      <span style={{ fontSize: 12, fontWeight: 700, color: "#6B7280", flex: 1 }}>Noche 19:00 – 23:30</span>
                      {ctNoche > 0 && <span style={{ fontSize: 10, background: colorDia, color: "#fff", borderRadius: 10, padding: "2px 8px", fontWeight: 700 }}>{ctNoche} cita{ctNoche !== 1 ? "s" : ""}</span>}
                    </div>
                  )}
                  <div style={{ display: "flex", gap: 8, marginBottom: citasFranja.length > 0 ? 6 : 1, alignItems: "flex-start" }}>
                    <div style={{ width: 52, flexShrink: 0, textAlign: "right", paddingTop: 8, fontSize: 14, fontWeight: 700, color: citasFranja.length > 0 ? colorDia : "#94A3B8", letterSpacing: 0.3 }}>{franja}</div>
                    <div style={{ flex: 1 }}>
                      {citasFranja.length === 0 ? (
                        <div style={{ height: 1, background: "#F0F0F0", marginTop: 12 }} />
                      ) : (
                        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 4 }}>
                          {citasFranja.slice(0, 4).map(c => {
                            const estado = ESTADOS_CITA.find(e => e.id === (c.estadoId || "prospecto")) || ESTADOS_CITA[0];
                            const finalizado = finalizadosHoy.has(c.id);
                            return (
                              <div key={c.id}
                                onClick={() => setEditCalendario({ id: c.id, cliente: c.cliente, hora: c.hora, notas: c.notas || "", estadoId: c.estadoId || "prospecto", fechaOrig: c.fecha })}
                                style={{ background: finalizado ? "#F0FDF4" : "#fff", border: `2px solid ${finalizado ? "#86EFAC" : estado.color}`, borderTop: `4px solid ${colorDia}`, borderRadius: 8, padding: "6px 7px", opacity: (pasadaUnaHora || esPasado) && !finalizado ? 0.5 : 1, boxShadow: "0 1px 4px rgba(0,0,0,0.07)", cursor: "pointer", transition: "transform 0.1s" }}
                                onMouseOver={e => e.currentTarget.style.transform = "scale(1.03)"}
                                onMouseOut={e => e.currentTarget.style.transform = "scale(1)"}
                              >
                                <div style={{ display: "flex", alignItems: "center", gap: 4, marginBottom: 2 }}>
                                  <div style={{ width: 8, height: 8, borderRadius: "50%", background: estadoBG(estado), flexShrink: 0 }} />
                                  {finalizado && <span style={{ fontSize: 9, color: "#16A34A", fontWeight: 900 }}>✓</span>}
                                </div>
                                <div style={{ fontSize: 10, fontWeight: 700, color: "#142B4D", textDecoration: finalizado ? "line-through" : "none", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{c.cliente}</div>
                                <div style={{ background: estadoBG(estado), color: estado.text, borderRadius: 6, padding: "1px 4px", fontSize: 8, fontWeight: 700, display: "inline-block", marginTop: 3, whiteSpace: "nowrap" }}>{estado.label}</div>
                              </div>
                            );
                          })}
                          {Array.from({ length: Math.max(0, 4 - citasFranja.length) }).map((_, i) => (
                            <div key={`empty-${i}`} style={{ borderRadius: 8, border: "1.5px dashed #E5E7EB", minHeight: 52, opacity: 0.35 }} />
                          ))}
                        </div>
                      )}
                    </div>
                  </div>
                </React.Fragment>
              );
            })}

            {!verNocheAlta && (
              <div onClick={() => setVerNocheAlta(true)} style={{ display: "flex", alignItems: "center", gap: 8, padding: "8px 12px", background: "#fff", borderRadius: 8, border: "1px solid #E5E7EB", cursor: "pointer", marginTop: 8, userSelect: "none" }}>
                <span style={{ fontSize: 13, color: colorDia }}>▼</span>
                <span style={{ fontSize: 12, fontWeight: 700, color: "#6B7280", flex: 1 }}>Noche 19:00 – 23:30</span>
                {ctNoche > 0 && <span style={{ fontSize: 10, background: colorDia, color: "#fff", borderRadius: 10, padding: "2px 8px", fontWeight: 700 }}>{ctNoche} cita{ctNoche !== 1 ? "s" : ""}</span>}
              </div>
            )}

            {citasDia.length === 0 && (
              <div style={{ textAlign: "center", color: "#9CA3AF", padding: "40px 0", fontSize: 14 }}>
                <div style={{ fontSize: 36, marginBottom: 10 }}>📭</div>
                Sin pendientes registrados este día.
              </div>
            )}
          </div>
        </div>
      );
    };

    return (
      <>
        {/* Modal editar desde calendario anual */}
        {editCalendario && (() => {
          const palabrasNota = (editCalendario.notas || "").trim().split(/\s+/).filter(Boolean).length;
          const restantes = 120 - palabrasNota;
          // accion: "editar" | "mover" | "copiar"
          const accion = editCalendario.accion || "editar";
          const fechaDestino = editCalendario.fechaDestino || "";
          const horaDestino = editCalendario.horaDestino || editCalendario.hora;
          return (
            <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.65)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center", padding: 16, overflowY: "auto" }}>
              <div style={{ background: "#fff", borderRadius: 14, padding: 22, maxWidth: 420, width: "100%", boxShadow: "0 12px 40px rgba(0,0,0,0.4)", maxHeight: "92vh", overflowY: "auto" }}>

                {/* Tabs de acción */}
                <div style={{ display: "flex", gap: 6, marginBottom: 18 }}>
                  {[["editar","✏️ Editar"],["mover","🔄 Mover"],["copiar","📋 Copiar"]].map(([val, label]) => (
                    <button key={val} onClick={() => setEditCalendario({ ...editCalendario, accion: val, fechaDestino: "", horaDestino: editCalendario.hora })}
                      style={{ flex: 1, padding: "8px 4px", border: "none", borderRadius: 8, fontSize: 12, fontWeight: 800, cursor: "pointer",
                        background: accion === val ? colorDia : "#F1F5F9",
                        color: accion === val ? "#fff" : "#6B7280" }}>
                      {label}
                    </button>
                  ))}
                </div>

                {/* ── EDITAR ── */}
                {accion === "editar" && (<>
                  <div style={{ marginBottom: 12 }}>
                    <label style={{ fontSize: 11, fontWeight: 700, color: "#6B7280", display: "block", marginBottom: 4, textTransform: "uppercase", letterSpacing: 0.5 }}>Nombre</label>
                    <input value={editCalendario.cliente} onChange={e => setEditCalendario({ ...editCalendario, cliente: e.target.value })}
                      style={{ width: "100%", padding: "10px 12px", border: "1.5px solid #E3DECF", borderRadius: 8, fontSize: 14, boxSizing: "border-box" }} />
                  </div>
                  <div style={{ marginBottom: 12 }}>
                    <label style={{ fontSize: 11, fontWeight: 700, color: "#6B7280", display: "block", marginBottom: 4, textTransform: "uppercase", letterSpacing: 0.5 }}>Nota</label>
                    <textarea value={editCalendario.notas}
                      onChange={e => {
                        const p = e.target.value.trim().split(/\s+/).filter(Boolean);
                        if (p.length <= 120 || e.target.value.length < (editCalendario.notas || "").length)
                          setEditCalendario({ ...editCalendario, notas: e.target.value });
                      }}
                      rows={3} placeholder="Observaciones..."
                      style={{ width: "100%", padding: "10px 12px", border: "1.5px solid #E3DECF", borderRadius: 8, fontSize: 13, resize: "none", fontFamily: "inherit", boxSizing: "border-box" }} />
                    <div style={{ textAlign: "right", fontSize: 10, marginTop: 2, color: restantes <= 10 ? "#D6452B" : "#C0C0C0" }}>
                      {editCalendario.notas?.trim() ? `${restantes} palabras restantes` : "Máx. 120 palabras"}
                    </div>
                  </div>
                  <div style={{ marginBottom: 12 }}>
                    <label style={{ fontSize: 11, fontWeight: 700, color: "#6B7280", display: "block", marginBottom: 4, textTransform: "uppercase", letterSpacing: 0.5 }}>Horario</label>
                    <select value={editCalendario.hora} onChange={e => setEditCalendario({ ...editCalendario, hora: e.target.value })}
                      style={{ width: "100%", padding: "10px 12px", border: "1.5px solid #E3DECF", borderRadius: 8, fontSize: 14 }}>
                      {FRANJAS.map(f => {
                        const ocupadas = citas.filter(c => c.fecha === editCalendario.fechaOrig && c.hora === f && c.id !== editCalendario.id).length;
                        const llena = ocupadas >= 4;
                        return <option key={f} value={f} disabled={llena}>{f}{llena ? " — LLENA" : ocupadas > 0 ? ` (${ocupadas}/4)` : ""}</option>;
                      })}
                    </select>
                  </div>
                  <div style={{ marginBottom: 16 }}>
                    <label style={{ fontSize: 11, fontWeight: 700, color: "#6B7280", display: "block", marginBottom: 6, textTransform: "uppercase", letterSpacing: 0.5 }}>Color / Estado</label>
                    <div style={{ display: "flex", flexWrap: "wrap", gap: 5 }}>
                      {ESTADOS_CITA.map(e => {
                        let bloqueado = false;
                        if (COLORES_PASADO_CAL.includes(e.id)) {
                          const horaLimite = new Date(`${editCalendario.fechaOrig}T${editCalendario.hora}:00`);
                          horaLimite.setSeconds(horaLimite.getSeconds() - 5);
                          bloqueado = new Date() < horaLimite;
                        }
                        const selec = editCalendario.estadoId === e.id;
                        return (
                          <div key={e.id} onClick={() => !bloqueado && setEditCalendario({ ...editCalendario, estadoId: e.id })}
                            title={bloqueado ? "Disponible solo después de la hora" : e.label}
                            style={{ display: "flex", alignItems: "center", gap: 5, padding: "4px 10px", borderRadius: 20, cursor: bloqueado ? "not-allowed" : "pointer", userSelect: "none",
                              background: bloqueado ? "#E5E7EB" : estadoBG(e), color: bloqueado ? "#9CA3AF" : e.text,
                              border: selec ? "3px solid #142B4D" : "3px solid transparent",
                              opacity: bloqueado ? 0.5 : 1, fontSize: 11, fontWeight: 700,
                              boxShadow: selec ? "0 0 0 2px #fff inset" : "none" }}>
                            {bloqueado ? "🔒" : selec ? "✓ " : ""}{e.label}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                  <button onClick={async () => {
                    if (!editCalendario.cliente.trim()) return;
                    const ts = new Date().toISOString();
                    const orig = citas.find(c => c.id === editCalendario.id);
                    const historialEntry = { de: orig?.estadoId || "prospecto", a: editCalendario.estadoId, fecha: ts };
                    try {
                      await guardarCitas(citas.map(c => c.id === editCalendario.id
                        ? { ...c, cliente: editCalendario.cliente, hora: editCalendario.hora, notas: editCalendario.notas, estadoId: editCalendario.estadoId, historial: [...(c.historial || []), historialEntry] }
                        : c));
                      mostrarToast("Pendiente actualizado");
                    } catch { mostrarToast("Error al guardar. Intenta de nuevo."); }
                    setEditCalendario(null);
                  }} disabled={!editCalendario.cliente.trim()}
                    style={{ width: "100%", padding: "13px", border: "none", borderRadius: 8, background: editCalendario.cliente.trim() ? colorDia : "#E5E7EB", color: editCalendario.cliente.trim() ? "#fff" : "#9CA3AF", fontWeight: 800, fontSize: 15, cursor: editCalendario.cliente.trim() ? "pointer" : "not-allowed", marginBottom: 8 }}>
                    ✓ Aceptar
                  </button>
                </>)}

                {/* ── MOVER / COPIAR ── */}
                {(accion === "mover" || accion === "copiar") && (<>
                  <div style={{ background: "#F8FAFC", borderRadius: 8, padding: "10px 14px", marginBottom: 14, fontSize: 13, color: "#142B4D" }}>
                    <strong>{editCalendario.cliente}</strong>
                    <div style={{ fontSize: 11, color: "#6B7280", marginTop: 2 }}>
                      Origen: {editCalendario.fechaOrig} · {editCalendario.hora}
                    </div>
                  </div>

                  {/* Fecha destino */}
                  <div style={{ marginBottom: 12 }}>
                    <label style={{ fontSize: 11, fontWeight: 700, color: "#6B7280", display: "block", marginBottom: 4, textTransform: "uppercase", letterSpacing: 0.5 }}>
                      {accion === "mover" ? "Mover a fecha" : "Copiar a fecha"}
                    </label>
                    <input type="date" value={fechaDestino}
                      min={`${anio}-01-01`} max={`${anio}-12-31`}
                      onChange={e => setEditCalendario({ ...editCalendario, fechaDestino: e.target.value, horaDestino: editCalendario.hora })}
                      style={{ width: "100%", padding: "10px 12px", border: "1.5px solid #E3DECF", borderRadius: 8, fontSize: 14, boxSizing: "border-box" }} />
                  </div>

                  {/* Hora destino */}
                  <div style={{ marginBottom: 16 }}>
                    <label style={{ fontSize: 11, fontWeight: 700, color: "#6B7280", display: "block", marginBottom: 4, textTransform: "uppercase", letterSpacing: 0.5 }}>Horario destino</label>
                    <select value={horaDestino}
                      onChange={e => setEditCalendario({ ...editCalendario, horaDestino: e.target.value })}
                      style={{ width: "100%", padding: "10px 12px", border: "1.5px solid #E3DECF", borderRadius: 8, fontSize: 14 }}>
                      {FRANJAS.map(f => {
                        if (!fechaDestino) return <option key={f} value={f}>{f}</option>;
                        const ocupadas = citas.filter(c => c.fecha === fechaDestino && c.hora === f && (accion === "mover" ? c.id !== editCalendario.id : true)).length;
                        const llena = ocupadas >= 4;
                        return <option key={f} value={f} disabled={llena}>{f}{llena ? " — LLENA" : ocupadas > 0 ? ` (${ocupadas}/4)` : ""}</option>;
                      })}
                    </select>
                  </div>

                  {/* Confirmación visual */}
                  {fechaDestino && (
                    <div style={{ background: accion === "mover" ? "#FEF3C7" : "#F0FDF4", border: `1px solid ${accion === "mover" ? "#F5C518" : "#86EFAC"}`, borderRadius: 8, padding: "10px 14px", marginBottom: 14, fontSize: 12, color: "#142B4D" }}>
                      {accion === "mover" ? "🔄" : "📋"} <strong>{accion === "mover" ? "Mover" : "Copiar"}</strong> a{" "}
                      <strong>{new Date(fechaDestino + "T12:00:00").toLocaleDateString("es-MX", { weekday: "long", day: "numeric", month: "long" })}</strong>{" "}
                      a las <strong>{horaDestino}</strong>
                      {accion === "mover" && <div style={{ fontSize: 11, color: "#92400E", marginTop: 4 }}>El pendiente desaparecerá del día original.</div>}
                      {accion === "copiar" && <div style={{ fontSize: 11, color: "#15803D", marginTop: 4 }}>El original se conserva en {editCalendario.fechaOrig}.</div>}
                    </div>
                  )}

                  <button onClick={async () => {
                    if (!fechaDestino || !horaDestino) return;
                    try {
                      if (accion === "mover") {
                        await guardarCitas(citas.map(c => c.id === editCalendario.id
                          ? { ...c, fecha: fechaDestino, hora: horaDestino }
                          : c));
                        mostrarToast("Pendiente movido correctamente");
                        setDiaDetalleCalendario(fechaDestino);
                      } else {
                        const nueva = { ...citas.find(c => c.id === editCalendario.id), id: uid(), fecha: fechaDestino, hora: horaDestino, alertado: false };
                        await guardarCitas([...citas, nueva].sort((a,b) => `${a.fecha}T${a.hora}`.localeCompare(`${b.fecha}T${b.hora}`)));
                        mostrarToast("Pendiente copiado correctamente");
                      }
                    } catch { mostrarToast("Error al guardar. Intenta de nuevo."); }
                    setEditCalendario(null);
                  }} disabled={!fechaDestino}
                    style={{ width: "100%", padding: "13px", border: "none", borderRadius: 8, background: fechaDestino ? colorDia : "#E5E7EB", color: fechaDestino ? "#fff" : "#9CA3AF", fontWeight: 800, fontSize: 15, cursor: fechaDestino ? "pointer" : "not-allowed", marginBottom: 8 }}>
                    ✓ {accion === "mover" ? "Confirmar movimiento" : "Confirmar copia"}
                  </button>
                </>)}

                <button onClick={() => setEditCalendario(null)}
                  style={{ width: "100%", padding: "11px", border: "none", borderRadius: 8, background: "#F1F5F9", color: "#6B7280", fontWeight: 700, fontSize: 14, cursor: "pointer" }}>
                  Cancelar
                </button>
                <button
                  onClick={async () => {
                    if (!window.confirm("¿Eliminar este pendiente? Esta acción no se puede deshacer.")) return;
                    try {
                      await guardarCitas(citas.filter(c => c.id !== editCalendario.id));
                      mostrarToast("Pendiente eliminado");
                    } catch { mostrarToast("Error al eliminar. Intenta de nuevo."); }
                    setEditCalendario(null);
                  }}
                  style={{ width: "100%", marginTop: 8, padding: "10px", border: "1px solid #EF4444", borderRadius: 8, background: "#fff", color: "#EF4444", fontWeight: 700, fontSize: 13, cursor: "pointer" }}
                >
                  🗑 Eliminar pendiente
                </button>
              </div>
            </div>
          );
        })()}
        <DetalleDiaCalendario />
      </>
    );
  }

  // ── VISTA: Calendario anual ──
  // vistaAgenda === "calendario"
  return (
    <div>
      {/* ── Cuadro flotante de alarma 15 minutos ── */}
      {alarmaProxima && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.75)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
          <div style={{ background: "#fff", borderRadius: 14, width: "100%", maxWidth: 420, boxShadow: "0 16px 48px rgba(0,0,0,0.45)", overflow: "hidden" }}>
            <div style={{ background: "#C0392B", padding: "18px 22px", textAlign: "center" }}>
              <div style={{ fontSize: 32, marginBottom: 6 }}>⏰</div>
              <div className="display" style={{ color: "#fff", fontSize: 17, fontWeight: 800, lineHeight: 1.3 }}>
                ¡En 15 minutos tendrás{" "}
                <span style={{ color: "#F5C518" }}>{alarmaProxima.length} pendiente{alarmaProxima.length !== 1 ? "s" : ""}</span>{" "}
                por cumplir!
              </div>
            </div>
            <div style={{ padding: "16px 22px" }}>
              {alarmaProxima.map((c, idx) => (
                <div key={idx} style={{ background: "#F8FAFC", borderRadius: 8, padding: "10px 14px", marginBottom: 8, border: "1px solid #E5E7EB" }}>
                  <div style={{ fontWeight: 700, fontSize: 14, color: "#142B4D" }}>{c.cliente}</div>
                  <div style={{ fontSize: 12, color: "#6B7280", marginTop: 2 }}>⏰ {c.hora}{c.notas ? ` · ${c.notas}` : ""}</div>
                </div>
              ))}
            </div>
            <div style={{ padding: "0 22px 18px" }}>
              <button onClick={() => setAlarmaProxima(null)} style={{ width: "100%", padding: "11px", border: "none", borderRadius: 8, background: "#C0392B", color: "#fff", fontWeight: 800, fontSize: 14, cursor: "pointer" }}>
                ✓ ENTENDIDO
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Toast */}
      {toastMsg && (
        <div style={{ position: "fixed", top: 16, left: "50%", transform: "translateX(-50%)", background: "#22C55E", color: "#fff", padding: "10px 24px", borderRadius: 8, fontSize: 14, fontWeight: 700, zIndex: 99999, boxShadow: "0 4px 16px rgba(0,0,0,0.2)" }}>
          ✓ {toastMsg}
        </div>
      )}

      {/* Resultado búsqueda anual */}
      {resultadoBusqueda && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.7)", zIndex: 9999, overflowY: "auto", display: "flex", alignItems: "flex-start", justifyContent: "center", padding: "20px 16px" }}>
          <div style={{ background: "#fff", borderRadius: 12, width: "100%", maxWidth: 680, boxShadow: "0 12px 40px rgba(0,0,0,0.4)", overflow: "hidden" }}>
            <div style={{ background: "#1A1A1A", padding: "14px 20px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div style={{ color: "#fff", fontWeight: 700, fontSize: 16 }}>🔍 Resultados: "{busquedaAnual}"</div>
              <button onClick={() => { setResultadoBusqueda(null); setBusquedaAnual(""); }} style={{ background: "none", border: "none", color: "#fff", fontSize: 20, cursor: "pointer" }}>✕</button>
            </div>
            <div style={{ padding: "16px 20px", maxHeight: "60vh", overflowY: "auto" }}>
              {resultadoBusqueda.length === 0 ? (
                <div style={{ textAlign: "center", color: "#9CA3AF", padding: "20px 0", fontSize: 14 }}>No se encontró ningún cliente con ese nombre en {anio}.</div>
              ) : (
                <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                  {resultadoBusqueda.sort((a, b) => a.fecha.localeCompare(b.fecha) || a.hora.localeCompare(b.hora)).map((c, i) => {
                    const estado = ESTADOS_CITA.find((e) => e.id === (c.estadoId || "prospecto")) || ESTADOS_CITA[0];
                    const fechaObj = new Date(c.fecha + "T12:00:00");
                    const fechaLarga = fechaObj.toLocaleDateString("es-MX", { weekday: "long", day: "numeric", month: "long", year: "numeric" });
                    return (
                      <div key={c.id || i} style={{ background: "#F8FAFC", borderRadius: 8, padding: "12px 14px", border: "1px solid #E5E7EB" }}>
                        <div style={{ fontWeight: 700, fontSize: 14, color: "#142B4D", marginBottom: 4 }}>{c.cliente}</div>
                        <div style={{ fontSize: 12, color: "#6B7280", marginBottom: 6, textTransform: "capitalize" }}>📅 {fechaLarga}</div>
                        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                          <span style={{ fontSize: 12, color: "#6B7280" }}>⏰ {c.hora}</span>
                          <div style={{ background: estadoBG(estado), color: estado.text, borderRadius: 12, padding: "3px 10px", fontSize: 11, fontWeight: 700 }}>{estado.label}</div>
                        </div>
                        {c.notas && <div style={{ fontSize: 11, color: "#6B7280", marginTop: 6, fontStyle: "italic" }}>📝 {c.notas}</div>}
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
            <div style={{ padding: "12px 20px", borderTop: "1px solid #F3F4F6" }}>
              <button onClick={() => { setResultadoBusqueda(null); setBusquedaAnual(""); }} style={{ width: "100%", padding: "11px", border: "none", borderRadius: 8, background: "#1A1A1A", color: "#fff", fontWeight: 800, fontSize: 14, cursor: "pointer" }}>✓ Cerrar</button>
            </div>
          </div>
        </div>
      )}

      <div style={{ background: "#1A1A1A", color: "#fff", padding: "16px 20px" }} className="no-print">
        <div style={{ maxWidth: 900, margin: "0 auto" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 10, marginBottom: 12 }}>
            <div>
              <div style={{ fontSize: 11, letterSpacing: 3, color: "rgba(255,255,255,0.7)", textTransform: "uppercase" }}>Autocon Management · Plataforma</div>
              <div className="display" style={{ fontSize: 20, fontWeight: 700 }}>📅 CALENDARIO {anio} — AGENDA VIRTUAL</div>
            </div>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap", alignItems: "center" }}>
              <button onClick={() => { setVistaAgenda(null); setCalendarZoom(1); }} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: "#D6452B", color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>
            </div>
          </div>
          {/* Buscador anual */}
          <div style={{ display: "flex", gap: 8 }}>
            <input
              placeholder="🔍 Buscar cliente en este año… escribe el nombre"
              value={busquedaAnual}
              onChange={(e) => { setBusquedaAnual(e.target.value); if (!e.target.value) setResultadoBusqueda(null); }}
              onKeyDown={(e) => {
                if (e.key === "Enter" && busquedaAnual.trim()) {
                  const encontradas = citas.filter((c) => nombreConApellido(c.cliente).includes(busquedaAnual.toLowerCase().trim()) || (c.cliente || "").toLowerCase().includes(busquedaAnual.toLowerCase().trim()));
                  setResultadoBusqueda(encontradas.length > 0 ? encontradas : []);
                }
              }}
              style={{ flex: 1, padding: "9px 14px", border: "none", borderRadius: 6, fontSize: 14, color: "#142B4D" }}
            />
            <button
              onClick={() => {
                if (busquedaAnual.trim()) {
                  const encontradas = citas.filter((c) => nombreConApellido(c.cliente).includes(busquedaAnual.toLowerCase().trim()) || (c.cliente || "").toLowerCase().includes(busquedaAnual.toLowerCase().trim()));
                  setResultadoBusqueda(encontradas.length > 0 ? encontradas : []);
                }
              }}
              style={{ padding: "9px 16px", border: "none", borderRadius: 6, background: "#F5C518", color: "#142B4D", fontWeight: 700, cursor: "pointer", fontSize: 13 }}
            >
              Buscar
            </button>
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 900, margin: "0 auto", padding: "20px" }}>
        {loading ? (
          <div style={{ textAlign: "center", color: "#6B7280", padding: 32 }}>Cargando agenda…</div>
        ) : (
          <>
            <div
              onTouchStart={onCalendarTouchStart}
              onTouchMove={onCalendarTouchMove}
              style={{
                overflow: "auto",
                WebkitOverflowScrolling: "touch",
                touchAction: "pan-x pan-y",
                maxHeight: "70vh",
                border: calendarZoom > 1 ? "1px dashed #F5C518" : "none",
                borderRadius: 8,
              }}
            >
              <div style={{
                display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 10,
                transform: `scale(${calendarZoom})`, transformOrigin: "top center",
                transition: "transform 0.1s ease-out",
              }}>
                {Array.from({length: 12}, (_, i) => renderMes(i))}
              </div>
            </div>
            <div style={{ marginTop: 14, background: "#F0FDF4", border: "1px solid #BBF7D0", borderRadius: 8, padding: "10px 16px", fontSize: 12, color: "#15803D", textAlign: "center", fontWeight: 500 }}>
              💡 ¿Ya viste el número pequeño debajo de cada día? Es el número de citados que tienes en ese día. Revisa y cierra esas ventas.
              {" "}Pellizca con dos dedos para acercar y seleccionar con más precisión.
              {calendarZoom > 1 && (
                <div style={{ marginTop: 8 }}>
                  <button onClick={() => setCalendarZoom(1)} style={{ padding: "6px 16px", border: "none", borderRadius: 6, background: "#F5C518", color: "#142B4D", fontWeight: 700, fontSize: 12, cursor: "pointer" }}>
                    ↺ Restablecer tamaño ({Math.round(calendarZoom * 100)}%)
                  </button>
                </div>
              )}
            </div>
          </>
        )}
      </div>
    </div>
  );
}


/* ── AsesorPanel rediseñado con tarjetas ── */
// Horas del día (formato 24h) en las que se revisa si corresponde mostrar el recordatorio.
// Ventana activa: 8:00 a 17:00 en punto (a partir de las 17:00 ya no se muestra).
const HORAS_RECORDATORIO_PRODUCTIVIDAD = [8, 10, 12, 14, 16];

function nombreCortoAsesor(nombreCompleto) {
  const partes = (nombreCompleto || "").trim().split(/\s+/);
  return partes.slice(0, 2).join(" ") || nombreCompleto || "";
}

// Mensajes por nivel (1° a 5° día consecutivo con el indicador de "PENDIENTES DE HOY" en 0)
const MENSAJES_PRODUCTIVIDAD = {
  1: (nombre) => ({
    titulo: `Hola, ${nombre} ¿Tienes actividades para hoy?`,
    cuerpo: "Tu indicador aparece en 0 pendientes.",
    cierre: "Es momento de activarse. ¡Ánimo!",
    tono: "info",
  }),
  2: (nombre) => ({
    titulo: `Hola, ${nombre} ¿Tienes actividades para hoy?`,
    cuerpo: "Tu indicador sigue apareciendo en 0 pendientes por segundo día consecutivo.",
    cierre: "Es momento de activarse. ¡Ánimo!",
    tono: "warn",
  }),
  3: (nombre) => ({
    titulo: `Hola, ${nombre}`,
    cuerpo: "Tu indicador sigue apareciendo en 0 pendientes por tercer día consecutivo. ¿Sucede algo? ¿Tienes algún detalle con tu prospección?",
    cierre: "Te invitamos a acercarte a tu líder para que te ayude. ¡Ánimo!",
    tono: "alerta",
  }),
  4: (nombre) => ({
    titulo: `Hola, ${nombre}`,
    cuerpo: "Tu indicador sigue apareciendo en 0 tras varios días hábiles. Eres muy importante para el equipo, pero también recuerda que se nos mide la productividad personal día a día sin excepción y tus números son preocupantes.",
    cierre: "¡Te hacemos la invitación a que mejores tus números!",
    tono: "alerta",
  }),
  5: (nombre) => ({
    titulo: `Apreciable ${nombre}`,
    cuerpo: "Se le informa que al 5to día si su actividad sigue en 0 se dará de baja su acceso al sistema.",
    cierre: "Ya que la falta de productividad permanente es inaceptable en las políticas internas. Gracias por su atención.",
    tono: "critico",
  }),
};

/* ── Recordatorio flotante de productividad (asesor) ──
   Se monta siempre que el asesor está dentro de su panel, sin importar la pantalla en la
   que se encuentre. Revisa cada minuto si corresponde mostrar el aviso, según el indicador
   de "PENDIENTES DE HOY" y la racha de días consecutivos en 0 (histórico permanente). */
function RecordatorioProductividad({ session, onLogout }) {
  const [aviso, setAviso] = useState(null);
  const nombreCorto = nombreCortoAsesor(session.nombre);

  useEffect(() => {
    let activo = true;

    const evaluar = async () => {
      const hoy = fechaLocalISO();
      const horaActual = new Date().getHours();

      let citas = [];
      try {
        citas = await loadCitas(session.id);
      } catch { citas = []; }
      const citasHoy = citas.filter((c) => c.fecha === hoy);

      let finalizadosHoySet = new Set();
      try {
        const raw = localStorage.getItem(`finalizados-${session.id}-${hoy}`);
        if (raw) finalizadosHoySet = new Set(JSON.parse(raw));
      } catch {}
      const pendientesHoyLive = Math.max(0, citasHoy.length - finalizadosHoySet.size);

      const resultado = await evaluarProductividadAsesor(session.id, { pendientesHoyLive, citasPrecargadas: citas });
      if (!activo) return;

      // Baja automática detectada durante la sesión activa del asesor
      if (resultado.bajaAhora) {
        try {
          const advisorsList = await loadAdvisors();
          const actualizados = advisorsList.map((a) => (a.id === session.id ? { ...a, activo: false } : a));
          await saveAdvisors(actualizados);
        } catch {}
        if (onLogout) onLogout();
        return;
      }

      if (pendientesHoyLive > 0 || horaActual < 8 || horaActual >= 17) { setAviso(null); return; }

      const nivel = Math.min(5, resultado.diasConsecutivosCero + 1);

      if (nivel >= 5) {
        // Nivel 5: aviso único de 10 segundos, no se repite cada 2 horas
        let yaMostrado = null;
        try { yaMostrado = localStorage.getItem(`avisoProdNivel5-${session.id}-${hoy}`); } catch {}
        if (!yaMostrado) {
          try { localStorage.setItem(`avisoProdNivel5-${session.id}-${hoy}`, "1"); } catch {}
          setAviso({ nivel: 5, ...MENSAJES_PRODUCTIVIDAD[5](nombreCorto) });
          setTimeout(() => { if (activo) setAviso(null); }, 10000);
        }
        return;
      }

      // Niveles 1-4: un aviso por cada franja de 2 horas (8, 10, 12, 14, 16), dentro de la ventana 8:00-17:00
      const checkpointActual = HORAS_RECORDATORIO_PRODUCTIVIDAD.filter((h) => h <= horaActual).pop();
      if (!checkpointActual) return;
      let mostrados = [];
      try { mostrados = JSON.parse(localStorage.getItem(`avisoProdMostrados-${session.id}-${hoy}`) || "[]"); } catch { mostrados = []; }
      if (!mostrados.includes(checkpointActual)) {
        try { localStorage.setItem(`avisoProdMostrados-${session.id}-${hoy}`, JSON.stringify([...mostrados, checkpointActual])); } catch {}
        setAviso({ nivel, ...MENSAJES_PRODUCTIVIDAD[nivel](nombreCorto) });
      }
    };

    evaluar();
    const iv = setInterval(evaluar, 60000);
    return () => { activo = false; clearInterval(iv); };
  }, [session.id]);

  if (!aviso) return null;

  const COLORES_TONO = {
    info: "#1A1A1A",
    warn: "#B45309",
    alerta: "#991B1B",
    critico: "#450A0A",
  };
  const colorTono = COLORES_TONO[aviso.tono] || COLORES_TONO.info;
  const icono = aviso.nivel >= 5 ? "🚨" : aviso.nivel >= 3 ? "⚠️" : "👋";

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.7)", zIndex: 99999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
      <div style={{ background: "#fff", borderRadius: 14, width: "100%", maxWidth: 420, boxShadow: "0 16px 48px rgba(0,0,0,0.45)", overflow: "hidden" }}>
        <div style={{ background: colorTono, padding: "18px 22px" }}>
          <div style={{ fontSize: 28, marginBottom: 6 }}>{icono}</div>
          <div className="display" style={{ color: "#fff", fontSize: 16, fontWeight: 800, lineHeight: 1.35 }}>{aviso.titulo}</div>
        </div>
        <div style={{ padding: "18px 22px" }}>
          <div style={{ fontSize: 14, color: "#142B4D", lineHeight: 1.5, marginBottom: 10 }}>{aviso.cuerpo}</div>
          <div style={{ fontSize: 14, color: "#142B4D", fontWeight: 700, lineHeight: 1.5 }}>{aviso.cierre}</div>
        </div>
        {aviso.nivel < 5 ? (
          <div style={{ padding: "0 22px 18px" }}>
            <button onClick={() => setAviso(null)} style={{ width: "100%", padding: "13px", border: "none", borderRadius: 8, background: colorTono, color: "#fff", fontWeight: 800, fontSize: 15, cursor: "pointer" }}>
              ✓ Entendido
            </button>
          </div>
        ) : (
          <div style={{ padding: "0 22px 18px", fontSize: 11, color: "#9CA3AF", textAlign: "center" }}>Este aviso se cerrará automáticamente…</div>
        )}
      </div>
    </div>
  );
}

// Nivel 2 de restricción móvil: exige que coincidan tanto el user-agent de un teléfono
// como un ancho de pantalla angosto, para no bloquear por error una ventana de escritorio
// achicada, y para no saltarse la restricción solo activando "modo escritorio" del ancho.
function esDispositivoMovil() {
  if (typeof navigator === "undefined" || typeof window === "undefined") return false;
  const uaMovil = /Android|iPhone|iPod|iPad|Mobile|Tablet/i.test(navigator.userAgent || "");
  // Pantalla no muy ancha (cubre también tablets/celulares grandes en horizontal) — 1024, no 768.
  const pantallaAngosta = window.innerWidth < 1024;
  const esTactilPrincipal = typeof window.matchMedia === "function" && window.matchMedia("(pointer: coarse)").matches;
  // Basta con que se cumpla CUALQUIERA de las tres señales — así un celular en "modo escritorio"
  // (que cambia su identificación de navegador) sigue detectándose por pantalla angosta o táctil.
  return uaMovil || pantallaAngosta || esTactilPrincipal;
}
function useEsDispositivoMovil() {
  const [esMovil, setEsMovil] = useState(esDispositivoMovil());
  useEffect(() => {
    const onResize = () => setEsMovil(esDispositivoMovil());
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);
  return esMovil;
}

function AsesorPanel(props) {
  return (
    <>
      <RecordatorioProductividad session={props.session} onLogout={props.onLogout} />
      <AsesorPanelInterno {...props} />
    </>
  );
}

function AsesorPanelInterno({ session, solicitudes, cotizaciones, totalSolicitudes, onLogout, onRefresh }) {
  const [view, setView] = useState("inicio");
  const esMovil = useEsDispositivoMovil();
  const VISTAS_PERMITIDAS_MOVIL = ["inicio", "agenda", "entrenamiento"];

  // Si el asesor entra desde un celular, solo puede ver Agenda Virtual y Entrenamiento de Ventas.
  // Si por alguna razón la vista actual no está permitida (ej. cambió de tamaño de ventana), regresa a inicio.
  useEffect(() => {
    if (esMovil && !VISTAS_PERMITIDAS_MOVIL.includes(view)) setView("inicio");
  }, [esMovil, view]);

  const misCotizaciones = (cotizaciones || []).filter((c) => c.asesorId === session.id);
  const misSolicitudes = solicitudes || [];

  if (esMovil && !VISTAS_PERMITIDAS_MOVIL.includes(view)) return null;

  if (view === "nueva") return <NuevaSolicitud session={session} existingCount={totalSolicitudes} onDone={async () => { await onRefresh(); setView("inicio"); }} onCancel={() => setView("inicio")} />;
  if (view === "practica") return <NuevaSolicitudPractica session={session} onDone={async () => { await onRefresh(); setView("inicio"); }} onCancel={() => setView("inicio")} />;
  if (view === "cotizador") return <CotizadorPanel session={session} canManage={false} onClose={() => setView("inicio")} onSaved={async () => { await onRefresh(); }} />;
  if (view === "solicitudes") return (
    <div key="vista-solicitudes" onContextMenu={(e) => e.preventDefault()}>
      <TopBar title="Mis Solicitudes" subtitle={session.nombre} onLogout={null} right={<button onClick={() => setView("inicio")} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: "#D6452B", color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>} />
      <div style={{ maxWidth: 800, margin: "0 auto", padding: "24px 20px" }}>
        {misSolicitudes.length === 0 ? <div style={{ textAlign: "center", color: "#6B7280", padding: 32 }}>No has capturado ninguna solicitud todavía.</div> : (
          <div style={{ background: "#fff", borderRadius: 6, overflow: "hidden", border: "1px solid #E3DECF" }}>
            {misSolicitudes.slice().sort((a, b) => (b.fechaCreacion || "").localeCompare(a.fechaCreacion || "")).map((s, i) => {
              const isPrueba = s.esPractica === true;
              return (
                <div key={s.id} style={{ padding: "7px 16px", borderTop: i === 0 ? "none" : "1px solid #E3DECF", display: "flex", justifyContent: "space-between", alignItems: "center", background: isPrueba ? "#FFFBEB" : "#fff" }}>
                  <div>
                    <div style={{ fontWeight: 600, fontSize: 13, display: "flex", alignItems: "center", gap: 6 }}>
                      {s.nombre || "(sin nombre)"}
                      {isPrueba && <span style={{ background: "#F59E0B", color: "#fff", fontSize: 9, fontWeight: 700, padding: "1px 6px", borderRadius: 10 }}>PRUEBA</span>}
                    </div>
                    <div style={{ fontSize: 11, color: "#6B7280", marginTop: 1 }}>
                      Folio {s.folioContrato} · {s.fechaCreacion} · <strong style={{ color: "#142B4D" }}>{fmtMoney(s.montoContratado)}</strong>
                    </div>
                  </div>
                  <EstadoBadge estado={s.estatus} />
                </div>
              );
            })}
          </div>
        )}
        <div style={{ marginTop: 16, fontSize: 12, color: "#6B7280", textAlign: "center" }}>Esta información solo puede ser impresa o exportada por el administrador.</div>
      </div>
    </div>
  );

  if (view === "historial") return <HistorialCotizacionesPanel cotizaciones={misCotizaciones} showAsesor={false} onClose={() => setView("inicio")} />;
  if (view === "agenda") return <AgendaVirtual session={session} onClose={() => setView("inicio")} />;
  if (view === "entrenamiento") return <EntrenamientoVentas session={session} onClose={() => setView("inicio")} />;

  return (
    <div key="vista-inicio" onContextMenu={(e) => e.preventDefault()}>
      <TopBar title={`Hola, ${session.nombre}`} subtitle={`Captura de clientes · ${fmtDate(today())}`} onLogout={onLogout} right={
        <div style={{ textAlign: "center", flex: 1 }}>
          <div className="display" style={{ fontSize: 20, fontWeight: 700, color: "#fff", letterSpacing: 0.5, lineHeight: 1.4 }}>El panel está listo.</div>
          <div className="display" style={{ fontSize: 18, fontWeight: 700, color: "#F7E820", letterSpacing: 0.3 }}>¡Hoy es un excelente día para ganar!</div>
        </div>
      } />

      <div style={{ maxWidth: 820, margin: "0 auto", padding: "24px 20px" }}>
        <div style={{ display: "flex", gap: 8, alignItems: "baseline", marginBottom: 16, fontSize: 13, color: "#6B7280" }}>
          <span style={{ fontWeight: 800, color: "#142B4D" }}>💡 Tip del día:</span>
          <span>{TIPS_DIARIOS[new Date().getDate() % TIPS_DIARIOS.length]}</span>
        </div>
        {esMovil ? (
          <div>
            <div style={{ background: "#FFFBEB", border: "1px solid #F5C518", borderRadius: 8, padding: "10px 14px", marginBottom: 16, fontSize: 12.5, color: "#92400E" }}>
              🔒 Por seguridad, desde un celular solo puedes acceder a Agenda Virtual y Entrenamiento de Ventas. El resto de la plataforma solo está disponible desde computadora.
            </div>
            <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
              <Card color="#1A1A1A" icon={<span style={{fontSize:32, background:"#F5C518", borderRadius:8, padding:"4px 6px", lineHeight:1, display:"inline-block"}}>🔭</span>} title="Agenda Virtual" subtitle="Gestiona y haz seguimiento de tus citas con clientes" onClick={() => setView("agenda")} />
              <Card color="#4A90D9" icon="📢" title="Entrenamiento de Ventas" subtitle="Aprende y perfecciona técnicas de venta efectivas" onClick={() => setView("entrenamiento")} />
            </div>
          </div>
        ) : (
          <>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
              {/* Fila 1 */}
              <Card color="#FFFFFF" textColor="#142B4D" icon="➕" title="Nueva Solicitud de Cliente" subtitle="Inicia un nuevo registro de cliente y solicitud de financiamiento" onClick={() => setView("nueva")} border="1px solid #E5E7EB" />
              <Card color="#F5923E" icon="🧮" title="Cotizador de Financiamiento" subtitle="Accede a la herramienta de cálculo para nuevos clientes" onClick={() => setView("cotizador")} />
              {/* Fila 2 */}
              <Card color="#27AE60" icon="📋" title="Mis Solicitudes" subtitle={`Sigue el estado de todas tus solicitudes (${misSolicitudes.length} registradas)`} onClick={() => setView("solicitudes")} />
              <Card color="#F5C518" textColor="#142B4D" icon="📊" title="Historial Cotizaciones" subtitle="Ver historial completo de cotizaciones y su estatus" onClick={() => setView("historial")} />
            </div>

            {/* Fila 3 */}
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 12, marginTop: 12 }}>
              <Card color="#4A90D9" icon="📢" title="Entrenamiento de Ventas" subtitle="Aprende y perfecciona técnicas de venta efectivas" onClick={() => setView("entrenamiento")} />
              <Card color="#6C7A89" icon="🎓" title="Área de Práctica" subtitle="Realiza simulaciones de crédito en entorno seguro" onClick={() => setView("practica")} />
              <Card color="#1A1A1A" icon={<span style={{fontSize:32, background:"#F5C518", borderRadius:8, padding:"4px 6px", lineHeight:1, display:"inline-block"}}>🔭</span>} title="Agenda Virtual" subtitle="Gestiona y haz seguimiento de tus citas con clientes" onClick={() => setView("agenda")} />
            </div>
          </>
        )}

        <div style={{ marginTop: 20, fontSize: 12, color: "#6B7280", textAlign: "center" }}>Esta información solo puede ser impresa o exportada por el administrador.</div>
      </div>
    </div>
  );
}


function NuevaSolicitudPractica({ session, onDone, onCancel }) {
  const [stepIdx, setStepIdx] = useState(0);
  const [data, setData] = useState(emptySolicitud());
  const [saving, setSaving] = useState(false);
  const [emptyFields, setEmptyFields] = useState(new Set());
  const [showAlert, setShowAlert] = useState(false);
  const [showWarning, setShowWarning] = useState(true);
  const [folioAgotado, setFolioAgotado] = useState(false);
  const step = STEPS[stepIdx];
  const isLast = stepIdx === STEPS.length - 1;
  const isReview = stepIdx === STEPS.length;

  const update = (key, val) => {
    setData((d) => ({ ...d, [key]: val }));
    if (emptyFields.has(key)) {
      setEmptyFields((prev) => { const s = new Set(prev); s.delete(key); return s; });
    }
  };

  const { inscripcion, cuota: mensualidad, total: importeTotal } = calcMontos(data.montoContratado);

  const validateAll = () => {
    const empty = new Set();
    STEPS.forEach((s) => { s.fields.forEach((f) => { if (!f.optional && !String(data[f.key] || "").trim()) empty.add(f.key); }); });
    return empty;
  };
  const validateCurrentStep = () => {
    const empty = new Set();
    step.fields.forEach((f) => { if (!f.optional && !String(data[f.key] || "").trim()) empty.add(f.key); });
    return empty;
  };

  const [submitError, setSubmitError] = useState("");
  const submit = async () => {
    const empty = validateAll();
    if (empty.size > 0) {
      setEmptyFields(empty);
      setShowAlert(true);
      setTimeout(() => setShowAlert(false), 5000);
      for (let i = 0; i < STEPS.length; i++) {
        if (STEPS[i].fields.some((f) => empty.has(f.key))) { setStepIdx(i); break; }
      }
      return;
    }
    setSaving(true);
    setSubmitError("");
    try {
      const existing = await loadSolicitudes();
      // La validación de duplicado solo compara contra solicitudes activas — una ya cancelada
      // (en la papelera) no debe bloquear un registro nuevo y legítimo del mismo cliente.
      const yaExiste = existing.filter((s) => !s.eliminada).some((s) =>
        (s.nombre || "").trim().toLowerCase() === (data.nombre || "").trim().toLowerCase() &&
        s.fechaNacimiento === data.fechaNacimiento
      );
      if (yaExiste) {
        setSaving(false);
        setSubmitError("Ya existe una solicitud con el mismo nombre y fecha de nacimiento. No se puede duplicar.");
        return;
      }
      // El folio de práctica solo se reserva aquí, cuando ya sabemos que sí se va a guardar.
      const folio = await getNextFolioPractica();
      if (!folio) { setFolioAgotado(true); setSaving(false); return; }
      const record = {
        ...data,
        inscripcionIva: inscripcion,
        asesorId: session.id,
        asesorNombre: session.nombre,
        folioNumero: folio.numero,
        folioContrato: folio.contrato,
        fechaCreacion: fmtDate(today()),
        fechaHoraCreacion: new Date().toISOString(),
        estatus: "Nueva",
        esPractica: true,
      };
      await conReintento(() => saveSolicitudes([...existing, record]));
    } catch (err) { setSaving(false); setSubmitError(err?.message ? `No se pudo guardar: ${err.message}` : "No se pudo guardar. Intenta de nuevo."); return; }
    setSaving(false);
    onDone();
  };

  const handleNext = () => {
    const empty = validateCurrentStep();
    if (empty.size > 0) {
      setEmptyFields((prev) => new Set([...prev, ...empty]));
      setShowAlert(true);
      setTimeout(() => setShowAlert(false), 5000);
      return;
    }
    setStepIdx(stepIdx + 1);
  };

  if (folioAgotado) return (
    <div style={{ maxWidth: 500, margin: "60px auto", background: "#fff", borderRadius: 8, padding: 32, textAlign: "center", border: `1px solid ${COLORS.line}` }}>
      <div style={{ fontSize: 36, marginBottom: 12 }}>⚠️</div>
      <div style={{ fontSize: 18, fontWeight: 700, color: COLORS.navy, marginBottom: 10 }}>Folios de práctica agotados</div>
      <div style={{ fontSize: 14, color: COLORS.slate, marginBottom: 20 }}>Ambos folios de práctica (72510008 y 72510009) ya están en uso. El Administrador General debe presionar <strong>"Reiniciar pruebas"</strong> antes de continuar.</div>
      <button onClick={onCancel} style={secondaryBtnStyle}>← Volver</button>
    </div>
  );

  return (
    <div onContextMenu={(e) => e.preventDefault()}>
      {showWarning && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.6)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
          <div style={{ background: "#FFFBEB", border: `2px solid #F59E0B`, borderRadius: 10, padding: 30, maxWidth: 460, width: "100%", boxShadow: "0 8px 32px rgba(0,0,0,0.3)", textAlign: "center" }}>
            <div style={{ fontSize: 40, marginBottom: 10 }}>🧪</div>
            <div style={{ fontSize: 18, fontWeight: 700, color: "#92400E", marginBottom: 8 }}>SOLICITUD DE PRÁCTICA</div>
            <div style={{ fontSize: 13, color: "#78350F", lineHeight: 1.6, marginBottom: 8 }}>
              Esta solicitud usará un <strong>folio de práctica</strong> (72510008 ó 72510009).<br />
              <strong style={{ color: COLORS.red }}>No tiene validez comercial.</strong>
            </div>
            <div style={{ fontSize: 13, color: COLORS.slate, lineHeight: 1.6, marginBottom: 20 }}>
              Rellena los campos con la información correcta del cliente. No hacerlo puede generar una cancelación con un <strong style={{ color: COLORS.red }}>costo administrativo de $500</strong>.
            </div>
            <button onClick={() => setShowWarning(false)} style={{ ...primaryBtnStyle, background: "#F59E0B", padding: "12px 32px", fontSize: 15 }}>
              Entendido, practicar
            </button>
          </div>
        </div>
      )}

      {showAlert && (
        <div style={{ position: "fixed", top: 20, left: "50%", transform: "translateX(-50%)", background: "#fff", border: `2px solid ${COLORS.red}`, borderRadius: 8, padding: "14px 20px", zIndex: 9999, boxShadow: "0 6px 24px rgba(0,0,0,0.18)", maxWidth: 480, width: "90%", textAlign: "center", fontSize: 14, fontWeight: 600, color: COLORS.red }}>
          ⚠️ ¡Verifique de nuevo sus campos. Uno o más campos no están rellenados. Rellene los campos correctamente para continuar!
        </div>
      )}

      <TopBar title="Solicitud de Práctica" subtitle={`🧪 Folio de capacitación · ${session.nombre}`} onLogout={null} right={<button onClick={onCancel} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: "#D6452B", color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>} />
      <div style={{ background: "#FEF3C7", padding: "8px 20px", textAlign: "center", fontSize: 13, fontWeight: 600, color: "#92400E" }}>
        🧪 Esta solicitud es de práctica — Folio 72510008 ó 72510009 — SIN VALOR COMERCIAL
      </div>
      <div style={{ maxWidth: 720, margin: "0 auto", padding: "24px 20px 60px" }}>
        <div style={{ display: "flex", gap: 4, marginBottom: 22 }}>
          {STEPS.map((s, i) => (<div key={i} style={{ flex: 1, height: 4, borderRadius: 2, background: i <= stepIdx ? "#F59E0B" : COLORS.line }} />))}
        </div>

        {!isReview ? (
          <div style={{ background: "#fff", borderRadius: 6, border: `2px solid #F59E0B`, padding: 24 }}>
            <div className="display" style={{ fontSize: 12, letterSpacing: 1.5, color: "#F59E0B", textTransform: "uppercase", fontWeight: 600, marginBottom: 4 }}>
              Paso {stepIdx + 1} de {STEPS.length} — PRÁCTICA
            </div>
            <div className="display" style={{ fontSize: 22, fontWeight: 600, color: COLORS.navy, marginBottom: 4 }}>{step.title}</div>
            {step.note && <div style={{ fontSize: 12, color: COLORS.slateSoft, marginBottom: 14 }}>{step.note}</div>}
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, marginTop: 16 }}>
              {step.fields.map((f) => {
                const isEmpty = emptyFields.has(f.key);
                return (
                  <div key={f.key} style={{ gridColumn: f.span === 2 ? "1 / -1" : "auto" }}>
                    <label style={{ fontSize: 12, fontWeight: 600, display: "flex", alignItems: "center", gap: 4, marginBottom: 5, color: isEmpty ? COLORS.red : COLORS.slate }}>
                      {f.label}{isEmpty && <span style={{ color: COLORS.red, fontWeight: 700, fontSize: 13 }}>✕</span>}
                    </label>
                    {f.type === "select" ? (
                      <select value={data[f.key]} onChange={(e) => update(f.key, e.target.value)} style={{ ...inputStyle, border: isEmpty ? `1.5px solid ${COLORS.red}` : `1px solid ${COLORS.line}` }}>
                        <option value="">Selecciona…</option>
                        {f.options.map((o) => <option key={o} value={o}>{o}</option>)}
                      </select>
                    ) : f.prefix ? (
                      <div style={{ position: "relative" }}>
                        <span style={{ position: "absolute", left: 11, top: "50%", transform: "translateY(-50%)", color: "#6B7280", fontSize: 14, pointerEvents: "none" }}>{f.prefix}</span>
                        <input type="number" value={data[f.key]} onChange={(e) => update(f.key, e.target.value)} style={{ ...inputStyle, paddingLeft: 22, border: isEmpty ? `1.5px solid ${COLORS.red}` : `1px solid ${COLORS.line}` }} />
                      </div>
                    ) : (
                      <input
                        type={f.type === "date" ? "date" : f.type === "number" ? "number" : "text"}
                        inputMode={f.numericOnly ? "numeric" : undefined}
                        maxLength={f.numericOnly ? 5 : undefined}
                        value={data[f.key]}
                        onChange={(e) => update(f.key, f.numericOnly ? e.target.value.replace(/\D/g, "") : e.target.value)}
                        style={{ ...inputStyle, border: isEmpty ? `1.5px solid ${COLORS.red}` : `1px solid ${COLORS.line}` }}
                      />
                    )}
                  </div>
                );
              })}
              {step.title === "Datos del Solicitante" && data.fechaNacimiento && (
                <div style={{ gridColumn: "1 / -1", fontSize: 12, color: COLORS.slateSoft }}>Edad: <strong>{calcEdad(data.fechaNacimiento)} años</strong></div>
              )}
              {step.title === "Descripción del Bien Contratado" && data.montoContratado && (
                <div style={{ gridColumn: "1 / -1", background: COLORS.cream, borderRadius: 4, padding: 12, fontSize: 13 }} className="no-select">
                  <div>Inscripción con IVA: <strong>{fmtMoney(inscripcion)}</strong></div>
                  <div>1ra cuota periódica: <strong>{fmtMoney(mensualidad)}</strong></div>
                  <div>Importe total: <strong>{fmtMoney(importeTotal)}</strong></div>
                </div>
              )}
            </div>
            <div style={{ display: "flex", justifyContent: "space-between", marginTop: 24 }}>
              <button onClick={() => (stepIdx === 0 ? onCancel() : setStepIdx(stepIdx - 1))} style={secondaryBtnStyle}>{stepIdx === 0 ? "Cancelar" : "Atrás"}</button>
              <button onClick={handleNext} style={{ ...primaryBtnStyle, background: "#F59E0B" }}>{isLast ? "Revisar y enviar" : "Siguiente"}</button>
            </div>
          </div>
        ) : (
          <div style={{ background: "#fff", borderRadius: 6, border: `2px solid #F59E0B`, padding: 24 }}>
            <div className="display" style={{ fontSize: 22, fontWeight: 600, color: COLORS.navy, marginBottom: 4 }}>Revisión final — PRÁCTICA</div>
            <SectionGrid title="Solicitante" data={[["Nombre", data.nombre], ["RFC", data.rfc], ["CURP", data.curp]]} />
            <SectionGrid title="Vehículo" data={[["Unidad", data.marcaTipo], ["Monto", fmtMoney(data.montoContratado)], ["Inscripción c/IVA", fmtMoney(inscripcion)], ["1ra cuota", fmtMoney(mensualidad)], ["Importe total", fmtMoney(importeTotal)]]} />
            <div style={{ display: "flex", justifyContent: "space-between", marginTop: 24, alignItems: "center" }}>
              <button onClick={() => setStepIdx(STEPS.length - 1)} style={secondaryBtnStyle}>Atrás</button>
              {submitError && <div style={{ color: COLORS.red, fontSize: 13 }}>{submitError}</div>}
              <button onClick={submit} disabled={saving} style={{ ...primaryBtnStyle, background: "#F59E0B" }}>
                {saving ? "Guardando…" : "Guardar solicitud de práctica"}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

function NuevaSolicitud({ session, existingCount, onDone, onCancel }) {
  const borradorKey = `borrador-solicitud-${session.id}`;
  const [stepIdx, setStepIdx] = useState(0);
  const [data, setData] = useState(emptySolicitud());
  const [saving, setSaving] = useState(false);
  const [emptyFields, setEmptyFields] = useState(new Set());
  const [showAlert, setShowAlert] = useState(false);
  const [showWarning, setShowWarning] = useState(true); // Alerta inicial de advertencia
  const [borradorEncontrado, setBorradorEncontrado] = useState(null); // {data, stepIdx, guardadoEl} | null
  const [borradorResuelto, setBorradorResuelto] = useState(false); // ya se preguntó/decidió qué hacer con el borrador
  const [folioManual, setFolioManual] = useState(null); // {numero, contrato} | null — si el asesor lo escribió a mano
  const [showFolioManual, setShowFolioManual] = useState(false); // cuadro flotante abierto/cerrado
  const [folioManualNumero, setFolioManualNumero] = useState("");
  const [folioManualContrato, setFolioManualContrato] = useState("");
  const [folioManualError, setFolioManualError] = useState("");

  // Al entrar, revisa si hay un formulario sin terminar guardado en este dispositivo
  // (por ejemplo, si la sesión se cerró sola por inactividad a la mitad de la captura).
  useEffect(() => {
    try {
      const guardado = localStorage.getItem(borradorKey);
      if (guardado) {
        const parsed = JSON.parse(guardado);
        setBorradorEncontrado(parsed);
      } else {
        setBorradorResuelto(true);
      }
    } catch { setBorradorResuelto(true); }
  }, []);

  // Guarda el avance automáticamente cada vez que cambia algo, para no perderlo si la
  // sesión se cierra por inactividad — la sesión sí se cierra (por seguridad), pero el
  // trabajo ya escrito se recupera al volver a entrar.
  useEffect(() => {
    if (!borradorResuelto) return; // no pisar el borrador viejo antes de decidir qué hacer con él
    try {
      localStorage.setItem(borradorKey, JSON.stringify({ data, stepIdx, guardadoEl: new Date().toISOString() }));
    } catch {}
  }, [data, stepIdx, borradorResuelto]);

  const continuarBorrador = () => {
    setData(borradorEncontrado.data);
    setStepIdx(borradorEncontrado.stepIdx || 0);
    setBorradorEncontrado(null);
    setBorradorResuelto(true);
  };
  const descartarBorrador = () => {
    try { localStorage.removeItem(borradorKey); } catch {}
    setBorradorEncontrado(null);
    setBorradorResuelto(true);
  };

  const abrirFolioManual = () => {
    setFolioManualNumero(folioManual?.numero || "");
    setFolioManualContrato(folioManual?.contrato || "");
    setFolioManualError("");
    setShowFolioManual(true);
  };
  const confirmarFolioManual = async () => {
    const numero = folioManualNumero.trim();
    const contrato = folioManualContrato.trim();
    if (!numero || !contrato) {
      setFolioManualError("Escribe ambos números para continuar.");
      return;
    }
    try {
      const existentes = await loadSolicitudes();
      const yaExisteNumero = existentes.some((s) => !s.eliminada && String(s.folioNumero) === numero);
      const yaExisteContrato = existentes.some((s) => !s.eliminada && String(s.folioContrato) === contrato);
      if (yaExisteNumero || yaExisteContrato) {
        setFolioManualError("Ese número ya está usado en otra solicitud. Escribe uno distinto.");
        return;
      }
    } catch {
      // si no se pudo verificar por un problema de conexión, se deja continuar de todas formas
    }
    setFolioManual({ numero, contrato });
    setShowFolioManual(false);
  };
  const quitarFolioManual = () => {
    setFolioManual(null);
    setFolioManualNumero("");
    setFolioManualContrato("");
    setShowFolioManual(false);
  };

  const step = STEPS[stepIdx];
  const isLast = stepIdx === STEPS.length - 1;
  const isReview = stepIdx === STEPS.length;

  const update = (key, val) => {
    setData((d) => ({ ...d, [key]: val }));
    if (emptyFields.has(key)) {
      setEmptyFields((prev) => { const s = new Set(prev); s.delete(key); return s; });
    }
  };

  const { inscripcion, cuota: mensualidad, total: importeTotal } = calcMontos(data.montoContratado);

  // Validar todos los campos requeridos de todos los pasos
  const validateAll = () => {
    const empty = new Set();
    STEPS.forEach((s) => {
      s.fields.forEach((f) => {
        if (!f.optional && !String(data[f.key] || "").trim()) {
          empty.add(f.key);
        }
      });
    });
    return empty;
  };

  // Validar solo el paso actual
  const validateCurrentStep = () => {
    const empty = new Set();
    step.fields.forEach((f) => {
      if (!f.optional && !String(data[f.key] || "").trim()) {
        empty.add(f.key);
      }
    });
    return empty;
  };

  const [submitError, setSubmitError] = useState("");
  const submit = async () => {
    // Validar todos los pasos antes de enviar
    const empty = validateAll();
    if (empty.size > 0) {
      setEmptyFields(empty);
      setShowAlert(true);
      setTimeout(() => setShowAlert(false), 5000);
      // Ir al primer paso que tenga error
      for (let i = 0; i < STEPS.length; i++) {
        if (STEPS[i].fields.some((f) => empty.has(f.key))) {
          setStepIdx(i);
          break;
        }
      }
      return;
    }
    setSaving(true);
    setSubmitError("");
    try {
      const existing = await loadSolicitudes();
      // La validación de duplicado solo compara contra solicitudes activas — una ya cancelada
      // (en la papelera) no debe bloquear un registro nuevo y legítimo del mismo cliente.
      const yaExiste = existing.filter((s) => !s.eliminada).some((s) =>
        (s.nombre || "").trim().toLowerCase() === (data.nombre || "").trim().toLowerCase() &&
        s.fechaNacimiento === data.fechaNacimiento
      );
      if (yaExiste) {
        setSaving(false);
        setSubmitError("Ya existe una solicitud con el mismo nombre y fecha de nacimiento. No se puede duplicar.");
        return;
      }
      // El folio solo se reserva justo aquí, cuando ya sabemos que sí se va a guardar — nunca antes.
      // Si el asesor escribió un número a mano en el cuadro flotante, se usa ese en vez del automático.
      const folio = folioManual || await getNextFolio();
      const record = {
        ...data,
        inscripcionIva: inscripcion,
        asesorId: session.id,
        asesorNombre: session.nombre,
        folioNumero: folio.numero,
        folioContrato: folio.contrato,
        fechaCreacion: fmtDate(today()),
        fechaHoraCreacion: new Date().toISOString(),
        estatus: "Nueva",
        esPractica: false,
      };
      await conReintento(() => saveSolicitudes([...existing, record]));
    } catch (err) {
      setSaving(false);
      setSubmitError(err?.message ? `No se pudo enviar la solicitud: ${err.message}` : "No se pudo enviar la solicitud. Revisa tu conexión e intenta de nuevo.");
      return;
    }
    try { localStorage.removeItem(borradorKey); } catch {}
    setSaving(false);
    onDone();
  };

  const handleNext = () => {
    const empty = validateCurrentStep();
    if (empty.size > 0) {
      setEmptyFields((prev) => new Set([...prev, ...empty]));
      setShowAlert(true);
      setTimeout(() => setShowAlert(false), 5000);
      return;
    }
    setStepIdx(stepIdx + 1);
  };

  return (
    <div onContextMenu={(e) => e.preventDefault()}>
      {/* Aviso de borrador recuperado (formulario sin terminar de una sesión anterior) */}
      {borradorEncontrado && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.6)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
          <div style={{ background: "#fff", borderRadius: 10, padding: 30, maxWidth: 460, width: "100%", boxShadow: "0 8px 32px rgba(0,0,0,0.3)", textAlign: "center" }}>
            <div style={{ fontSize: 40, marginBottom: 10 }}>📝</div>
            <div style={{ fontSize: 18, fontWeight: 700, color: COLORS.navy, marginBottom: 12 }}>Tienes un formulario sin terminar</div>
            <div style={{ fontSize: 14, color: COLORS.slate, lineHeight: 1.6, marginBottom: 20 }}>
              Parece que la sesión se cerró antes de que terminaras de capturar una solicitud
              {borradorEncontrado.data?.nombre ? <> de <strong>{borradorEncontrado.data.nombre}</strong></> : ""}.
              ¿Quieres continuar donde te quedaste, o empezar una nueva?
            </div>
            <div style={{ display: "flex", gap: 10, justifyContent: "center" }}>
              <button onClick={continuarBorrador} style={{ ...primaryBtnStyle, padding: "12px 24px" }}>Continuar donde me quedé</button>
              <button onClick={descartarBorrador} style={secondaryBtnStyle}>Empezar de nuevo</button>
            </div>
          </div>
        </div>
      )}
      {/* Alerta flotante */}
      {/* Alerta de advertencia inicial */}
      {showWarning && !borradorEncontrado && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.6)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
          <div style={{ background: "#fff", borderRadius: 10, padding: 30, maxWidth: 460, width: "100%", boxShadow: "0 8px 32px rgba(0,0,0,0.3)", textAlign: "center" }}>
            <div style={{ fontSize: 40, marginBottom: 10 }}>⚠️</div>
            <div style={{ fontSize: 18, fontWeight: 700, color: COLORS.navy, marginBottom: 12 }}>Antes de continuar</div>
            <div style={{ fontSize: 14, color: COLORS.slate, lineHeight: 1.6, marginBottom: 20 }}>
              Rellene por favor bien los campos con la <strong>información correcta del cliente</strong>. No hacerlo puede generar una cancelación que tiene un <strong style={{ color: COLORS.red }}>costo administrativo de $500</strong>.
            </div>
            <button onClick={() => setShowWarning(false)} style={{ ...primaryBtnStyle, padding: "12px 32px", fontSize: 15 }}>
              Entendido, continuar
            </button>
          </div>
        </div>
      )}

      {showAlert && (
        <div style={{
          position: "fixed", top: 20, left: "50%", transform: "translateX(-50%)",
          background: "#fff", border: `2px solid ${COLORS.red}`, borderRadius: 8,
          padding: "14px 20px", zIndex: 9999, boxShadow: "0 6px 24px rgba(0,0,0,0.18)",
          maxWidth: 480, width: "90%", textAlign: "center",
          fontSize: 14, fontWeight: 600, color: COLORS.red,
        }}>
          ⚠️ ¡Verifique de nuevo sus campos. Uno o más campos no están rellenados. Rellene los campos correctamente para continuar!
        </div>
      )}

      <TopBar title="Nueva solicitud" subtitle={session.nombre} onLogout={null} right={
        <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
          {folioManual ? (
            <span onClick={abrirFolioManual} style={{ fontSize: 12, color: "#7BC67E", fontWeight: 700, cursor: "pointer" }}>
              🔢 Folio manual: {folioManual.contrato} (editar)
            </span>
          ) : (
            <button onClick={abrirFolioManual} style={{ padding: "10px 18px", border: "1px solid #fff", borderRadius: 6, background: "transparent", color: "#fff", cursor: "pointer", fontSize: 13, fontWeight: 700 }}>
              🔢 Escribir folio manual
            </button>
          )}
          <button onClick={onCancel} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: "#D6452B", color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>
        </div>
      } />

      {/* Cuadro flotante: escribir folio a mano */}
      {showFolioManual && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)", zIndex: 9500, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
          <div style={{ background: "#fff", borderRadius: 10, padding: 28, maxWidth: 440, width: "100%", boxShadow: "0 8px 32px rgba(0,0,0,0.25)" }}>
            <div style={{ fontSize: 18, fontWeight: 700, color: COLORS.navy, marginBottom: 6 }}>🔢 Escribir folio manualmente</div>
            <div style={{ fontSize: 13, color: COLORS.slate, marginBottom: 16 }}>
              Si no lo escribes, la plataforma le asigna el siguiente número automático al guardar.
            </div>
            <label style={{ fontSize: 12, fontWeight: 600, display: "block", marginBottom: 5 }}>No. de Solicitud</label>
            <input
              value={folioManualNumero}
              onChange={(e) => { setFolioManualNumero(e.target.value); setFolioManualError(""); }}
              placeholder="Ej. 72510008"
              style={{ width: "100%", padding: "10px 12px", border: `1.5px solid ${COLORS.line}`, borderRadius: 6, fontSize: 14, marginBottom: 12 }}
            />
            <label style={{ fontSize: 12, fontWeight: 600, display: "block", marginBottom: 5 }}>No. de Contrato</label>
            <input
              value={folioManualContrato}
              onChange={(e) => { setFolioManualContrato(e.target.value); setFolioManualError(""); }}
              placeholder="Ej. AL72510008"
              style={{ width: "100%", padding: "10px 12px", border: `1.5px solid ${COLORS.line}`, borderRadius: 6, fontSize: 14 }}
            />
            {folioManualError && <div style={{ color: COLORS.red, fontSize: 13, marginTop: 8 }}>{folioManualError}</div>}
            <div style={{ display: "flex", gap: 10, marginTop: 18 }}>
              <button onClick={confirmarFolioManual} style={primaryBtnStyle}>Aceptar</button>
              {folioManual && <button onClick={quitarFolioManual} style={secondaryBtnStyle}>Quitar folio manual</button>}
              <button onClick={() => setShowFolioManual(false)} style={secondaryBtnStyle}>Cancelar</button>
            </div>
          </div>
        </div>
      )}
      <div style={{ maxWidth: 720, margin: "0 auto", padding: "24px 20px 60px" }}>
        {/* progress */}
        <div style={{ display: "flex", gap: 4, marginBottom: 22 }}>
          {STEPS.map((s, i) => (
            <div key={i} style={{ flex: 1, height: 4, borderRadius: 2, background: i <= stepIdx ? COLORS.red : COLORS.line }} />
          ))}
        </div>

        {!isReview ? (
          <div style={{ background: "#fff", borderRadius: 6, border: `1px solid ${COLORS.line}`, padding: 24 }}>
            <div className="display" style={{ fontSize: 12, letterSpacing: 1.5, color: COLORS.red, textTransform: "uppercase", fontWeight: 600, marginBottom: 4 }}>
              Paso {stepIdx + 1} de {STEPS.length}
            </div>
            <div className="display" style={{ fontSize: 22, fontWeight: 600, color: COLORS.navy, marginBottom: 4 }}>{step.title}</div>
            {step.note && <div style={{ fontSize: 12, color: COLORS.slateSoft, marginBottom: 14 }}>{step.note}</div>}

            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, marginTop: 16 }}>
              {step.fields.map((f) => {
                const isEmpty = emptyFields.has(f.key);
                return (
                  <div key={f.key} style={{ gridColumn: f.span === 2 ? "1 / -1" : "auto" }}>
                    <label style={{ fontSize: 12, fontWeight: 600, display: "flex", alignItems: "center", gap: 4, marginBottom: 5, color: isEmpty ? COLORS.red : COLORS.slate }}>
                      {f.label}
                      {isEmpty && <span style={{ color: COLORS.red, fontWeight: 700, fontSize: 13 }}>✕</span>}
                    </label>
                    {f.type === "select" ? (
                      <select
                        value={data[f.key]}
                        onChange={(e) => update(f.key, e.target.value)}
                        style={{ ...inputStyle, border: isEmpty ? `1.5px solid ${COLORS.red}` : `1px solid ${COLORS.line}` }}
                      >
                        <option value="">Selecciona…</option>
                        {f.options.map((o) => <option key={o} value={o}>{o}</option>)}
                      </select>
                    ) : f.prefix ? (
                      <div style={{ position: "relative" }}>
                        <span style={{ position: "absolute", left: 11, top: "50%", transform: "translateY(-50%)", color: "#6B7280", fontSize: 14, pointerEvents: "none" }}>{f.prefix}</span>
                        <input
                          type="number"
                          value={data[f.key]}
                          onChange={(e) => update(f.key, e.target.value)}
                          style={{ ...inputStyle, paddingLeft: 22, border: isEmpty ? `1.5px solid ${COLORS.red}` : `1px solid ${COLORS.line}` }}
                        />
                      </div>
                    ) : (
                      <input
                        type={f.type === "date" ? "date" : f.type === "number" ? "number" : "text"}
                        inputMode={f.numericOnly ? "numeric" : undefined}
                        maxLength={f.numericOnly ? 5 : undefined}
                        value={data[f.key]}
                        onChange={(e) => update(f.key, f.numericOnly ? e.target.value.replace(/\D/g, "") : e.target.value)}
                        style={{ ...inputStyle, border: isEmpty ? `1.5px solid ${COLORS.red}` : `1px solid ${COLORS.line}` }}
                      />
                    )}
                  </div>
                );
              })}
              {step.title === "Datos del Solicitante" && data.fechaNacimiento && (
                <div style={{ gridColumn: "1 / -1", fontSize: 12, color: COLORS.slateSoft }}>
                  Edad calculada: <strong>{calcEdad(data.fechaNacimiento)} años</strong>
                </div>
              )}
              {step.title === "Descripción del Bien Contratado" && data.montoContratado && (
                <div style={{ gridColumn: "1 / -1", background: COLORS.cream, borderRadius: 4, padding: 12, fontSize: 13 }} className="no-select">
                  <div>Inscripción con IVA (3.5% + IVA): <strong>{fmtMoney(inscripcion)}</strong></div>
                  <div>1ra cuota periódica (factor 2.2%): <strong>{fmtMoney(mensualidad)}</strong></div>
                  <div>Importe total (inscripción + 1ra cuota): <strong>{fmtMoney(importeTotal)}</strong></div>
                </div>
              )}
            </div>

            <div style={{ display: "flex", justifyContent: "space-between", marginTop: 24 }}>
              <button onClick={() => (stepIdx === 0 ? onCancel() : setStepIdx(stepIdx - 1))} style={secondaryBtnStyle}>
                {stepIdx === 0 ? "Cancelar" : "Atrás"}
              </button>
              <button onClick={handleNext} style={primaryBtnStyle}>
                {isLast ? "Revisar y enviar" : "Siguiente"}
              </button>
            </div>
          </div>
        ) : (
          <div style={{ background: "#fff", borderRadius: 6, border: `1px solid ${COLORS.line}`, padding: 24 }}>
            <div className="display" style={{ fontSize: 22, fontWeight: 600, color: COLORS.navy, marginBottom: 4 }}>Revisión final</div>
            <div style={{ fontSize: 13, color: COLORS.slateSoft, marginBottom: 16 }}>
              Verifica los datos antes de enviar. Una vez enviada, la solicitud queda disponible para el administrador.
            </div>
            <SectionGrid title="Solicitante" data={[["Nombre", data.nombre], ["RFC", data.rfc], ["CURP", data.curp]]} />
            <SectionGrid title="Vehículo" data={[["Unidad", data.marcaTipo], ["Monto", fmtMoney(data.montoContratado)], ["Inscripción c/IVA", fmtMoney(inscripcion)], ["1ra cuota", fmtMoney(mensualidad)], ["Importe total", fmtMoney(importeTotal)]]} />
            <div style={{ display: "flex", justifyContent: "space-between", marginTop: 24, alignItems: "center" }}>
              <button onClick={() => setStepIdx(STEPS.length - 1)} style={secondaryBtnStyle}>Atrás</button>
              {submitError && <div style={{ color: COLORS.red, fontSize: 13, fontWeight: 500 }}>{submitError}</div>}
              <button onClick={submit} disabled={saving} style={primaryBtnStyle}>
                {saving ? "Enviando…" : "Enviar solicitud"}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

const inputStyle = {
  width: "100%",
  padding: "9px 11px",
  border: `1px solid ${COLORS.line}`,
  borderRadius: 4,
  fontSize: 14,
};

/* ============================================================
   COTIZADOR (interno, protegido — sin descarga ni exportación)
   Disponible para asesores y administradores
   ============================================================ */
const PLAN_KEYS = ["agencia", "ahorrador", "puntual60", "puntual48", "casaLiquidez"];

const emptyCotizadorForm = () => ({
  cliente: "", sucursal: "", unidad: "", color: "", modelo: "", anio: "",
  noCaratula: "", noContrato: "",
  precioLleno: "", precio: "",
});

function CotizadorPanel({ session, canManage, onClose, onSaved }) {
  const [form, setForm] = useState(emptyCotizadorForm());
  const [showCliente, setShowCliente] = useState(false);
  const [saving, setSaving] = useState(false);
  const [saveMsg, setSaveMsg] = useState("");
  const [confirmGuardar, setConfirmGuardar] = useState(false);
  const [camposVacios, setCamposVacios] = useState(new Set());
  const [alertaCampos, setAlertaCampos] = useState(false);
  const [alertaCamposOrigen, setAlertaCamposOrigen] = useState("guardar"); // "guardar" | "imprimir"
  const [confirmImprimir, setConfirmImprimir] = useState(false);
  const [showExito, setShowExito] = useState(false);

  // Campos obligatorios del Cotizador
  const CAMPOS_REQUERIDOS = ["cliente", "sucursal", "unidad", "color", "modelo", "anio", "precio", "noCaratula"];

  const updateCot = (key, val) => {
    setForm((f) => ({ ...f, [key]: val }));
    if (camposVacios.has(key)) {
      setCamposVacios((prev) => { const s = new Set(prev); s.delete(key); return s; });
    }
  };

  const [fechaHoraCotizacion] = useState(() => new Date());

  const cLabelStyle = { fontSize: 13, fontWeight: 700, display: "block", marginBottom: 5, color: "#fff", letterSpacing: 0.3, textShadow: "1px 1px 2px rgba(0,0,0,0.9), -1px -1px 1px rgba(0,0,0,0.5)" };

  const r = calcCotizador({ precio: form.precio, precioLleno: form.precioLleno });
  const hasPrecio = parseFloat(form.precio) > 0;
  const fechaCotizacionTxt = fmtDateTime(fechaHoraCotizacion);
  const fechaLimiteTxt = fmtDateTime(new Date(fechaHoraCotizacion.getTime() + 16 * 60 * 60 * 1000));

  const guardarCotizacion = async () => {
    setSaving(true);
    setSaveMsg("");
    try {
      const existing = await loadCotizaciones();
      const yaExiste = existing.some((c) =>
        String(c.noCaratula) === String(form.noCaratula) &&
        (c.cliente || "").trim().toLowerCase() === (form.cliente || "").trim().toLowerCase()
      );
      if (yaExiste) {
        setSaving(false);
        setSaveMsg("Ya existe una cotización con el mismo número de carátula y el mismo cliente. No se puede duplicar.");
        return;
      }
      const record = {
        ...form,
        id: uid(),
        asesorId: session.id,
        asesorNombre: session.nombre,
        fechaCreacion: fmtDate(today()),
        fechaHoraCreacion: fechaHoraCotizacion.toISOString(),
      };
      await saveCotizaciones([...existing, record]);
      if (onSaved) await onSaved();
      setShowExito(true);
    } catch (err) {
      setSaveMsg(err?.message ? `No se pudo guardar: ${err.message}` : "No se pudo guardar. Intenta de nuevo.");
    }
    setSaving(false);
  };

  if (showCliente) {
    return <CotizacionClientePrint form={form} r={r} canManage={canManage} onClose={() => setShowCliente(false)} />;
  }

  return (
    <div onContextMenu={(e) => e.preventDefault()} className="no-select">
      <TopBar title="Cotizador Autocon Management Group." subtitle={`Uso interno · ${session.nombre}`} onLogout={null} right={
        <button onClick={onClose} style={{ padding: "12px 28px", border: "none", borderRadius: 6, background: "#D6452B", color: "#fff", cursor: "pointer", fontSize: 15, fontWeight: 700 }}>← Salir</button>
      } />
      <div style={{ maxWidth: 980, margin: "0 auto", padding: "24px 20px 60px" }}>
        <div style={{ background: "#EAF1FB", border: `1px solid #C7D7EF`, borderRadius: 6, padding: "12px 16px", marginBottom: 20, fontSize: 13, color: COLORS.navy }}>
          <div style={{ display: "flex", flexWrap: "wrap", gap: 16, fontWeight: 600 }}>
            <div style={{ color: COLORS.navy }}>Fecha de Cotización: {fechaCotizacionTxt}</div>
            <div style={{ color: COLORS.red }}>Fecha y Hora Límite: {fechaLimiteTxt}</div>
          </div>
          <div style={{ fontSize: 11, fontStyle: "italic", marginTop: 6, color: COLORS.red, textShadow: "none" }}>
            * Precios, tasa y mensualidades vigentes hasta un plazo de 16 horas. Después de ese plazo límite se actualizan.<br />
            * Lugares limitados en el grupo de adjudicación del mes en curso.
          </div>
        </div>

        <div style={{ background: "#6A89A7", borderRadius: 6, border: `1px solid ${COLORS.line}`, padding: 24, marginBottom: 20 }}>
          <div className="display" style={{ fontSize: 16, fontWeight: 600, color: "#fff", marginBottom: 14, textTransform: "uppercase", letterSpacing: 0.5, background: "#163D6B", padding: "8px 12px", borderRadius: 4, marginLeft: -12, marginRight: -12, textShadow: "1px 1px 2px rgba(0,0,0,0.9), -1px -1px 1px rgba(0,0,0,0.5)" }}>
            Datos Generales
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
            <div><label style={{ ...cLabelStyle, color: camposVacios.has("cliente") ? COLORS.red : "#fff" }}>Cliente {camposVacios.has("cliente") && <span style={{ color: COLORS.red, fontWeight: 700 }}>✕</span>}</label><input value={form.cliente} onChange={(e) => updateCot("cliente", e.target.value)} style={{ ...inputStyle, border: camposVacios.has("cliente") ? `1.5px solid ${COLORS.red}` : `1px solid ${COLORS.line}` }} /></div>
            <div><label style={{ ...cLabelStyle, color: camposVacios.has("sucursal") ? COLORS.red : "#fff" }}>Sucursal {camposVacios.has("sucursal") && <span style={{ color: COLORS.red, fontWeight: 700 }}>✕</span>}</label><input value={form.sucursal} onChange={(e) => updateCot("sucursal", e.target.value)} style={{ ...inputStyle, border: camposVacios.has("sucursal") ? `1.5px solid ${COLORS.red}` : `1px solid ${COLORS.line}` }} /></div>
            {canManage && <div><label style={{ ...cLabelStyle, color: camposVacios.has("noCaratula") ? COLORS.red : "#fff" }}>No. de Carátula {camposVacios.has("noCaratula") && <span style={{ color: COLORS.red, fontWeight: 700 }}>✕</span>}</label><input value={form.noCaratula} onChange={(e) => updateCot("noCaratula", e.target.value)} placeholder="Ej. 72510020" style={{ ...inputStyle, border: camposVacios.has("noCaratula") ? `1.5px solid ${COLORS.red}` : `1px solid ${COLORS.line}` }} /></div>}
            {canManage && <div><label style={cLabelStyle}>No. de Contrato</label><input value={form.noContrato} onChange={(e) => updateCot("noContrato", e.target.value)} placeholder="Ej. AL72510020" style={inputStyle} /></div>}
          </div>
        </div>

        <div style={{ background: "#6A89A7", borderRadius: 6, border: `1px solid ${COLORS.line}`, padding: 24, marginBottom: 20 }}>
          <div className="display" style={{ fontSize: 16, fontWeight: 600, color: "#fff", marginBottom: 14, textTransform: "uppercase", letterSpacing: 0.5, background: "#163D6B", padding: "8px 12px", borderRadius: 4, marginLeft: -12, marginRight: -12, textShadow: "1px 1px 2px rgba(0,0,0,0.9), -1px -1px 1px rgba(0,0,0,0.5)" }}>
            Datos del Vehículo
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
            <div><label style={{ ...cLabelStyle, color: camposVacios.has("unidad") ? COLORS.red : "#fff" }}>Unidad {camposVacios.has("unidad") && <span style={{ color: COLORS.red, fontWeight: 700 }}>✕</span>}</label><input value={form.unidad} onChange={(e) => updateCot("unidad", e.target.value)} style={{ ...inputStyle, border: camposVacios.has("unidad") ? `1.5px solid ${COLORS.red}` : `1px solid ${COLORS.line}` }} /></div>
            <div><label style={{ ...cLabelStyle, color: camposVacios.has("color") ? COLORS.red : "#fff" }}>Color {camposVacios.has("color") && <span style={{ color: COLORS.red, fontWeight: 700 }}>✕</span>}</label><input value={form.color} onChange={(e) => updateCot("color", e.target.value)} style={{ ...inputStyle, border: camposVacios.has("color") ? `1.5px solid ${COLORS.red}` : `1px solid ${COLORS.line}` }} /></div>
            <div><label style={{ ...cLabelStyle, color: camposVacios.has("modelo") ? COLORS.red : "#fff" }}>Versión {camposVacios.has("modelo") && <span style={{ color: COLORS.red, fontWeight: 700 }}>✕</span>}</label><input value={form.modelo} onChange={(e) => updateCot("modelo", e.target.value)} style={{ ...inputStyle, border: camposVacios.has("modelo") ? `1.5px solid ${COLORS.red}` : `1px solid ${COLORS.line}` }} /></div>
            <div><label style={{ ...cLabelStyle, color: camposVacios.has("anio") ? COLORS.red : "#fff" }}>Año {camposVacios.has("anio") && <span style={{ color: COLORS.red, fontWeight: 700 }}>✕</span>}</label><input type="number" value={form.anio} onChange={(e) => updateCot("anio", e.target.value)} style={{ ...inputStyle, border: camposVacios.has("anio") ? `1.5px solid ${COLORS.red}` : `1px solid ${COLORS.line}` }} /></div>
          </div>
        </div>

        <div style={{ background: "#6A89A7", borderRadius: 6, border: `1px solid ${COLORS.line}`, padding: 24, marginBottom: 20 }}>
          <div className="display" style={{ fontSize: 16, fontWeight: 600, color: "#fff", marginBottom: 14, textTransform: "uppercase", letterSpacing: 0.5, background: "#163D6B", padding: "8px 12px", borderRadius: 4, marginLeft: -12, marginRight: -12, textShadow: "1px 1px 2px rgba(0,0,0,0.9), -1px -1px 1px rgba(0,0,0,0.5)" }}>
            Datos del Contrato
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, marginBottom: hasPrecio ? 18 : 0 }}>
            <div><label style={cLabelStyle}>Precio Lleno sin Descuento (opcional)</label>
              <div style={{ position: "relative" }}>
                <span style={{ position: "absolute", left: 11, top: "50%", transform: "translateY(-50%)", color: "#6B7280", fontSize: 14, pointerEvents: "none" }}>$</span>
                <CampoMoneda value={form.precioLleno} onChange={(e) => updateCot("precioLleno", e.target.value)} style={{ ...inputStyle, paddingLeft: 22 }} />
              </div>
            </div>
            <div><label style={{ ...cLabelStyle, color: camposVacios.has("precio") ? COLORS.red : "#fff" }}>Precio {camposVacios.has("precio") && <span style={{ color: COLORS.red, fontWeight: 700 }}>✕</span>}</label>
              <div style={{ position: "relative" }}>
                <span style={{ position: "absolute", left: 11, top: "50%", transform: "translateY(-50%)", color: "#6B7280", fontSize: 14, pointerEvents: "none" }}>$</span>
                <CampoMoneda value={form.precio} onChange={(e) => updateCot("precio", e.target.value)} style={{ ...inputStyle, paddingLeft: 22, border: camposVacios.has("precio") ? `1.5px solid ${COLORS.red}` : `1px solid ${COLORS.line}` }} />
              </div>
            </div>
          </div>
          {hasPrecio && (
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginTop: 10 }}>
              {[
                ["% Descuento Aplicado", r.descuentoAplicado === null ? "-" : `${(r.descuentoAplicado * 100).toFixed(1)}%`],
                ["Máximo Autorizado", fmtMoney(r.maxAutorizado)],
                ["Inscripción", fmtMoney(r.inscripcion)],
                ["IVA", fmtMoney(r.iva)],
                ["Inscripción con IVA", fmtMoney(r.inscripcionConIva)],
                ["Pago Inicial", fmtMoney(r.pagoInicialGeneral)],
              ].map(([lbl, val]) => (
                <div key={lbl}>
                  <div style={{ fontSize: 11, color: "rgba(255,255,255,0.9)", fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.3, textShadow: "1px 1px 2px rgba(0,0,0,0.9), -1px -1px 1px rgba(0,0,0,0.5)" }}>{lbl}</div>
                  <div style={{ fontSize: 15, fontWeight: 700, color: "#fff", textShadow: "1px 1px 2px rgba(0,0,0,0.9), -1px -1px 1px rgba(0,0,0,0.5)" }}>{val}</div>
                </div>
              ))}
            </div>
          )}
        </div>

        {!hasPrecio ? (
          <EmptyState text="Captura el Precio del vehículo para calcular la cotización." />
        ) : (
          <>
            <div style={{ background: "#6A89A7", borderRadius: 6, border: `1px solid ${COLORS.line}`, padding: 24, marginBottom: 20, overflowX: "auto" }}>
              <div className="display" style={{ fontSize: 16, fontWeight: 600, color: "#fff", marginBottom: 14, textTransform: "uppercase", letterSpacing: 0.5, background: "#163D6B", padding: "8px 12px", borderRadius: 4, marginLeft: -12, marginRight: -12, textShadow: "1px 1px 2px rgba(0,0,0,0.9), -1px -1px 1px rgba(0,0,0,0.5)" }}>
                Opciones de mensualidad
              </div>
              <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12.5, minWidth: 720 }}>
                <thead>
                  <tr>
                    <th style={{ ...thStyle, background: "#163D6B", color: "#fff", borderRight: "1px solid rgba(255,255,255,0.5)" }}>CONCEPTO</th>
                    {PLAN_KEYS.map((k) => {
                      const headers = {
                        agencia: (
                          <div>
                            <div style={{ fontWeight: 700, fontSize: 13 }}>PLAN AGENCIA</div>
                            <div style={{ color: "rgba(255,255,255,0.85)", fontSize: 11 }}>48 Meses</div>
                            <div style={{ fontStyle: "italic", fontSize: 9, color: "rgba(255,255,255,0.7)" }}>Excelente Historial de Crédito<br/>Modelos de 2025 a 2026</div>
                          </div>
                        ),
                        ahorrador: (
                          <div>
                            <div style={{ fontWeight: 700, fontSize: 13 }}>PLAN AHORRADOR <span style={{ fontWeight: 400, fontSize: 11 }}>(Limitado)</span></div>
                            <div style={{ fontStyle: "italic", fontSize: 9, color: "rgba(255,255,255,0.7)", marginTop: 4 }}>
                              Contenido Informativo.<br />
                              Tarifa promocional limitada<br />
                              hasta el folio de sistema<br />
                              terminación 008
                            </div>
                          </div>
                        ),
                        puntual60: (
                          <div>
                            <div style={{ fontWeight: 700, fontSize: 13 }}>PAGO PUNTUAL</div>
                            <div style={{ color: "rgba(255,255,255,0.85)", fontSize: 11 }}>60 meses</div>
                            <div style={{ fontStyle: "italic", fontSize: 9, color: "rgba(255,255,255,0.7)" }}>(Integrante)</div>
                          </div>
                        ),
                        puntual48: (
                          <div>
                            <div style={{ fontWeight: 700, fontSize: 13 }}>PAGO PUNTUAL</div>
                            <div style={{ color: "rgba(255,255,255,0.85)", fontSize: 11 }}>48 meses</div>
                            <div style={{ fontStyle: "italic", fontSize: 9, color: "rgba(255,255,255,0.7)" }}>(Propietario)</div>
                          </div>
                        ),
                        casaLiquidez: (
                          <div>
                            <div style={{ fontWeight: 700, fontSize: 13 }}>PLAN LIQUIDEZ</div>
                            <div style={{ color: "rgba(255,255,255,0.85)", fontSize: 11 }}>144 meses</div>
                          </div>
                        ),
                      };
                      return <th key={k} style={{ ...thStyle, whiteSpace: "normal", fontWeight: 600, verticalAlign: "top", background: "#163D6B", color: "#fff" }}>{headers[k]}</th>;
                    })}
                  </tr>
                </thead>
                <tbody>
                  <tr>
                    <td style={{ ...tdLabelStyle, background: "#142B4D", color: "#fff" }}>Pago Inicial</td>
                    {PLAN_KEYS.map((k) => <td key={k} style={{ ...tdStyle, background: "#142B4D", color: "#fff", fontWeight: 700 }}>{fmtMoney(r.pagoInicial[k])}</td>)}
                  </tr>
                  <tr><td style={{ ...tdLabelStyle, background: "#4A4F57", color: "#fff" }}>Tasa Anual Nominal</td>{PLAN_KEYS.map((k) => <td key={k} style={{ ...tdStyle, background: "#4A4F57", color: "#fff" }}>{(r.tasaNominal[k] * 100).toFixed(2)}%</td>)}</tr>
                  <tr><td style={{ ...tdLabelStyle, background: "#4A4F57", color: "#fff" }}>Tasa Anual Efectiva</td>{PLAN_KEYS.map((k) => <td key={k} style={{ ...tdStyle, background: "#4A4F57", color: "#fff" }}>{(r.tasaEfectiva[k] * 100).toFixed(2)}%</td>)}</tr>
                  <tr><td style={{ ...tdLabelStyle, background: "#4A4F57", color: "#fff" }}>Factor Mensual</td>{PLAN_KEYS.map((k) => <td key={k} style={{ ...tdStyle, background: "#4A4F57", color: "#fff" }}>{(PLAN_FACTORES[k] * 100).toFixed(3)}%</td>)}</tr>
                  <tr>
                    <td style={{ ...tdLabelStyle, background: "#E8B800", color: COLORS.slate }}>M.M.A.</td>
                    {PLAN_KEYS.map((k) => <td key={k} style={{ ...tdStyle, background: "#E8B800", color: COLORS.slate }}>{k === "agencia" ? "—" : fmtMoney(r.mma[k])}</td>)}
                  </tr>
                  <tr>
                    <td style={{ ...tdLabelStyle, background: "#F7E820", color: COLORS.slate }}>1ra. Mensualidad</td>
                    {PLAN_KEYS.map((k) => <td key={k} style={{ ...tdStyle, background: "#F7E820", color: COLORS.slate, fontWeight: 700 }}>{fmtMoney(r.primeraMensualidad[k])}</td>)}
                  </tr>
                </tbody>
              </table>
            </div>

            {r.comparativa && (
              <div style={{ background: "#F7E820", borderRadius: 6, border: `1px solid ${COLORS.line}`, padding: 24, marginBottom: 20 }}>
                <div className="display" style={{ fontSize: 16, fontWeight: 600, color: "#fff", marginBottom: 4, textTransform: "uppercase", letterSpacing: 0.5, background: "#163D6B", padding: "8px 12px", borderRadius: 4 }}>
                  Comparativa
                </div>
                <div style={{ fontSize: 12, color: COLORS.slate, marginBottom: 14 }}>
                  Solo aparece cuando "Precio Lleno sin Descuento" es mayor a $100,000.
                </div>
                <SectionGrid title="" data={[
                  ["% Descuento Aplicado", `${(r.comparativa.descuentoAplicado * 100).toFixed(1)}%`],
                  ["Mensual Normal", fmtMoney(r.comparativa.mensualSinDescuento)],
                  ["Mensual Plan Ahorra.", fmtMoney(r.comparativa.mensualConDescuento)],
                  ["Ahorro Mensual", fmtMoney(r.comparativa.ahorroMensual)],
                  ["Ahorro Anual", fmtMoney(r.comparativa.ahorroAnual)],
                ]} />
              </div>
            )}

            <div style={{ background: "#D4E3B5", borderRadius: 6, border: `1px solid #A8BF7A`, padding: 24, marginBottom: 20 }}>
              <div className="display" style={{ fontSize: 16, fontWeight: 600, color: "#fff", marginBottom: 14, textTransform: "uppercase", letterSpacing: 0.5, background: "#163D6B", padding: "8px 12px", borderRadius: 4 }}>
                CV (uso interno)
              </div>
              <SectionGrid title="" data={[
                ["Factor CV", `${(r.factorCV * 100).toFixed(0)}%`],
                ["CV", fmtMoney(r.cv)],
                ["Ret 12%", fmtMoney(r.ret12)],
              ]} />
              <div style={{ marginTop: 10 }}>
                <div style={{ fontSize: 11, fontWeight: 600, color: COLORS.slateSoft, textTransform: "uppercase", letterSpacing: 0.3 }}>Total</div>
                <div style={{ fontSize: 22, fontWeight: 800, color: COLORS.navy, letterSpacing: 0.5 }}>{fmtMoney(r.cvTotal)}</div>
              </div>
            </div>

            <div style={{ display: "flex", justifyContent: "flex-end", gap: 10, flexWrap: "wrap", alignItems: "center" }}>
              {saveMsg && <div style={{ fontSize: 13, color: COLORS.red, fontWeight: 600 }}>{saveMsg}</div>}
              {canManage && (
                <button
                  onClick={() => {
                    const vacios = new Set(CAMPOS_REQUERIDOS.filter(k => !String(form[k] || "").trim()));
                    if (vacios.size > 0) { setCamposVacios(vacios); setAlertaCamposOrigen("guardar"); setAlertaCampos(true); return; }
                    setConfirmGuardar(true);
                  }}
                  disabled={saving}
                  style={{ ...primaryBtnStyle, background: "#D6452B" }}
                >
                  {saving ? "Guardando…" : "Guardar cotización"}
                </button>
              )}
              {canManage && (
                <button
                  onClick={() => {
                    const vacios = new Set(CAMPOS_REQUERIDOS.filter(k => !String(form[k] || "").trim()));
                    if (vacios.size > 0) { setCamposVacios(vacios); setAlertaCamposOrigen("imprimir"); setAlertaCampos(true); return; }
                    setConfirmImprimir(true);
                  }}
                  style={primaryBtnStyle}
                >
                  Generar cotización para cliente
                </button>
              )}
            </div>

            {/* Alerta: campos vacíos */}
            {alertaCampos && (
              <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
                <div style={{ background: "#fff", borderRadius: 10, padding: 30, maxWidth: 420, width: "100%", boxShadow: "0 8px 32px rgba(0,0,0,0.25)", textAlign: "center" }}>
                  <div style={{ fontSize: 36, marginBottom: 12 }}>⚠️</div>
                  <div style={{ fontSize: 16, fontWeight: 700, color: COLORS.red, marginBottom: 14 }}>
                    {alertaCamposOrigen === "imprimir"
                      ? <>Hay campos vacíos aún.<br />Rellenar correctamente antes de imprimir.</>
                      : <>Verifique de nuevo su cotización.<br />Uno o más campos no están rellenados.</>}
                  </div>
                  <button onClick={() => setAlertaCampos(false)} style={{ ...primaryBtnStyle, padding: "10px 32px" }}>Aceptar</button>
                </div>
              </div>
            )}

            {/* Confirmación antes de imprimir/generar la cotización para el cliente */}
            {confirmImprimir && (
              <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
                <div style={{ background: "#fff", borderRadius: 10, padding: 30, maxWidth: 420, width: "100%", boxShadow: "0 8px 32px rgba(0,0,0,0.25)", textAlign: "center" }}>
                  <div style={{ fontSize: 36, marginBottom: 12 }}>🔍</div>
                  <div style={{ fontSize: 18, fontWeight: 700, color: COLORS.navy, marginBottom: 12 }}>¿Reviso que todos los datos sean correctos?</div>
                  <div style={{ fontSize: 13, color: COLORS.slateSoft, marginBottom: 24 }}>
                    Verifique monto, unidad, cliente y mensualidades antes de imprimir.
                  </div>
                  <div style={{ display: "flex", gap: 10, justifyContent: "center" }}>
                    <button
                      onClick={() => { setConfirmImprimir(false); setShowCliente(true); }}
                      style={{ ...primaryBtnStyle, padding: "12px 32px", fontSize: 15 }}
                    >
                      ✓ Aceptar
                    </button>
                    <button onClick={() => setConfirmImprimir(false)} style={secondaryBtnStyle}>
                      Revisar
                    </button>
                  </div>
                </div>
              </div>
            )}

            {/* Cuadro de éxito al guardar */}
            {showExito && (
              <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.6)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
                <div style={{ background: "linear-gradient(135deg, #142B4D 0%, #1A6EA8 100%)", borderRadius: 14, padding: "36px 32px", maxWidth: 440, width: "100%", boxShadow: "0 12px 40px rgba(0,0,0,0.4)", textAlign: "center" }}>
                  <div style={{ fontSize: 52, marginBottom: 12 }}>🎯</div>
                  <div style={{ fontSize: 20, fontWeight: 800, color: "#fff", marginBottom: 10, letterSpacing: 0.3 }}>
                    ¡Cotización registrada con éxito!
                  </div>
                  <div style={{ fontSize: 14, color: "rgba(255,255,255,0.85)", lineHeight: 1.7, marginBottom: 8, fontStyle: "italic" }}>
                    ¡Listo, {session.nombre.split(" ")[0]}! Ya puedes continuar con el cierre de tu venta.<br />
                    Recuerda: una buena presentación es la clave del cierre.
                  </div>
                  <div style={{ fontSize: 13, fontWeight: 700, color: "#F5DC7A", marginBottom: 24, letterSpacing: 0.5 }}>
                    ¡Mucho éxito, el equipo Autocon confía en ti!
                  </div>
                  <button
                    onClick={() => {
                      setShowExito(false);
                      setForm(emptyCotizadorForm());
                      setSaveMsg("");
                      if (onSaved) onSaved();
                      onClose();
                    }}
                    style={{ background: "#D6452B", color: "#fff", border: "none", borderRadius: 8, padding: "12px 36px", fontSize: 15, fontWeight: 700, cursor: "pointer" }}
                  >
                    ¡Gracias!
                  </button>
                </div>
              </div>
            )}

            {/* Cuadro de confirmación al guardar */}
            {confirmGuardar && (
              <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
                <div style={{ background: "#fff", borderRadius: 10, padding: 30, maxWidth: 420, width: "100%", boxShadow: "0 8px 32px rgba(0,0,0,0.25)", textAlign: "center" }}>
                  <div style={{ fontSize: 36, marginBottom: 12 }}>🔍</div>
                  <div style={{ fontSize: 18, fontWeight: 700, color: COLORS.navy, marginBottom: 12 }}>¿Ya revisó que todos los datos estén correctos?</div>
                  <div style={{ fontSize: 13, color: COLORS.slateSoft, marginBottom: 24 }}>
                    Verifique monto, unidad, cliente y mensualidades antes de guardar.
                  </div>
                  <div style={{ display: "flex", gap: 10, justifyContent: "center" }}>
                    <button
                      onClick={async () => { setConfirmGuardar(false); await guardarCotizacion(); }}
                      style={{ ...primaryBtnStyle, padding: "12px 32px", fontSize: 15 }}
                    >
                      ✓ Aceptar
                    </button>
                    <button onClick={() => setConfirmGuardar(false)} style={secondaryBtnStyle}>
                      Revisar
                    </button>
                  </div>
                </div>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

const thStyle = { textAlign: "left", padding: "8px 10px", fontWeight: 700, color: COLORS.slate, background: COLORS.cream, borderBottom: `2px solid ${COLORS.line}`, whiteSpace: "nowrap" };
const tdStyle = { padding: "8px 10px", borderBottom: `1px solid ${COLORS.line}`, whiteSpace: "nowrap" };
const tdLabelStyle = { ...tdStyle, fontWeight: 700, background: "#FAFAF7" };

/* ============================================================
   COTIZACIÓN CLIENTE (documento imprimible, generado desde el Cotizador)
   ============================================================ */
function CotizacionClientePrint({ form, r, canManage, onClose }) {
  const printRef = useRef(null);
  const [popupBlocked, setPopupBlocked] = useState(false);
  const esPrueba = TEST_FOLIOS.includes(form.noCaratula) || TEST_FOLIOS.includes(String(form.folioNumero));

  const marcaAgua = esPrueba ? `
    <div style="position:fixed;top:50%;left:50%;transform:translate(-50%,-50%) rotate(-45deg);
      font-size:90px;font-weight:900;color:rgba(0,0,0,0.06);white-space:nowrap;
      pointer-events:none;z-index:9999;letter-spacing:4px;font-family:Arial,sans-serif;">
      SIN VALOR COMERCIAL
    </div>` : "";

  const buildHTML = () => {
    const content = printRef.current ? printRef.current.innerHTML : "";
    return `<!DOCTYPE html><html><head><meta charset="utf-8" />
      <title>Cotización ${form.cliente || ""}</title>
      <style>
        @page { size: 216mm 279mm; margin: 7mm; }
        * { box-sizing: border-box; -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; color-adjust: exact !important; }
        body { font-family: Arial, Helvetica, sans-serif; color: #2E3744; margin: 0; }
        img { max-width: 100%; }
        #btn-imprimir-flotante { position: fixed; top: 14px; right: 14px; background: #142B4D; color: #fff; border: none; border-radius: 6px; padding: 12px 20px; font-size: 15px; font-weight: 700; cursor: pointer; box-shadow: 0 4px 14px rgba(0,0,0,0.3); z-index: 9999; }
        @media print { #btn-imprimir-flotante { display: none !important; } }
      </style>
      </head><body>
      <button id="btn-imprimir-flotante" onclick="window.print()">🖨️ Imprimir esta hoja</button>
      ${marcaAgua}
      ${content}
      </body></html>`;
  };
  const downloadHTML = () => {
    const html = buildHTML();
    const blob = new Blob([html], { type: "text/html" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `Cotizacion_${(form.cliente || "alfasur").replace(/[^a-zA-Z0-9_-]/g, "_")}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(url), 2000);
  };

  const Bar = ({ children }) => (
    <div style={{ background: "#7A8290", color: "#fff", padding: "4px 10px", fontWeight: 700, fontSize: 13, textTransform: "uppercase", letterSpacing: 0.4, textAlign: "center" }}>{children}</div>
  );
  const Row = ({ label, value, half, highlight }) => (
    <div style={{ display: "flex", borderBottom: `1px solid ${COLORS.line}`, fontSize: 13, background: highlight ? "#E2E4E8" : "transparent" }}>
      <div style={{ width: half ? "35%" : "28%", padding: "4px 8px", fontWeight: 700, background: highlight ? "#E2E4E8" : "#FAFAF7" }}>{label}</div>
      <div style={{ flex: 1, padding: "4px 8px", fontWeight: highlight ? 700 : 400 }}>{value || ""}</div>
    </div>
  );
  const Row3 = ({ a, b, c }) => (
    <div style={{ display: "flex", borderBottom: `1px solid ${COLORS.line}`, fontSize: 13 }}>
      <div style={{ flex: 1, padding: "4px 8px" }}><span style={{ fontWeight: 700 }}>{a[0]}: </span>{a[1]}</div>
      <div style={{ flex: 1, padding: "4px 8px", borderLeft: `1px solid ${COLORS.line}` }}><span style={{ fontWeight: 700 }}>{b[0]}: </span>{b[1]}</div>
      <div style={{ flex: 1, padding: "7px 10px", borderLeft: `1px solid ${COLORS.line}` }}><span style={{ fontWeight: 700 }}>{c[0]}: </span>{c[1]}</div>
    </div>
  );
  const PlanBlock = ({ titulo, nota, enganche, cuota, plazo }) => (
    <div>
      <div style={{ background: "#EAF1FB", padding: "5px 10px", fontWeight: 700, fontSize: 12, color: COLORS.navy, borderBottom: `1px solid ${COLORS.line}`, textAlign: "center" }}>{titulo}</div>
      {nota && <div style={{ padding: "5px 12px", fontSize: 10, color: COLORS.slateSoft, borderBottom: `1px solid ${COLORS.line}`, textAlign: "center" }}>{nota}</div>}
      <div style={{ display: "flex", textAlign: "center", fontSize: 11, fontWeight: 700, color: COLORS.slate, borderBottom: `1px solid ${COLORS.line}` }}>
        <div style={{ flex: 1, padding: "3px 4px" }}>Enganche</div>
        <div style={{ flex: 1, padding: "3px 4px", borderLeft: `1px solid ${COLORS.line}` }}>Cuota Mensual</div>
        <div style={{ flex: 1, padding: "3px 4px", borderLeft: `1px solid ${COLORS.line}` }}>Plazo</div>
      </div>
      <div style={{ display: "flex", textAlign: "center", fontSize: 14, fontWeight: 700, borderBottom: `3px solid ${COLORS.line}` }}>
        <div style={{ flex: 1, padding: "6px 4px" }}>{enganche}</div>
        <div style={{ flex: 1, padding: "6px 4px", borderLeft: `1px solid ${COLORS.line}` }}>{cuota}</div>
        <div style={{ flex: 1, padding: "6px 4px", borderLeft: `1px solid ${COLORS.line}` }}>{plazo}</div>
      </div>
    </div>
  );
  const baseTimestamp = form.fechaHoraCreacion ? new Date(form.fechaHoraCreacion) : new Date();
  const fechaCotizacion = fmtDateTime(baseTimestamp);

  return (
    <div onContextMenu={(e) => { if (!canManage) e.preventDefault(); }} className={!canManage ? "no-select" : ""} style={{ background: "#888", minHeight: "100vh", padding: 20 }}>
      <div className="no-print" style={{ maxWidth: 800, margin: "0 auto 14px", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 8 }}>
        <button onClick={onClose} style={secondaryBtnStyle}>← Volver</button>
        {canManage ? (
          <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
            <button onClick={downloadHTML} style={secondaryBtnStyle}>Descargar hoja</button>
          </div>
        ) : (
          <div style={{ fontSize: 12, color: COLORS.slateSoft, fontStyle: "italic" }}>
            Vista previa — solo el administrador puede imprimir o descargar esta cotización.
          </div>
        )}
      </div>
      {popupBlocked && (
        <div className="no-print" style={{ maxWidth: 800, margin: "0 auto 14px", background: "#fff3cd", border: "1px solid #C9881D", borderRadius: 6, padding: 12, fontSize: 13, color: "#6B4E0A" }}>
          El navegador bloqueó la ventana emergente. Permítela en la barra de direcciones e intenta de nuevo.
        </div>
      )}

      <div id="print-area" ref={printRef} style={{ background: "#fff", maxWidth: 850, margin: "0 auto", fontFamily: "'Inter', sans-serif", color: COLORS.slate, border: `1px solid ${COLORS.line}` }}>
        <div style={{ display: "flex", justifyContent: "space-between", padding: "10px 18px 10px", borderBottom: `2px solid ${COLORS.navy}` }}>
          <div>
            <div style={{ fontSize: 13 }}>
              <div><strong>No. Carátula:</strong> {form.noCaratula}</div>
              <div><strong>No. Contrato:</strong> {form.noContrato}</div>
            </div>
            <div style={{ fontSize: 9, color: COLORS.slateSoft, lineHeight: 1.4, marginTop: 8 }}>
              CORPORATIVO ALFA SUR AUTOS Y MOTOS S.A.S DE C.V.<br />
              RFC: CAS2507083L2<br />
              Dirección fiscal: Paseo de la Reforma #342 Col. Juárez.<br />
              Cuauhtémoc, Ciudad de México.
            </div>
          </div>
          <div style={{ textAlign: "center" }}>
            <img src={LOGO_PRINT_BASE64} alt="Corporativo Alfa Sur" style={{ width: 190, maxWidth: "100%", height: "auto" }} />
          </div>
          <div style={{ fontSize: 13, textAlign: "right" }}>
            <div className="display" style={{ fontSize: 20, fontWeight: 700, color: COLORS.navy }}>COTIZACIÓN</div>
            <div style={{ marginTop: 4 }}><strong>Fecha:</strong> {fechaCotizacion}</div>
          </div>
        </div>

        <Bar>Datos del Cliente</Bar>
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="Cliente" value={form.cliente} half /></div>
          <div style={{ flex: 1 }}><Row label="Sucursal" value={form.sucursal} half /></div>
        </div>

        <Bar>Datos del Vehículo</Bar>
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="Unidad" value={form.unidad} half /></div>
          <div style={{ flex: 1 }}><Row label="Monto Contratado" value={fmtMoney(r.maxAutorizado)} half /></div>
        </div>
        <Row3 a={["Versión", form.modelo]} b={["Color", form.color]} c={["Año", form.anio]} />

        <Bar>Datos del Contrato</Bar>
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="Inscripción" value={fmtMoney(r.inscripcion)} half /></div>
          <div style={{ flex: 1 }}><Row label="IVA Inscripción" value={fmtMoney(r.iva)} half /></div>
        </div>
        <Row label="1ra. Cuota Periódica Total" value={fmtMoney(r.mma.puntual60)} highlight />
        <Row label="Total Pago Inicial" value={fmtMoney(r.pagoInicialGeneral)} highlight />

        <Bar>Planes de Autofinanciamiento</Bar>
        <PlanBlock
          titulo="Plan con Enganche Directo del 35% (Previa Autorización)"
          enganche={fmtMoney(r.planesCliente.engancheDirecto.enganche)}
          cuota={fmtMoney(r.planesCliente.engancheDirecto.cuota)}
          plazo={`${r.planesCliente.engancheDirecto.plazo} meses`}
        />
        <PlanBlock
          titulo="Plan de Ahorro o Puntos"
          nota="Adjudicaciones día 21 de cada mes · Pago puntual del 1-3 de cada mes · Promedio de 9 a 12 pagos puntuales"
          enganche="—"
          cuota={fmtMoney(r.planesCliente.ahorroPuntos.cuota)}
          plazo={`${r.planesCliente.ahorroPuntos.plazo} meses`}
        />
        <PlanBlock
          titulo="Plan de Enganche Diferido"
          nota="3 aportaciones mensuales y proporcionar un 25% de enganche"
          enganche={fmtMoney(r.planesCliente.engancheDiferido.enganche)}
          cuota={fmtMoney(r.planesCliente.engancheDiferido.cuota)}
          plazo={`${r.planesCliente.engancheDiferido.plazo} meses`}
        />

        <div style={{ padding: "10px 14px", fontSize: 9, fontStyle: "italic", color: COLORS.slateSoft, lineHeight: 1.35 }}>
          La presente cotización no garantiza la adjudicación del vehículo, el pago inicial o la inscripción no garantizan la entrega inmediata del vehículo, sino que el cliente se integra a un grupo de consumidores y que la adjudicación dependerá de los métodos contratados (subasta, puntuación, o adjudicación por liquidación etc.). Sujeta a disponibilidad y autorización. Precios, valores de la unidad y promociones están sujetos a las variaciones del mercado automotriz y del fabricante sin previo aviso. Los montos, mensualidades, asignación y derechos de las partes se regulan y garantizan exclusivamente por lo establecido en el Contrato de Adhesión correspondiente de CORPORATIVO ALFA SUR AUTOS Y MOTOS S.A.S DE C.V., RFC: CAS2507083L2. Dirección fiscal: Paseo de la Reforma #342 Col. Juárez, Cuauhtémoc, Ciudad de México. Dirección Sucursal: Av. Paseo Usumacinta #1025 Col. Atasta de Serra CP 86100 Villahermosa Tabasco.
        </div>

        <div style={{ display: "flex", justifyContent: "space-between", padding: "118px 50px 14px", gap: 24 }}>
          <div style={{ flex: 1, textAlign: "center" }}>
            <div style={{ borderTop: `1.5px solid ${COLORS.slate}`, paddingTop: 6, fontSize: 12, fontWeight: 600 }}>EJECUTIVO</div>
          </div>
          <div style={{ flex: 1, textAlign: "center" }}>
            <div style={{ borderTop: `1.5px solid ${COLORS.slate}`, paddingTop: 6, fontSize: 12, fontWeight: 600 }}>NOMBRE Y FIRMA DEL CONTRATANTE</div>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ============================================================
   PRINT VIEW  (solo accesible desde AdminPanel)
   ============================================================ */
function PrintSolicitud({ sol, onClose }) {
  const { inscripcion, cuota: mensualidad, total: importeTotal } = calcMontos(sol.montoContratado);
  const planes = ["Enganche", "Enganche Diferido", "Plan de Pago Puntual (puntos)", "Plan de Secuencial"];
  const formas = ["Efectivo", "Transferencia", "Tarjeta de Crédito", "Tarjeta de Débito"];
  const printRef = useRef(null);
  const [popupBlocked, setPopupBlocked] = useState(false);
  const esPrueba = sol.esPractica === true;

  const marcaAgua = esPrueba ? `
    <div style="position:fixed;top:50%;left:50%;transform:translate(-50%,-50%) rotate(-45deg);
      font-size:90px;font-weight:900;color:rgba(0,0,0,0.06);white-space:nowrap;
      pointer-events:none;z-index:9999;letter-spacing:4px;font-family:Arial,sans-serif;">
      SIN VALOR COMERCIAL
    </div>` : "";

  const buildHTML = () => {
    const content = printRef.current ? printRef.current.innerHTML : "";
    return `<!DOCTYPE html><html><head><meta charset="utf-8" />
      <title>Solicitud ${sol.folioContrato || ""}</title>
      <style>
        @page { size: 216mm 340mm; margin: 4mm 7mm 7mm 7mm; }
        * { box-sizing: border-box; -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; color-adjust: exact !important; }
        body { font-family: Arial, Helvetica, sans-serif; color: #2E3744; margin: 0; }
        img { max-width: 100%; }
        #btn-imprimir-flotante { position: fixed; top: 14px; right: 14px; background: #142B4D; color: #fff; border: none; border-radius: 6px; padding: 12px 20px; font-size: 15px; font-weight: 700; cursor: pointer; box-shadow: 0 4px 14px rgba(0,0,0,0.3); z-index: 9999; }
        @media print {
          #btn-imprimir-flotante { display: none !important; }
          .firmas-solicitud { margin-top: 20mm !important; }
        }
      </style>
      </head><body>
      <button id="btn-imprimir-flotante" onclick="window.print()">🖨️ Imprimir esta hoja</button>
      ${marcaAgua}
      ${content}
      </body></html>`;
  };

  const openPrintWindow = () => {
    setPopupBlocked(false);
    const w = window.open("", "_blank");
    if (!w) {
      setPopupBlocked(true);
      return;
    }
    w.document.open();
    w.document.write(buildHTML());
    w.document.close();
  };

  const downloadHTML = () => {
    const html = buildHTML();
    const blob = new Blob([html], { type: "text/html" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `Solicitud_${(sol.folioContrato || "alfasur").replace(/[^a-zA-Z0-9_-]/g, "")}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(url), 2000);
  };

  const Bar = ({ children }) => (
    <div style={{ background: "#7A8290", color: "#fff", padding: "2.5px 8px", fontWeight: 700, fontSize: 13, textTransform: "uppercase", letterSpacing: 0.4 }}>
      {children}
    </div>
  );
  const Row = ({ label, value, half, highlight }) => (
    <div style={{ display: "flex", borderBottom: `1px solid ${COLORS.line}`, fontSize: 11, lineHeight: 1.1, background: highlight ? "#E2E4E8" : "transparent" }}>
      <div style={{ width: half ? "35%" : "28%", padding: "2px 6px", fontWeight: 700, background: highlight ? "#E2E4E8" : "#FAFAF7" }}>{label}</div>
      <div style={{ flex: 1, padding: "2px 6px", fontWeight: highlight ? 700 : 400 }}>{value || ""}</div>
    </div>
  );

  return (
    <div style={{ background: "#888", minHeight: "100vh", padding: 20 }}>
      <div className="no-print" style={{ maxWidth: 800, margin: "0 auto 14px", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 8 }}>
        <button onClick={onClose} style={secondaryBtnStyle}>← Cerrar</button>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
          <button onClick={downloadHTML} style={secondaryBtnStyle}>Descargar hoja</button>
          <button onClick={openPrintWindow} style={primaryBtnStyle}>Abrir hoja en pestaña nueva</button>
        </div>
      </div>
      <div className="no-print" style={{ maxWidth: 800, margin: "0 auto 14px", background: "#E8EEF5", border: `1px solid ${COLORS.navy}`, borderRadius: 6, padding: "12px 16px", fontSize: 13, color: COLORS.navy }}>
        <strong>Antes de imprimir, sigue estos pasos (cada vez que cambies de impresora):</strong>
        <ol style={{ margin: "8px 0 0", paddingLeft: 18, lineHeight: 1.6 }}>
          <li>Abre el diálogo de imprimir y entra a <strong>"Más configuraciones"</strong> o <strong>"Configuración adicional"</strong>.</li>
          <li>En <strong>"Tamaño de papel"</strong>, elige <strong>Oficio</strong>. Si tu impresora no la tiene, usa <strong>Legal</strong>.</li>
          <li>En <strong>"Escala"</strong>, elige <strong>100% / Tamaño real</strong> — nunca "Ajustar a la página".</li>
          <li>Imprime normal.</li>
        </ol>
      </div>
      {popupBlocked && (
        <div className="no-print" style={{ maxWidth: 800, margin: "0 auto 14px", background: "#fff3cd", border: "1px solid #C9881D", borderRadius: 6, padding: 12, fontSize: 13, color: "#6B4E0A" }}>
          El navegador bloqueó la ventana emergente. Busca el ícono de "ventana emergente bloqueada" en la barra de direcciones, permítela, y vuelve a tocar "Abrir para imprimir".
        </div>
      )}

      <div id="print-area" ref={printRef} style={{ background: "#fff", maxWidth: 850, margin: "0 auto", fontFamily: "'Inter', sans-serif", color: COLORS.slate, border: `1px solid ${COLORS.line}`, minHeight: 0 }}>
        {/* Caratula */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "0px 10px 2px", borderBottom: `2px solid ${COLORS.navy}` }}>
          <div style={{ fontSize: 10.5 }}>
            <div style={{ fontWeight: 700, fontSize: 11, color: COLORS.navy, textTransform: "uppercase", marginBottom: 2 }}>Carátula de Contrato</div>
            <div><strong>No. Contrato:</strong> {sol.folioContrato}</div>
            <div><strong>Atención al cliente:</strong> (44 98) 99 87 40</div>
            <div>www.autocongroup.org</div>
          </div>
          <div style={{ textAlign: "center" }}>
            <img src={LOGO_PRINT_BASE64} alt="Corporativo Alfa Sur" style={{ width: 130, maxWidth: "100%", height: "auto" }} />
          </div>
          <div style={{ fontSize: 10.5, textAlign: "right" }}>
            <div>AV. PASEO USUMACINTA #1025</div>
            <div>COL. ATASTA DE SERRA, C.P. 86100</div>
            <div>VILLAHERMOSA, TAB.</div>
            <div style={{ marginTop: 4 }}><strong>FECHA:</strong> {sol.fechaCreacion}</div>
          </div>
        </div>

        <Bar>Datos del Solicitante</Bar>
        <Row label="Nombre" value={sol.nombre} />
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="RFC" value={sol.rfc} half /></div>
          <div style={{ flex: 1 }}><Row label="CURP" value={sol.curp} half /></div>
        </div>
        <Row label="Ocupación" value={sol.ocupacion} />
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="Género" value={sol.genero} half /></div>
          <div style={{ flex: 1 }}><Row label="Estado civil" value={sol.estadoCivil} half /></div>
        </div>
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="Fecha de nacimiento" value={sol.fechaNacimiento} half /></div>
          <div style={{ flex: 1 }}><Row label="Edad" value={calcEdad(sol.fechaNacimiento)} half /></div>
        </div>

        <Bar>Domicilio del Solicitante</Bar>
        <Row label="Calle" value={sol.calle} />
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="No. Ext." value={sol.noExt} half /></div>
          <div style={{ flex: 1 }}><Row label="No. Int." value={sol.noInt} half /></div>
        </div>
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="Colonia" value={sol.colonia} half /></div>
          <div style={{ flex: 1 }}><Row label="C.P." value={sol.cp} half /></div>
        </div>
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="Municipio" value={sol.municipio} half /></div>
          <div style={{ flex: 1 }}><Row label="Estado" value={sol.estado} half /></div>
        </div>
        <Row label="Tipo de vivienda" value={sol.tipoVivienda} />
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="Tel. casa" value={sol.telCasa} half /></div>
          <div style={{ flex: 1 }}><Row label="Tel. celular" value={sol.telCelular} half /></div>
        </div>
        <Row label="Correo electrónico" value={sol.correo} />

        <Bar>Datos del Empleo o Negocio</Bar>
        <Row label="Empresa" value={sol.empresa} />
        <Row label="Razón social" value={sol.razonSocial} />
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="Giro" value={sol.giro} half /></div>
          <div style={{ flex: 1 }}><Row label="Jefe directo" value={sol.jefeDirecto} half /></div>
        </div>
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="Teléfono" value={sol.telEmpresa} half /></div>
          <div style={{ flex: 1 }}><Row label="Correo" value={sol.correoEmpresa} half /></div>
        </div>
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="Sueldo bruto" value={fmtMoney(sol.sueldoBruto)} half /></div>
          <div style={{ flex: 1 }}><Row label="Sueldo neto" value={fmtMoney(sol.sueldoNeto)} half /></div>
        </div>
        <Row label="Frecuencia de pago" value={sol.frecuenciaPago} />
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="Otros ingresos" value={fmtMoney(sol.otrosIngresos)} half /></div>
          <div style={{ flex: 1 }}><Row label="Fuente" value={sol.fuenteOtrosIngresos} half /></div>
        </div>
        <Row label="Ingresos totales" value={fmtMoney((parseFloat(sol.sueldoNeto)||0)+(parseFloat(sol.otrosIngresos)||0))} />
        <Row label="¿Son comprobables?" value={sol.comprobables} />

        <Bar>Referencias Personales (familiar y/o amistad)</Bar>
        {[1, 2].map((n) => (
          <div key={n}>
            <Row label="Nombre completo" value={sol[`ref${n}Nombre`]} />
            <div style={{ display: "flex" }}>
              <div style={{ flex: 1 }}><Row label="Parentesco" value={sol[`ref${n}Parentesco`]} half /></div>
              <div style={{ flex: 1 }}><Row label="Celular" value={sol[`ref${n}Tel`]} half /></div>
            </div>
            <Row label="Domicilio" value={`${sol[`ref${n}Calle`] || ""} ${sol[`ref${n}NoExt`] || ""}, ${sol[`ref${n}Colonia`] || ""}, ${sol[`ref${n}Municipio`] || ""}, ${sol[`ref${n}Estado`] || ""} CP ${sol[`ref${n}Cp`] || ""}`} />
          </div>
        ))}

        <Bar>Beneficiario</Bar>
        <div style={{ fontSize: 8, padding: "2px 6px", fontStyle: "italic", background: "#FAFAF7" }}>
          Corporativo Alfa Sur Autos y Motos S.A.S. de C.V. es siempre el beneficiario preferente por cualquier saldo insoluto.
        </div>
        <Row label="Nombre completo" value={sol.benNombre} />
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="Parentesco" value={sol.benParentesco} half /></div>
          <div style={{ flex: 1 }}><Row label="Celular" value={sol.benTel} half /></div>
        </div>
        <Row label="Domicilio" value={`${sol.benCalle || ""}, ${sol.benMunicipio || ""}, ${sol.benEstado || ""} CP ${sol.benCp || ""}`} />

        <Bar>Descripción del Bien Contratado</Bar>
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="Marca y tipo de unidad" value={[sol.marcaTipo, sol.version, sol.modeloUnidad].filter(Boolean).join(" ")} half /></div>
          <div style={{ flex: 1 }}><Row label="Monto contratado" value={fmtMoney(sol.montoContratado)} half /></div>
        </div>
        <div style={{ display: "flex" }}>
          <div style={{ flex: 1 }}><Row label="Producto" value={sol.producto} half /></div>
          <div style={{ flex: 1 }}><Row label="Plazo" value={`${sol.plazo} meses`} half /></div>
        </div>
        <Row label="Inscripción con IVA" value={fmtMoney(inscripcion)} highlight />
        <Row label="1ra. cuota periódica total" value={fmtMoney(mensualidad)} highlight />
        <Row label="Importe total" value={fmtMoney(importeTotal)} highlight />
        <Row label="Plan de financiamiento aprobado" value={planes.map((p) => `${p} (${sol.planFinanciamiento === p ? "X" : " "})`).join("   ")} />
        <Row label="Forma de pago" value={formas.map((p) => `${p} (${sol.formaPago === p ? "X" : " "})`).join("   ")} />

        <div style={{ padding: "4px 8px", fontSize: 8.5, lineHeight: 1.2 }}>
          <div style={{ fontWeight: 700, marginBottom: 3 }}>Solicitante recuerde usted que:</div>
          <div>1) Las cuotas mensuales se ajustarán de acuerdo con las variaciones del precio de lista oficial que pueda tener el bien contratado hasta la adjudicación.</div>
          <div>2) Los pagos mensuales para que sean válidos solo deberán ser hechos en las instituciones bancarias autorizadas por la empresa, mismas que se le indicarán al momento de realizar su contrato.</div>
          <div>3) El atraso en el pago de dos mensualidades consecutivas o en su conjunto serán motivo de rescisión de este contrato de adhesión.</div>
          <div>4) El integrante puede renunciar voluntariamente o cediendo a un tercero los derechos y obligaciones de su contrato previa autorización por escrito.</div>
          <div>5) En caso de rescisión se estará a lo dispuesto en la cláusula V del contrato.</div>
          <div>6) El solicitante tiene el derecho a que se le devuelva el importe del presente recibo, si no fuese aceptado en el plan.</div>
          <div>7) El presente contrato se celebra entre particulares y cualquier controversia se resolverá por los medios asignados por las autoridades para resolución de dichas diferencias de carácter comercial, eximiendo así a las partes de ejercer cualquier acción penal una en contra de otra.</div>
          <div>8) En atención a las pruebas de asegurabilidad satisfactorias que deben ponerse en la Cía. De seguros de vida, en ciertos casos manifiesto a ser persona física mayor de 18 años y menor de 55 años y que no tengo celebrados otros contratos de prestaciones de servicios con CORPORATIVO ALFA SUR AUTOS Y MOTOS S.A.S DE C.V que sumados excedan de un importe de $2,500,000.00 de pesos. Quedo enterado que si alguno de estos datos no fuesen ciertos quedaré automáticamente desprotegido de este seguro, aunque no tenga información digital y/o escrita por parte de la empresa.</div>
          <div style={{ marginTop: 6 }}><strong>CAT Promedio Informativo 26.8% Sin IVA</strong> calculado al {getCatDate()} para fines informativos y de comparación exclusivamente. El costo real puede variar en función de las actualizaciones del valor del bien y la fecha de adjudicación del consumidor.</div>
        </div>

        <style>{`
          @media print {
            .firmas-solicitud { margin-top: 20mm !important; }
          }
        `}</style>
        <div className="firmas-solicitud" style={{ display: "flex", justifyContent: "space-between", padding: "30px 40px 8px", gap: 20 }}>
          <div style={{ flex: 1, textAlign: "center" }}>
            <div style={{ borderTop: `1.5px solid ${COLORS.slate}`, paddingTop: 3, fontSize: 9, fontWeight: 600 }}>NOMBRE Y FIRMA DEL ASESOR</div>
          </div>
          <div style={{ flex: 1, textAlign: "center" }}>
            <div style={{ borderTop: `1.5px solid ${COLORS.slate}`, paddingTop: 3, fontSize: 9, fontWeight: 600 }}>NOMBRE Y FIRMA DEL GERENTE</div>
          </div>
          <div style={{ flex: 1, textAlign: "center" }}>
            <div style={{ borderTop: `1.5px solid ${COLORS.slate}`, paddingTop: 3, fontSize: 9, fontWeight: 600 }}>NOMBRE Y FIRMA DEL CLIENTE</div>
          </div>
        </div>
      </div>
    </div>
  );
}
